-- Poems batch 239
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('2fbd7735-a6d0-49d2-8ba0-128d8df1e873','小洞天','毛奎','宋','宋诗','song-poetry','','[]','豐登少公事，時得訪林泉。',120,'全唐诗/poet.song.217000.json','["豐登少公事，時得訪林泉。", "鑿破蓬丘島，潛通小洞天。", "巖瞻橫北面，釣隠近西偏。", "縹緲雲藏閣，依稀石似船。", "崖平好磨琢，洞窈足迴旋。", "路貫層巔上，人隨曲巷穿。", "海光常瀲灧，山色更清妍。", "真可消塵俗，何妨中聖賢。", "烟霞無盡藏，風月不論錢。", "勝概好收拾，憑誰秉筆椽。"]'),
('cd43e248-be32-4810-b467-f1826bd4f316','小洞天','毛奎','宋','宋诗','song-poetry','','[]','丁相沉吟歎夙緣，衛公精爽亦凄然。',32,'全唐诗/poet.song.217000.json','["丁相沉吟歎夙緣，衛公精爽亦凄然。", "古今惟有毛知郡，偏愛崖州小洞天。"]'),
('9ee6ed3c-7510-4981-b569-b35369a07f04','大洞天','毛奎','宋','宋诗','song-poetry','','[]','大洞天連小洞天，洞天今在海南邊。',32,'全唐诗/poet.song.217000.json','["大洞天連小洞天，洞天今在海南邊。", "遊人賸有磨崖什，閑拂蒼苔看幾篇。"]'),
('64298d98-69a6-453b-bc21-80a110f659af','句','樓扶','宋','宋诗','song-poetry','','[]','夜深更擁寒衾坐，明月梅花共一窗。',16,'全唐诗/poet.song.217000.json','["夜深更擁寒衾坐，明月梅花共一窗。"]'),
('6cbb0dcb-00e8-4eda-a6f3-403c7ae3186c','還珠洞次曾宏正韻','蕭桂林','宋','宋诗','song-poetry','','[]','標柱征南不記春，未應追感淚流痕。',64,'全唐诗/poet.song.217000.json','["標柱征南不記春，未應追感淚流痕。", "巖虛生白□心地，波洑澄清肅耳根。", "壯士於斯留顯跡，大夫非此賦招魂。", "江山今古人何在，戰馬嘶風憶故園。"]'),
('a9078e7e-32a2-4efa-9bc1-e5d5510d2784','癸水亭次曾宏正韻','蕭桂林','宋','宋诗','song-poetry','','[]','□□□古碑，神奇永符讖。',48,'全唐诗/poet.song.217000.json','["□□□古碑，神奇永符讖。", "履巖俯馮夷，坐石存精祲。", "拂劍逼珠光，乘槎掉柯枋。", "風清明月懷，雲隠高山興。"]'),
('6f4ed2c8-d3f2-49f5-8142-bf477d389239','題駙馬都尉王晉卿所作夢游瀛山圖卷','袁立儒','宋','宋诗','song-poetry','','[]','珍木文禽玉佩環，清都絳闕色闌玕。',32,'全唐诗/poet.song.217000.json','["珍木文禽玉佩環，清都絳闕色闌玕。", "香山居士蓬萊院，借與王郎夢裏看。"]'),
('d7b037a4-3d08-4a07-a5c1-d048f6f0a084','詠胡季昭貶象州','曾宏父','宋','宋诗','song-poetry','','[]','湘山冷焰冰四海，寒蔽天晴日晝陰。',64,'全唐诗/poet.song.217000.json','["湘山冷焰冰四海，寒蔽天晴日晝陰。", "朝路偷生盡緘口，瘴鄉投死猶甘心。", "里閭節義紹襄簡，史冊姓名光古今。", "天定勝人公議在，褒忠錄後上恩深。"]'),
('6fe92f91-b77c-466e-bc51-0de06fc781b2','題鳳山書院修禊圖','曾宏父','宋','宋诗','song-poetry','','[]','暮春浴罷振春衣，正是流觴修禊時。',64,'全唐诗/poet.song.217000.json','["暮春浴罷振春衣，正是流觴修禊時。", "世事藏機應落落，人情忘我總熙熙。", "醉能辭醉原非醉，詩到無詩乃是詩。", "偉矣蘭亭衆君子，不將文字立藩籬。"]'),
('a24ab51c-0e36-4f38-880c-2c0807359ccb','妙高臺','釋鑒','宋','宋诗','song-poetry','','[]','一峰何突兀，不與羣峰齊。',24,'全唐诗/poet.song.217000.json','["一峰何突兀，不與羣峰齊。", "縱目乾坤窄，回頭日月低。"]'),
('bc1ce820-5365-488f-9ec2-53ad103b020d','藤龕','釋鑒','宋','宋诗','song-poetry','','[]','蘿居空未久，誰能繼其蹤。',24,'全唐诗/poet.song.217000.json','["蘿居空未久，誰能繼其蹤。", "寥寥巖畔月，千古屬和公。"]'),
('c26ed6e0-3b12-4e4c-a970-f549a4ba8ef0','含珠林','釋鑒','宋','宋诗','song-poetry','','[]','風勁蕭蕭響，露滴箇箇圓。',24,'全唐诗/poet.song.217000.json','["風勁蕭蕭響，露滴箇箇圓。", "坐看西山月，渾疑墮我前。"]'),
('25d4f79c-6312-490a-bc32-0b2379b06e5b','黄巢墓','釋鑒','宋','宋诗','song-poetry','','[]','圖王爭霸業，自古仗戈矛。',24,'全唐诗/poet.song.217000.json','["圖王爭霸業，自古仗戈矛。", "英風今何在，都成一古丘。"]'),
('f42a19ed-8b63-4b78-91ae-0926987900aa','錦鏡池','釋鑒','宋','宋诗','song-poetry','','[]','一鑑涵虛碧，萬象悉其中。',24,'全唐诗/poet.song.217000.json','["一鑑涵虛碧，萬象悉其中。", "重綠浮輕綠，深紅閒淺紅。"]'),
('2d943f81-83fe-4f1a-b7ab-0c3ec26316d3','入山亭','釋鑒','宋','宋诗','song-poetry','','[]','荒蕪行盡處，幽亭聊暫止。',24,'全唐诗/poet.song.217000.json','["荒蕪行盡處，幽亭聊暫止。", "带雨策孤筇，登高從此始。"]'),
('37035be6-627a-422d-9099-b218bda5f793','師子巖','釋鑒','宋','宋诗','song-poetry','','[]','昂空勢不已，踞地何雄哉。',24,'全唐诗/poet.song.217000.json','["昂空勢不已，踞地何雄哉。", "白雲遮不得，依舊山頭來。"]'),
('5407a996-00c0-495a-92b2-61c1ee23a479','聽泉亭','釋鑒','宋','宋诗','song-poetry','','[]','寒泉潄石齒，淅瀝鳴瑶琴。',24,'全唐诗/poet.song.217000.json','["寒泉潄石齒，淅瀝鳴瑶琴。", "坐來毛骨清，分明太古音。"]'),
('fc0d3c0e-9aad-481d-9431-1ca2745086da','桃花坑山','釋鑒','宋','宋诗','song-poetry','','[]','地僻人居少，林深路轉迷。',24,'全唐诗/poet.song.217000.json','["地僻人居少，林深路轉迷。", "桃花流水細，不異武陵溪。"]'),
('054259de-0303-4752-b568-1831f4a1724f','徐鳬巖','釋鑒','宋','宋诗','song-poetry','','[]','蕭然上方境，人稀知地僻。',24,'全唐诗/poet.song.217000.json','["蕭然上方境，人稀知地僻。", "徒聞古仙人，石上有遺迹。"]'),
('2a96ef57-1d92-4d5b-9cce-89567acc14c5','雪竇雜詠','釋鑒','宋','宋诗','song-poetry','','[]','特立羣峰表，危然勢不傾。',24,'全唐诗/poet.song.217000.json','["特立羣峰表，危然勢不傾。", "禪心清似洗，坐看月華明。"]'),
('0489fe4b-310f-44ca-afa0-382f22afe1b3','乳峰庵','釋鑒','宋','宋诗','song-poetry','','[]','崖竇乳堪啜，凝眸翠作屏。',24,'全唐诗/poet.song.217000.json','["崖竇乳堪啜，凝眸翠作屏。", "老禪初定起，山鳥自呼名。"]'),
('16891333-f005-436f-8edc-de8c023d6889','葛嶺賈似道園池','湯仲友','宋','宋诗','song-poetry','','[]','檀板歌殘陌上花，過牆荆棘刺檐牙。',64,'全唐诗/poet.song.217000.json','["檀板歌殘陌上花，過牆荆棘刺檐牙。", "指揮已失鐵如意，賜予寧存玉辟邪。", "敗屋春歸無主燕，廢池雨産在官蛙。", "木棉菴外尤愁絕，月黑夜深聞鬼車。"]'),
('6f867c52-0287-4cc7-97dc-eb0e11a1c545','虎山','湯仲友','宋','宋诗','song-poetry','','[]','虎是何年踞，名存跡已亡。',48,'全唐诗/poet.song.217000.json','["虎是何年踞，名存跡已亡。", "塔從林外出，山向寺中藏。", "池暗生寒氣，臺空旁夕陽。", "更無人弔古，來祇爲春茫。"]'),
('d332cf88-6120-4751-84b2-b11030031fc3','遊洞庭','湯仲友','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','寒色滿空山，翛然一徑閑。',48,'全唐诗/poet.song.217000.json','["寒色滿空山，翛然一徑閑。", "鳥啼黄葉外，人度翠峰間。", "古殿藏雲氣，唐碑带蘚斑。", "未窮幽絕處，興盡忽思還。"]'),
('fe67305d-643f-414d-b398-12d6d37fe830','楓橋','湯仲友','宋','宋诗','song-poetry','','[]','出城纔七里，地僻罕曾過。',48,'全唐诗/poet.song.217000.json','["出城纔七里，地僻罕曾過。", "孤塔臨官路，三門背運河。", "鐘鳴驚宿鳥，牆矮入漁歌。", "醉裏看題壁，如今張繼多。"]'),
('0a4dd5c3-b0dc-4cd6-ba57-e41a35b3c938','題惠山寺','湯仲友','宋','宋诗','song-poetry','','[]','梁溪停短棹，带月步西關。',48,'全唐诗/poet.song.217000.json','["梁溪停短棹，带月步西關。", "路盡忽逢寺，松多不見山。", "巖腰雲殿古，洞口石泉閑。", "到此正吟苦，秋聲滿樹間。"]'),
('83b9c32c-67ca-439c-a513-f89569fe55b9','西湖','湯仲友','宋','宋诗','song-poetry','','["\u897f\u6e56"]','山色波光步步隨，古今難畫亦難詩。',64,'全唐诗/poet.song.217000.json','["山色波光步步隨，古今難畫亦難詩。", "水浮亭館花間出，船載笙歌柳外移。", "過眼年華如去鳥，惱人春色似遊絲。", "六橋幾見輪蹄換，取樂莫辭金屈巵。"]'),
('472a2c2b-e870-4a33-91ee-f2fae4606322','舟□□□讀中興碑','趙楷','宋','宋诗','song-poetry','','[]','西風吹岸著浯溪，玉潔摩空十丈碑。',64,'全唐诗/poet.song.217000.json','["西風吹岸著浯溪，玉潔摩空十丈碑。", "不□開元久培植，可能靈武善扶持。", "斯文未泯今□□，盛德之興彼一時。", "崖下漫郎應在否，□□流涕手題詩。"]'),
('63496c7f-2dd0-4a8c-9084-d6b582f5bd1d','偈頌一百零九首  其一','釋可湘','宋','宋诗','song-poetry','','[]','祖翁閫域，撲地掀天。',24,'全唐诗/poet.song.217000.json','["祖翁閫域，撲地掀天。", "親切一回打透，不妨垂手入廛。"]'),
('7c4a00e3-2127-4ff8-a13c-b4c228360758','偈頌一百零九首  其二','釋可湘','宋','宋诗','song-poetry','','[]','摩竭陀國，親行此令。',20,'全唐诗/poet.song.217000.json','["摩竭陀國，親行此令。", "從上以來，孰敢違命。"]'),
('5d3d03d9-a4f4-460c-a53b-4b6cda60307d','偈頌一百零九首  其三','釋可湘','宋','宋诗','song-poetry','','[]','一釋迦，二元和，三佛陀。',24,'全唐诗/poet.song.217000.json','["一釋迦，二元和，三佛陀。", "阿呵呵，團欒且唱太平歌。"]'),
('bd6abb96-d28d-4071-b95e-8a71b7bbfbcb','偈頌一百零九首  其四','釋可湘','宋','宋诗','song-poetry','','[]','觸目未嘗無，臨機道什麽。',44,'全唐诗/poet.song.217000.json','["觸目未嘗無，臨機道什麽。", "錢是足陌，物是定價。", "坐破七箇蒲團，卷簾方見天下。", "千里追風非駿馬。"]'),
('3a4f22a7-0fb6-4ff8-ab64-93f938d8c889','偈頌一百零九首  其五','釋可湘','宋','宋诗','song-poetry','','[]','黄檗打臨濟，義出豐年。',48,'全唐诗/poet.song.217000.json','["黄檗打臨濟，義出豐年。", "興化趕克賓，蝦爲子屈。", "其功蓋代，只要重論。", "一火鑄成金彈子，棒頭敲出玉麒麟。"]'),
('7546d93c-6cf1-48ec-80dc-50ad270e2a5e','偈頌一百零九首  其六','釋可湘','宋','宋诗','song-poetry','','[]','浄倮倮，赤洒洒。',30,'全唐诗/poet.song.217000.json','["浄倮倮，赤洒洒。", "婷娉柳底花間，依約風前月下。", "僧繇妙筆難描畫。"]'),
('eb0f4053-65b5-49f9-a0e6-ba12c59c7f02','偈頌一百零九首  其七','釋可湘','宋','宋诗','song-poetry','','[]','□□□□理機梭，徧向園林織綺羅。',32,'全唐诗/poet.song.217000.json','["□□□□理機梭，徧向園林織綺羅。", "唯有黄鸝知此意，纔方偷眼又春過。"]'),
('0c15610c-ad20-4202-94e6-6c11cae60ccb','偈頌一百零九首  其八','釋可湘','宋','宋诗','song-poetry','','[]','風不來，樹不動。',34,'全唐诗/poet.song.217000.json','["風不來，樹不動。", "溈仰父子，互呈體用。", "三十烏藤話已行，萬牛回首丘山重。"]'),
('ad6cd495-354c-4c84-a502-d02c8924b512','偈頌一百零九首  其九','釋可湘','宋','宋诗','song-poetry','','[]','未舉念，周遊華藏。',31,'全唐诗/poet.song.217000.json','["未舉念，周遊華藏。", "未下足，超越毗盧。", "若道一法在門外，笑倒文殊。"]'),
('4f800a29-283e-43a5-b42d-6523e2b5da97','偈頌一百零九首  其一○','釋可湘','宋','宋诗','song-poetry','','[]','撥塵見佛，佛亦是塵。',24,'全唐诗/poet.song.217000.json','["撥塵見佛，佛亦是塵。", "山僧脚布作炊巾，眼不見爲浄。"]'),
('2fc39ad8-1f58-409e-a286-caf9d704be33','偈頌一百零九首  其一一','釋可湘','宋','宋诗','song-poetry','','[]','薄福住常雲，生涯只任真。',48,'全唐诗/poet.song.217000.json','["薄福住常雲，生涯只任真。", "燈籠懸露柱，北斗對南辰。", "法法皆依位，機機合見人。", "大家齊努力，扶起破沙盆。"]'),
('44b9be25-4ca8-40d0-ac89-e13ef9c88959','偈頌一百零九首  其一二','釋可湘','宋','宋诗','song-poetry','','[]','悉達出頭來，賣弄醜舉止。',40,'全唐诗/poet.song.217000.json','["悉達出頭來，賣弄醜舉止。", "雲門打不殺，德山呵不起。", "曉間園裡聽鶑啼，昔日毗嵐今宛爾。"]'),
('5f01a790-53ff-46b8-89d1-aa7a3d23ad28','偈頌一百零九首  其一三','釋可湘','宋','宋诗','song-poetry','','[]','幽壑鼓寒濤，霜林木葉飄。',24,'全唐诗/poet.song.217000.json','["幽壑鼓寒濤，霜林木葉飄。", "普通年遠事，歷歷在今朝。"]'),
('2a7f7aec-0b9e-4b07-8ff1-e51b0d21ae48','偈頌一百零九首  其一四','釋可湘','宋','宋诗','song-poetry','','[]','初三十一，中九下七。',34,'全唐诗/poet.song.217000.json','["初三十一，中九下七。", "今朝總入書雲筆，大書特書兼屢書，祖師兩眼黑如漆。"]'),
('dde625fa-2765-498b-87d3-a1c8ea6bc757','偈頌一百零九首  其一五','釋可湘','宋','宋诗','song-poetry','','[]','臘月五，無別語。',36,'全唐诗/poet.song.217000.json','["臘月五，無別語。", "握起須彌槌，打動虛空鼓。", "五日風，十日雨，聖人作而萬物覩。"]'),
('b2d913bc-171c-4026-bdf9-480de63a826e','偈頌一百零九首  其一六','釋可湘','宋','宋诗','song-poetry','','[]','一大藏教，了無關鑰。',36,'全唐诗/poet.song.217000.json','["一大藏教，了無關鑰。", "奇峰峩峩，幽石落落。", "撥轉機輪話已行，到底不留元字脚。"]'),
('57632d06-47d7-41de-93b7-0ad7c9808721','偈頌一百零九首  其一七','釋可湘','宋','宋诗','song-poetry','','[]','每憐紙撚揾無油，將底光輝古蕩湫。',32,'全唐诗/poet.song.217000.json','["每憐紙撚揾無油，將底光輝古蕩湫。", "今日元宵時節至，也還水上掛燈毬。"]'),
('276c832b-b578-49d9-8233-c51346a02609','偈頌一百零九首  其一八','釋可湘','宋','宋诗','song-poetry','','[]','胸摩卍字，弄假像真。',36,'全唐诗/poet.song.217000.json','["胸摩卍字，弄假像真。", "槨示雙趺，弄真像假。", "柳垂金線舞春風，演說涅槃猶未罷。"]'),
('aabcbbcb-3fe8-4cec-90d9-f81cff277a9b','偈頌一百零九首  其一九','釋可湘','宋','宋诗','song-poetry','','[]','門外門內，一時分付。',20,'全唐诗/poet.song.217000.json','["門外門內，一時分付。", "若是俊流，何必重舉。"]'),
('b584a255-640e-45fb-beac-9f992654eb3a','偈頌一百零九首  其二○','釋可湘','宋','宋诗','song-poetry','','[]','老瞿曇，沒碑記。',28,'全唐诗/poet.song.217000.json','["老瞿曇，沒碑記。", "占慈氏機先，埋通天界至。", "也須還我坐具地。"]'),
('04d2679d-da43-4273-8f90-1511d522ef1d','偈頌一百零九首  其二一','釋可湘','宋','宋诗','song-poetry','','[]','佛祖眼睛，衲僧命脈。',28,'全唐诗/poet.song.217000.json','["佛祖眼睛，衲僧命脈。", "觸境遇緣，單重交拆。", "桃花紅，李花白。"]'),
('53e7e9a2-363f-46df-ae2b-9e3ae6e1bb0e','偈頌一百零九首  其二二','釋可湘','宋','宋诗','song-poetry','','[]','拶透大圓覺，平地沉山岳。',24,'全唐诗/poet.song.217000.json','["拶透大圓覺，平地沉山岳。", "翻笑刻舟人，無繩徒自縛。"]'),
('ca37afd0-5252-4425-8796-099056649540','偈頌一百零九首  其二三','釋可湘','宋','宋诗','song-poetry','','[]','冬節前後，砂飛石走。',40,'全唐诗/poet.song.217000.json','["冬節前後，砂飛石走。", "忽憶溈山兩鳳毛，進前退後揚家醜。", "畢竟九巖作麽生，面南看北斗。"]'),
('701606a7-e29f-44bb-ab1b-bac165da7ba4','偈頌一百零九首  其二四','釋可湘','宋','宋诗','song-poetry','','[]','言中彼此带幽玄，盡向言中辨正偏。',32,'全唐诗/poet.song.217000.json','["言中彼此带幽玄，盡向言中辨正偏。", "孤負一條官驛路，茫茫沉在月明前。"]'),
('753bbe1b-0d77-4d10-933e-179a51a2e604','偈頌一百零九首  其二五','釋可湘','宋','宋诗','song-poetry','','[]','中秋令節，陞堂指月。',20,'全唐诗/poet.song.217000.json','["中秋令節，陞堂指月。", "眨得眼來，楚天空闊。"]'),
('52f48f72-187d-473d-8f52-ae399b70ad42','偈頌一百零九首  其二六','釋可湘','宋','宋诗','song-poetry','','[]','十方同聚會，瞎馿趁大隊。',42,'全唐诗/poet.song.217000.json','["十方同聚會，瞎馿趁大隊。", "箇箇學無爲，眉上更安眉。", "此是選佛場，屎窖立封疆，心空及第歸。"]'),
('c3c99e0b-064a-4153-9703-339d241fda33','偈頌一百零九首  其二七','釋可湘','宋','宋诗','song-poetry','','[]','黄面老，初成道，誇詫一場相皷倒。',48,'全唐诗/poet.song.217000.json','["黄面老，初成道，誇詫一場相皷倒。", "雪嶺峩峩雪未消，星河湛湛星猶皎。", "諸人冷地眼開時，莫似貧兒拾得寶。"]'),
('5afe4a79-fd27-4f8c-8725-e5326281cd5c','偈頌一百零九首  其二八','釋可湘','宋','宋诗','song-poetry','','[]','一年十二月，過了無多日。',48,'全唐诗/poet.song.217000.json','["一年十二月，過了無多日。", "乃事竟如何，茫然黑似漆。", "休休休，空悠悠，前許多時何處去，大寒然後索衣裘。"]'),
('781d1801-a5fe-482b-bc7d-0e8823f2cfe2','偈頌一百零九首  其二九','釋可湘','宋','宋诗','song-poetry','','[]','岸柳駸駸綠，巖花漸漸紅。',40,'全唐诗/poet.song.217000.json','["岸柳駸駸綠，巖花漸漸紅。", "摩胸一段義，舒卷在春風。", "分明點與諸人了，切忌朦朧在夢中。"]'),
('7bb19630-0edb-4958-b220-117dcdd9ac99','偈頌一百零九首  其三○','釋可湘','宋','宋诗','song-poetry','','[]','道道，非常道。',39,'全唐诗/poet.song.217000.json','["道道，非常道。", "踏不嗔，閙浩浩。", "莫管自家知不知，但看大熟秋成早。", "今日無端入荒草。"]'),
('8b495d10-22da-48d9-aacf-2df7b60591ad','偈頌一百零九首  其三一','釋可湘','宋','宋诗','song-poetry','','[]','祖翁活業，無減無增。',36,'全唐诗/poet.song.217000.json','["祖翁活業，無減無增。", "縱不挨究，亦自分明。", "古田蓄水重重綠，野燒迎春漸漸青。"]'),
('78240e15-96d9-4bec-882f-cdb8ee2a7c79','偈頌一百零九首  其三二','釋可湘','宋','宋诗','song-poetry','','[]','如來禪與祖師心，不在靈山及少林。',32,'全唐诗/poet.song.217000.json','["如來禪與祖師心，不在靈山及少林。", "日轉柳陰蓮沼靜，亂蟬嗚咽衆蛙嗂。"]'),
('9ffb1fc2-b858-4724-9f38-3f01e456e22a','偈頌一百零九首  其三三','釋可湘','宋','宋诗','song-poetry','','[]','幾次淘澄，半生熬煉。',54,'全唐诗/poet.song.217000.json','["幾次淘澄，半生熬煉。", "直教氣息全無，脫體精明自現。", "粗細短長，突出難辨。", "不是心，不是佛，不是物，分曉一團銀繡線。"]'),
('5a7ced41-ff9f-4db3-9d49-dd08e3702b6e','偈頌一百零九首  其三四','釋可湘','宋','宋诗','song-poetry','','[]','咬定牙關，全提殺活。',30,'全唐诗/poet.song.217000.json','["咬定牙關，全提殺活。", "刳文殊脛，拔維摩舌。", "更有一機，不說不說。"]'),
('bfddb0ed-4761-46c6-b672-16466e373520','偈頌一百零九首  其三五','釋可湘','宋','宋诗','song-poetry','','[]','多處添，少處減。',18,'全唐诗/poet.song.217000.json','["多處添，少處減。", "家常用度，文不加點。"]'),
('bb3e6aad-cedf-48e4-9685-8f1d40be5a3a','偈頌一百零九首  其三六','釋可湘','宋','宋诗','song-poetry','','[]','乾紙燃，漏燈盞，茫茫蹉過人何限。',32,'全唐诗/poet.song.217000.json','["乾紙燃，漏燈盞，茫茫蹉過人何限。", "當頭點出許誰看，三世如來同箇眼。"]'),
('4a2b0bd2-0538-4b57-bc60-2e0c259e6f23','偈頌一百零九首  其三七','釋可湘','宋','宋诗','song-poetry','','[]','心不是佛，智不是道。',54,'全唐诗/poet.song.217000.json','["心不是佛，智不是道。", "唯此一事，如何尋討。", "赤水得之非珍，崑崗拾來非寶。", "寒山子，曾了了。", "微風吹幽松，近聽聲愈好。"]'),
('b03eb21e-8b24-490e-a530-fb24dbdff218','偈頌一百零九首  其三八','釋可湘','宋','宋诗','song-poetry','','[]','黄面老漢，至死脫空。',36,'全唐诗/poet.song.217000.json','["黄面老漢，至死脫空。", "分明病背，特故摩胸。", "當日無人知此意，年年花鳥訴春風。"]'),
('783b50a1-6e8c-4314-a2df-d5ee6e09488c','偈頌一百零九首  其三九','釋可湘','宋','宋诗','song-poetry','','[]','南來北來，上載下載。',71,'全唐诗/poet.song.217000.json','["南來北來，上載下載。", "趙州老兒，法久成弊。", "三峰建箇門庭，除此別無體制。", "任是宿覺經過，也只一樣看待。", "分什麽南贍部洲，北鬰單越，西瞿耶尼，東弗于逮。"]'),
('f5e2de38-e463-4f1c-8ce1-1dfa228af4fd','偈頌一百零九首  其四○','釋可湘','宋','宋诗','song-poetry','','[]','古佛以慈悲爲室，山僧以怒駡爲室。',28,'全唐诗/poet.song.217000.json','["古佛以慈悲爲室，山僧以怒駡爲室。", "且要活捉生蛇，逼教角出。"]'),
('d57f0741-55d5-4af0-9bec-df1b0e85f1b2','偈頌一百零九首  其四一','釋可湘','宋','宋诗','song-poetry','','[]','開天門，闢地戶。',16,'全唐诗/poet.song.217000.json','["開天門，闢地戶。", "震法雷，擊法皷。"]'),
('2aac9c16-2e3a-4e12-a5a7-8e1844883209','偈頌一百零九首  其四二','釋可湘','宋','宋诗','song-poetry','','[]','劄住智者頰舌，剖出達磨骨髓。',24,'全唐诗/poet.song.217000.json','["劄住智者頰舌，剖出達磨骨髓。", "長劍倚天，寒光焰焰。"]'),
('87e7c8fc-845b-4264-b96f-b694c98f6166','偈頌一百零九首  其四三','釋可湘','宋','宋诗','song-poetry','','[]','身不離座，座不離身。',28,'全唐诗/poet.song.217000.json','["身不離座，座不離身。", "須彌燈王，又是何人。", "老來擡脚重千斤。"]'),
('012d7687-6fbe-4d99-b5a0-53fffdf28969','偈頌一百零九首  其四四','釋可湘','宋','宋诗','song-poetry','','[]','二月春將半，夭桃盛放花。',45,'全唐诗/poet.song.217000.json','["二月春將半，夭桃盛放花。", "靈雲歸去後，香艷落誰家。", "只如道直至如今更不疑，遇飯喫飯，遇茶喫茶。"]'),
('d6fdff49-7472-494e-85d1-f580c3476563','偈頌一百零九首  其四五','釋可湘','宋','宋诗','song-poetry','','[]','春日遲遲，春花爛爛。',28,'全唐诗/poet.song.217000.json','["春日遲遲，春花爛爛。", "般若靈光，顯然無間。", "捏不聚兮撥不散。"]'),
('63d9afdf-b0ff-477e-8827-6ff1e433da3d','偈頌一百零九首  其四六','釋可湘','宋','宋诗','song-poetry','','[]','一徑直，二周遮。',34,'全唐诗/poet.song.217000.json','["一徑直，二周遮。", "不循舊制，別立生涯。", "藕絲竅裡翻筋斗，麥浪堆中釣得蝦。"]'),
('086f787d-56b6-4972-9891-a34802a6d833','偈頌一百零九首  其四七','釋可湘','宋','宋诗','song-poetry','','[]','日月如梭，光陰似箭。',37,'全唐诗/poet.song.217000.json','["日月如梭，光陰似箭。", "目前一機，萬化千變。", "甚處見得，西風一陣來，落葉兩三片。"]'),
('21e735d8-d01d-4a0f-a79b-80882342ca4c','偈頌一百零九首  其四八','釋可湘','宋','宋诗','song-poetry','','[]','凌霄隊裡，昔曾合火分贓。',46,'全唐诗/poet.song.217000.json','["凌霄隊裡，昔曾合火分贓。", "小朶峰前，善賈不停死貨。", "橫身那畔，鶻眼迷蹤。", "歸根深得旨，落葉舞西風。"]'),
('274287c7-8238-4a31-8b82-ecf8d25b8472','偈頌一百零九首  其四九','釋可湘','宋','宋诗','song-poetry','','[]','一脚跨西天，隻履駐東土。',56,'全唐诗/poet.song.217000.json','["一脚跨西天，隻履駐東土。", "缺齒老臊胡，自來行闊步。", "兒孫遍地覓蹤由，長憶年年十月五。", "嗈嗈兮寒雁鳴雲，凜凜兮霜風襲戶。"]'),
('bae3c1ce-ccaf-423f-b77c-568281bd4cb2','偈頌一百零九首  其五○','釋可湘','宋','宋诗','song-poetry','','[]','吳山青，越山青。',42,'全唐诗/poet.song.217000.json','["吳山青，越山青。", "揖讓分賓主，低昂見弟兄。", "中間一句，風靜潮平。", "滿堂皆顧陸，捉筆畫難成。"]'),
('638e8bcb-0207-4748-9892-9f4d94215add','偈頌一百零九首  其五一','釋可湘','宋','宋诗','song-poetry','','[]','灌頂雲收，峩眉月晝。',42,'全唐诗/poet.song.217000.json','["灌頂雲收，峩眉月晝。", "父翁一片肝腸，宛如生鐵鑄就。", "弟應兄呼，全機漏逗。", "蘇州菱，邵伯藕。"]'),
('ec272151-d30c-48c8-9ade-30f7790ddd65','偈頌一百零九首  其五二','釋可湘','宋','宋诗','song-poetry','','[]','春山疊亂青，春水湛虛碧。',40,'全唐诗/poet.song.217000.json','["春山疊亂青，春水湛虛碧。", "豁開樓閣門，分身千百億。", "一念差，雲羃羃，善財無路尋知識。"]'),
('84ede7cc-f017-42ec-bcc8-8831abd1973c','偈頌一百零九首  其五三','釋可湘','宋','宋诗','song-poetry','','["\u897f\u6e56"]','撞出娘胎海嶽昏，指天指地若無人。',32,'全唐诗/poet.song.217000.json','["撞出娘胎海嶽昏，指天指地若無人。", "年年傾盡西湖水，難洗瞿曇滿面塵。"]'),
('78358774-d7a6-4bc8-9664-034aeaf16fc9','偈頌一百零九首  其五四','釋可湘','宋','宋诗','song-poetry','','[]','不是心，亦非佛。',46,'全唐诗/poet.song.217000.json','["不是心，亦非佛。", "玉兔東昇，金烏西沒。", "循環不暫停，究竟知何物。", "那箇男兒腕力强，一槌擊碎精靈窟。"]'),
('d1db8999-f647-44ef-9273-3dd1e6ec797c','偈頌一百零九首  其五五','釋可湘','宋','宋诗','song-poetry','','[]','雪山高幾何，矗矗在天表。',44,'全唐诗/poet.song.217000.json','["雪山高幾何，矗矗在天表。", "咄哉竺土仙，六年登不到。", "登得到，絕之遶，背手摘南辰，下視衆峰小。"]'),
('55fae244-98fa-4e5e-adbd-0aaf3da392f8','偈頌一百零九首  其五六','釋可湘','宋','宋诗','song-poetry','','[]','石說法，不談禪。',46,'全唐诗/poet.song.217000.json','["石說法，不談禪。", "句句皆含妙，明明不在言。", "難將耳聽，只貴心傳。", "此外別求玄路入，洛陽橋上望長安。"]'),
('10ef8e53-9b91-4baf-b321-d052666c7e26','偈頌一百零九首  其五七','釋可湘','宋','宋诗','song-poetry','','[]','瞿曇出母胎，膽志大如斗。',56,'全唐诗/poet.song.217000.json','["瞿曇出母胎，膽志大如斗。", "方學小兒行，便作獅子吼。", "水在湖，杓在手，乘時蕩向無何有。", "也勝雲門老古錐，藥囊空掉喪車後。"]'),
('ad52d850-9b62-43a5-be3a-5d030783a39f','偈頌一百零九首  其五八','釋可湘','宋','宋诗','song-poetry','','[]','東去西去，南來北來。',58,'全唐诗/poet.song.217000.json','["東去西去，南來北來。", "銅頭鐵額，馬面馿腮。", "毫端上打𨁝跳，燈影裡舞三臺。", "演福且搭箇樣子，耍得好親見一回，睡眼朦朧擘不開。"]'),
('072e6af7-e288-4df5-a124-feeb46ea4906','偈頌一百零九首  其五九','釋可湘','宋','宋诗','song-poetry','','[]','衲子奔相看，相看莫相負。',52,'全唐诗/poet.song.217000.json','["衲子奔相看，相看莫相負。", "飲水須貴脈，入門富弁主。", "問訊時，揖茶處，總爲諸人開活路。", "若是謝三郎，揚眉便歸去。"]'),
('44ca4ae0-272c-44a3-9ac2-9d4be5447c2b','偈頌一百零九首  其六○','釋可湘','宋','宋诗','song-poetry','','[]','東家點燈，西家暗坐。',36,'全唐诗/poet.song.217000.json','["東家點燈，西家暗坐。", "一樣元宵，生涯各做。", "暗坐底默默提撕，點燈者明明照破。"]'),
('ad818c30-4223-4777-89bf-56d3659183e3','偈頌一百零九首  其六一','釋可湘','宋','宋诗','song-poetry','','[]','了了無言，驀胸一拳。',20,'全唐诗/poet.song.217000.json','["了了無言，驀胸一拳。", "蜃江水急，不許泊船。"]'),
('e40ccce1-3fab-46be-bf7c-4e8d6e639126','偈頌一百零九首  其六二','釋可湘','宋','宋诗','song-poetry','','[]','大化樞機，中流砥柱。',20,'全唐诗/poet.song.217000.json','["大化樞機，中流砥柱。", "歸吾掌握，當見設施。"]'),
('b98bee21-d12f-435f-b2a3-f10fb70e967a','偈頌一百零九首  其六三','釋可湘','宋','宋诗','song-poetry','','[]','追憶仙遊輦未還，特輸忠赤舉風幡。',32,'全唐诗/poet.song.217000.json','["追憶仙遊輦未還，特輸忠赤舉風幡。", "掣開玉殿黄金鎖，最忌當頭觸聖顔。"]'),
('48714531-3d84-4a4e-ba91-ee9376937907','偈頌一百零九首  其六四','釋可湘','宋','宋诗','song-poetry','','[]','江上山，山上寺。',38,'全唐诗/poet.song.217000.json','["江上山，山上寺。", "門對斗城開，東西分兩序，總不得動著。", "是法住法位，世間相常住。"]'),
('bac3664b-129b-461c-931e-12a18458daa6','偈頌一百零九首  其六五','釋可湘','宋','宋诗','song-poetry','','[]','今朝五月五，及時道一句。',76,'全唐诗/poet.song.217000.json','["今朝五月五，及時道一句。", "無山可採藥，有水堪競渡。", "江心如許大龍舟，聚集梢郎同駕御。", "彼岸不著，此岸不居。", "只箇中流，住無所住。", "機先奪得錦標歸，石女木人爭起舞。"]'),
('1ad13e13-3565-4e41-9373-37526d56a260','偈頌一百零九首  其六六','釋可湘','宋','宋诗','song-poetry','','[]','巾子峰頭雲開雲合，龍翔江上潮落潮平。',44,'全唐诗/poet.song.217000.json','["巾子峰頭雲開雲合，龍翔江上潮落潮平。", "師承底事，的的分明。", "風前不必兄呼弟，見後毋勞弟應兄。"]'),
('dee368df-fc7f-4d1a-913b-5b873ec5ab38','偈頌一百零九首  其六七','釋可湘','宋','宋诗','song-poetry','','["\u6625\u5929"]','春雪滿空來，觸處似花開。',24,'全唐诗/poet.song.217000.json','["春雪滿空來，觸處似花開。", "不知園裡樹，那箇是真梅。"]'),
('0dbab1da-dfff-4aae-b010-ee4bb9edd973','偈頌一百零九首  其六八','釋可湘','宋','宋诗','song-poetry','','[]','摩胸告，展脚示。',28,'全唐诗/poet.song.217000.json','["摩胸告，展脚示。", "有來由，沒巴鼻。", "佛滅二千年，比丘少慚愧。"]'),
('1c7c44ec-d50a-4366-8ca6-b0a8fc7ec81f','偈頌一百零九首  其六九','釋可湘','宋','宋诗','song-poetry','','[]','建法幢，立宗旨。',73,'全唐诗/poet.song.217000.json','["建法幢，立宗旨。", "既承師訓，合聽官差。", "且宗旨法幢作麽生建立。", "行船同一命，方屯飛虎於江心。", "打皷召三軍，又布長蛇於雪嶺。", "海宇頓清猶带甲，心王親覩始休兵。"]'),
('5328de49-1d17-488a-ab6e-11ea0c7933a0','偈頌一百零九首  其七○','釋可湘','宋','宋诗','song-poetry','','[]','無門之門須得門而入，無意之意須得意而通。',28,'全唐诗/poet.song.217000.json','["無門之門須得門而入，無意之意須得意而通。", "一扇西兮一扇東。"]'),
('18538411-9133-4713-b20d-5203ef93a77d','偈頌一百零九首  其七一','釋可湘','宋','宋诗','song-poetry','','[]','頑鈍以此銷鎔，偏小以此彈擊。',32,'全唐诗/poet.song.217000.json','["頑鈍以此銷鎔，偏小以此彈擊。", "直中曲，曲中直。", "老盧不會，達磨不識。"]'),
('c792e176-669e-45d7-b4d3-3d34ea4aac14','偈頌一百零九首  其七二','釋可湘','宋','宋诗','song-poetry','','[]','一劄當頭，無咽喘氣，大鈞播物，易地生春。',28,'全唐诗/poet.song.217000.json','["一劄當頭，無咽喘氣，大鈞播物，易地生春。", "佛祖都來聽處分。"]'),
('53f62d99-aaa6-4cd9-b76c-1e1b948daf1a','偈頌一百零九首  其七三','釋可湘','宋','宋诗','song-poetry','','[]','語是謗，默是誑。',80,'全唐诗/poet.song.217000.json','["語是謗，默是誑。", "語默向上一機，佛祖聞而膽喪。", "曾郎輥三箇木毬，德山揮一條白棒。", "盡是弄精魂，呈影像。", "何似脚指築著，挨門拶著。", "卷簾見著，堪作衲僧榜樣。", "一聲鶴唳千峰上。"]'),
('a010a45b-7136-4391-a179-7b5391697c2e','偈頌一百零九首  其七四','釋可湘','宋','宋诗','song-poetry','','[]','太白峰頭月，寒泉水底燈。',40,'全唐诗/poet.song.217000.json','["太白峰頭月，寒泉水底燈。", "清光分上下，千里恰同明。", "一點不來翻夜雨，難謾迦葉老師兄。"]'),
('e089d4c9-08c1-44da-9eb4-e9c3ad4e85a4','偈頌一百零九首  其七五','釋可湘','宋','宋诗','song-poetry','','[]','烟樹斫開，曉月掛簷。',50,'全唐诗/poet.song.217000.json','["烟樹斫開，曉月掛簷。", "嘶木馬嶺雲耕罷，春風吹雨。", "吼泥牛聲前，領會無差。", "共樂法，喜禪悅，打刀須是邠州鐵。"]'),
('d5360600-cb8e-439d-9299-a7e528b04f84','偈頌一百零九首  其七六','釋可湘','宋','宋诗','song-poetry','','[]','今朝三月十五，眨眼又見春暮。',44,'全唐诗/poet.song.217000.json','["今朝三月十五，眨眼又見春暮。", "尺璧難酬寸陰，白日豈宜虛度。", "可憐杜宇一聲聲，啼得血流無用處。"]'),
('22365c82-ed24-44d0-97dd-3500b8748383','偈頌一百零九首  其七七','釋可湘','宋','宋诗','song-poetry','','[]','仰天灣下，喝石嶺頭。',70,'全唐诗/poet.song.217000.json','["仰天灣下，喝石嶺頭。", "昔年落賺，覆水難收。", "當堂稱父子，背面是冤仇。", "影也不願再見，豈料界隨相逐同到福州。", "莫莫莫，休休休。", "粗香强撮土，說破不爲讎。"]'),
('a9b3ff3f-f55f-4050-86a2-7e9098923802','偈頌一百零九首  其七八','釋可湘','宋','宋诗','song-poetry','','[]','十方國土中，惟有一乘法。',35,'全唐诗/poet.song.217000.json','["十方國土中，惟有一乘法。", "如何是一乘法，梅雨過，芰荷香，薰風殿閣生微凉。"]'),
('f4068ea4-f23c-4509-9801-9b32b6b6d65b','偈頌一百零九首  其七九','釋可湘','宋','宋诗','song-poetry','','[]','平明始立秋，冷已到山頭。',67,'全唐诗/poet.song.217000.json','["平明始立秋，冷已到山頭。", "談風說露兮蜩蟬嘒急，詠砌吟牆兮蟋蟀聲浮。", "不作佛法商量，不作時景話會。", "觀世音菩薩將錢買胡餠，放下手却是生鐵一塊。"]'),
('db5ddd6b-28d9-4f4d-aaeb-38551a9a475e','偈頌一百零九首  其八○','釋可湘','宋','宋诗','song-poetry','','[]','九日正當期，登高報衆知。',50,'全唐诗/poet.song.217000.json','["九日正當期，登高報衆知。", "黄花到處有，豈獨在東籬。", "難逢美景，採出一枝。", "觸目無人明此意，何妨自插滿頭歸。"]'),
('78a24f84-6257-4ee7-8e98-fc71963fe3bf','偈頌一百零九首  其八一','釋可湘','宋','宋诗','song-poetry','','[]','洞山首座喫果子，開口落空亡。',72,'全唐诗/poet.song.217000.json','["洞山首座喫果子，開口落空亡。", "雪嶠兩堂吞栗蓬，分頭張意氣。", "衲僧家，手是秤，眼是秤，輕也知，重也知。", "半斤八兩，毫髮無虧。", "爭奈未明三八九，難辨力㘞希。"]'),
('f69fe3e7-84c4-4e8b-a695-bb3420d21403','偈頌一百零九首  其八二','釋可湘','宋','宋诗','song-poetry','','[]','金烏飛，玉兔馳。',36,'全唐诗/poet.song.217000.json','["金烏飛，玉兔馳。", "歸來重會面，動是隔年期。", "鼻頭垂下元如舊，三昧依前各不知。"]'),
('3601abe5-bf90-45e7-a317-18be498ba1b9','偈頌一百零九首  其八三','釋可湘','宋','宋诗','song-poetry','','[]','趙州轉藏，動必全真。',36,'全唐诗/poet.song.217000.json','["趙州轉藏，動必全真。", "婆子開緘，語驚時聽。", "從前汗馬無人識，只要重論蓋代功。"]'),
('634004f8-d02e-4066-a5de-4db565a0ab00','偈頌一百零九首  其八四','釋可湘','宋','宋诗','song-poetry','','[]','傍家覓佛，著相參禪。',52,'全唐诗/poet.song.217000.json','["傍家覓佛，著相參禪。", "何異釣魚於山上，聽水於爐邊。", "三冬今去一，眨眼過殘年。", "翻思少室庭前雪，惟有神光得正傳。"]'),
('b3dac9ef-cc66-4aa9-9848-0145ba81ff53','偈頌一百零九首  其八五','釋可湘','宋','宋诗','song-poetry','','[]','三聲鼎蓋普門開，苦海勞生喚不回。',32,'全唐诗/poet.song.217000.json','["三聲鼎蓋普門開，苦海勞生喚不回。", "九十春光今又半，空飛花片點莓苔。"]'),
('e55b7699-792e-4851-b6ae-27bed0598c22','偈頌一百零九首  其八六','釋可湘','宋','宋诗','song-poetry','','[]','清明前，寒食後，處處掃松，家家插柳。',46,'全唐诗/poet.song.217000.json','["清明前，寒食後，處處掃松，家家插柳。", "祖意甚分明，茫然不知有。", "三皇塚上絕人遊，芳草連天髑髏吼。"]'),
('b89cf477-c30b-48ba-b9a9-fdd94743275e','偈頌一百零九首  其八七','釋可湘','宋','宋诗','song-poetry','','[]','集雲法令不徒施，趁起丹山白鳳兒。',32,'全唐诗/poet.song.217000.json','["集雲法令不徒施，趁起丹山白鳳兒。", "昨夜已飛霄漢去，平明空撼碧梧枝。"]'),
('b8fc3e63-6bef-4a19-8d07-2c0efeebbd41','偈頌一百零九首  其八八','釋可湘','宋','宋诗','song-poetry','','[]','打牛即是，打車即是。',38,'全唐诗/poet.song.217000.json','["打牛即是，打車即是。", "一種無絃琴，彈落知音耳。", "委不委，曹娥讀夜碑，且較三十里。"]'),
('54ddc6be-4347-4c93-9e68-48782f7d9251','偈頌一百零九首  其八九','釋可湘','宋','宋诗','song-poetry','','[]','心王寧，六國清。',113,'全唐诗/poet.song.217000.json','["心王寧，六國清。", "百川潮落，四海浪平。", "其如轇轕情塵，當遵古佛制，若也沉昏道眼，還待臘八冰。", "心王遼邈，孰覩其形。", "記得柏巖問洞山，觀察使姓什麽，不委他姓。", "名什麽，不委他名。", "殆傳尊貴語，舉目隔神京。", "相留過夏，曲徇人情。", "往往都來欠一程。"]'),
('c1ba52ab-eda1-40a3-b6d7-3ca481f7f7ba','偈頌一百零九首  其九○','釋可湘','宋','宋诗','song-poetry','','[]','眼若不睡，諸夢自除。',40,'全唐诗/poet.song.217000.json','["眼若不睡，諸夢自除。", "心若不異，萬法一如。", "佛也無，魔也無，今朝五月五，何用釘桃符。"]'),
('3e172b16-93df-42a0-b05f-4fa4d3211228','偈頌一百零九首  其九一','釋可湘','宋','宋诗','song-poetry','','[]','直下便瞥，炎天降雪。',55,'全唐诗/poet.song.217000.json','["直下便瞥，炎天降雪。", "當今蹉者一回，前面煞有酷熱。", "那堪鐵彈鑄未成，臘八冰不結。", "且過六月七月八月，更聽松風動寥泬。"]'),
('9ffe28bf-7a91-4175-b80c-ed79ecd9a8b5','偈頌一百零九首  其九二','釋可湘','宋','宋诗','song-poetry','','[]','世事悠悠，美景難留。',44,'全唐诗/poet.song.217000.json','["世事悠悠，美景難留。", "不可寢於長夜，須來共賞中秋。", "天宇浄，桂花浮。", "一片月生海，幾家人上樓。"]'),
('07e78bb6-c7ea-4ad4-9ca2-854879d7475d','偈頌一百零九首  其九三','釋可湘','宋','宋诗','song-poetry','','[]','重陽節，何可說。',54,'全唐诗/poet.song.217000.json','["重陽節，何可說。", "籬菊新開剪剪金，霜柑微露團團月。", "元亮攢眉回去見境生情，閩王特地緘來弄巧成拙。", "處處登高看不徹。"]'),
('c7a82fa8-2fc2-4b98-abe8-687d03860ef7','偈頌一百零九首  其九四','釋可湘','宋','宋诗','song-poetry','','[]','兩肩擔不起，壓倒世間人。',86,'全唐诗/poet.song.217000.json','["兩肩擔不起，壓倒世間人。", "覿體常現前，知他是什麽。", "縱使六陰塞戶，無欠亦無餘。", "假饒一氣轉鈞，同明復同暗。", "瞿曇廣說，達磨直指。", "詰其端由，全沒巴鼻。", "驀見陽生第一爻，九九元來八十二。"]'),
('41ddc90e-478d-46bf-a28d-4d63668f9932','偈頌一百零九首  其九五','釋可湘','宋','宋诗','song-poetry','','[]','一陽生，飄瑞雪，喚轉鰲山底時節。',36,'全唐诗/poet.song.217000.json','["一陽生，飄瑞雪，喚轉鰲山底時節。", "鐵樹開瓊花，烏龜變白鱉，普賢眼裡重添屑。"]'),
('1bde1ff0-269d-486e-9fb9-2902f544b693','偈頌一百零九首  其九六','釋可湘','宋','宋诗','song-poetry','','[]','空中一片雲，起滅渾無定。',40,'全唐诗/poet.song.217000.json','["空中一片雲，起滅渾無定。", "或要下筆書，或要用釘釘。", "竹杖拈來畫斷休，免得年年爲話柄。"]'),
('b9228fd4-a426-42c1-8b43-f543e96d100d','偈頌一百零九首  其九七','釋可湘','宋','宋诗','song-poetry','','[]','我此震旦人，到底少意氣。',72,'全唐诗/poet.song.217000.json','["我此震旦人，到底少意氣。", "放伊過界來，波濤起平地。", "直指單傳，有甚巴鼻。", "神光因爲這些，著了娘生隻臂。", "是旃檀，是馿屎。", "等閑一嗅腦門開，二十八代西天記。"]'),
('e230c96a-097e-4153-9fb4-be3ace2826a6','偈頌一百零九首  其九八','釋可湘','宋','宋诗','song-poetry','','[]','前時向者裡抽釘拔楔，而今却要添釘著楔。',38,'全唐诗/poet.song.217000.json','["前時向者裡抽釘拔楔，而今却要添釘著楔。", "前時向者裡解粘去縛，而今却要添繩加索。"]'),
('bea1e533-6344-4a38-b362-cd6f607f2134','偈頌一百零九首  其九九','釋可湘','宋','宋诗','song-poetry','','[]','朱行軍威掩萬衆，特露太阿。',42,'全唐诗/poet.song.217000.json','["朱行軍威掩萬衆，特露太阿。", "濟上座氣蓋諸方，不顧性命。", "選佛若無如是眼，宗風爭得到于今。"]'),
('bf3ece01-590e-4b02-9bd6-e27cbcb6158d','偈頌一百零九首  其一○○','釋可湘','宋','宋诗','song-poetry','','[]','大藏小藏，盡從者裡流出。',48,'全唐诗/poet.song.217000.json','["大藏小藏，盡從者裡流出。", "放去千燈萬焰，收來一月當天。", "只如不收不放一句作麽生判斷，上元定是正月半。"]'),
('87c0020e-a941-47d0-8840-1e808cbc5b26','偈頌一百零九首  其一○一','釋可湘','宋','宋诗','song-poetry','','[]','溈仰兩爺兒，採茶機對機。',46,'全唐诗/poet.song.217000.json','["溈仰兩爺兒，採茶機對機。", "只知呈體用，不覺露槍旗。", "正值風和日暖，何妨把手同歸，子規啼破已多時。"]'),
('1d581b4d-cb6f-47d7-b6f3-87ea15e1950a','偈頌一百零九首  其一○二','釋可湘','宋','宋诗','song-poetry','','[]','始見桃花李花，又見榴花藕花。',42,'全唐诗/poet.song.217000.json','["始見桃花李花，又見榴花藕花。", "金色頭陀，已歸雞足，靈雲老子，杳隔天涯。", "安得風流出當家。"]'),
('7c0d9e26-517a-467a-874a-5c9e235a4447','偈頌一百零九首  其一○三','釋可湘','宋','宋诗','song-poetry','','[]','娑羅雙樹間，瞿曇展脚睡。',44,'全唐诗/poet.song.217000.json','["娑羅雙樹間，瞿曇展脚睡。", "一睡二千年，而今醒也未。", "醒了也，足觀瞻。", "山花開似錦，澗水湛如藍。"]'),
('aee627ae-28a2-4236-88db-3767a9487567','偈頌一百零九首  其一○四','釋可湘','宋','宋诗','song-poetry','','[]','象骨飛冰片，鰲山吃雪團。',46,'全唐诗/poet.song.217000.json','["象骨飛冰片，鰲山吃雪團。", "家風嚴冷甚，覷著骨毛寒。", "聲價騰今耀古，馨香炙地薰天。", "年年不斷一爐烟。"]'),
('b82911e9-13b9-4f3b-a77b-bb46883c77e2','偈頌一百零九首  其一○五','釋可湘','宋','宋诗','song-poetry','','[]','見鞭影而行已非良馬，聽板聲打坐豈是禪流。',46,'全唐诗/poet.song.217000.json','["見鞭影而行已非良馬，聽板聲打坐豈是禪流。", "參須自參，悟須自悟。", "少林孤坐接神光，更無一句閑言語。"]'),
('c96a80e2-67cf-4935-ae3e-61a237fe4e60','偈頌一百零九首  其一○六','釋可湘','宋','宋诗','song-poetry','','[]','光境易消磨，看看中夏過。',48,'全唐诗/poet.song.217000.json','["光境易消磨，看看中夏過。", "長連床上客，本分事如何。", "本分事，沒回互。", "石梯侍者曾有言，某甲實是上堂去。"]'),
('4974ab42-e4d1-402a-8e2b-d4ab77fdf674','偈頌一百零九首  其一○七','釋可湘','宋','宋诗','song-poetry','','[]','藥山久不上堂，石中藴玉。',59,'全唐诗/poet.song.217000.json','["藥山久不上堂，石中藴玉。", "院主率先啟請，眼裡無珠。", "昧一己而且從，誤三軍尤可憫。", "大似𪇅𪇅鳥守空池，魚從脚下過，𪇅𪇅總不知。"]'),
('ed83ef62-ce65-4914-a527-c9b8a8e14fb8','偈頌一百零九首  其一○八','釋可湘','宋','宋诗','song-poetry','','[]','嗟末法，惡時世。',85,'全唐诗/poet.song.217000.json','["嗟末法，惡時世。", "諭之向上關，略不點頭。", "說及龍華會，何曾抽採。", "但見需撒花索苗米，惱得頭白，逼得面黄。", "留香一鉢飯，渾是皺眉糧。", "今歲上供銀未解，來年新底又催綱。", "歸堂快合休糧方。"]'),
('56b9fb45-ee20-42da-b069-6f4a08cd1d52','偈頌一百零九首  其一○九','釋可湘','宋','宋诗','song-poetry','','[]','藥山索鹽，雲岩奉馬。',49,'全唐诗/poet.song.217000.json','["藥山索鹽，雲岩奉馬。", "父子一家，風流儒雅。", "我也有箇木毬，亦要輥上輥下。", "沙彌在麽，出手不來，還成滯貨。"]'),
('2d57b861-0532-44a9-aa3e-6c203046b500','頌古十四首  其一','釋可湘','宋','宋诗','song-poetry','','[]','右脇翻身已怪哉，那堪便解舞三臺。',32,'全唐诗/poet.song.217000.json','["右脇翻身已怪哉，那堪便解舞三臺。", "做模打樣無端甚，寧免傍觀臭口開。"]'),
('733639ae-e90b-496a-8522-0e3cfd3826dd','頌古十四首  其二','釋可湘','宋','宋诗','song-poetry','','[]','當堂據坐寶花牀，真相從來本自黄。',32,'全唐诗/poet.song.217000.json','["當堂據坐寶花牀，真相從來本自黄。", "百萬參徒誰不見，何須重把紫金粧。"]'),
('ab2e4703-02f9-4634-a7a1-4673c26028c2','頌古十四首  其三','釋可湘','宋','宋诗','song-poetry','','[]','靈山結舌舉花枝，迦葉難瞞展笑眉。',32,'全唐诗/poet.song.217000.json','["靈山結舌舉花枝，迦葉難瞞展笑眉。", "接響承虛到今日，兒孫棒喝競交馳。"]'),
('4d70298a-e27d-4d66-afdf-6fa47ca1f286','頌古十四首  其四','釋可湘','宋','宋诗','song-poetry','','[]','覆水難收滿竺峰，如何臨死更摩胸。',32,'全唐诗/poet.song.217000.json','["覆水難收滿竺峰，如何臨死更摩胸。", "說無說有成生滅，併付春風一夢中。"]'),
('9bae307f-e2d7-495c-9c50-2da16dca159f','頌古十四首  其五','釋可湘','宋','宋诗','song-poetry','','[]','鞭影非惟示阿難，敲空作響孰知還。',32,'全唐诗/poet.song.217000.json','["鞭影非惟示阿難，敲空作響孰知還。", "當時未必皆良馬，應妬清風起赤幡。"]'),
('7699f7ac-b269-4073-8114-94ae305e6abb','頌古十四首  其六','釋可湘','宋','宋诗','song-poetry','','[]','撥開日面與月面，彷彿前三及後三。',32,'全唐诗/poet.song.217000.json','["撥開日面與月面，彷彿前三及後三。", "病在膏肓重爝艾，昏兜院主可無慚。"]'),
('b3ad6e8f-5e96-4902-b91c-ea1ec5a2fc9a','頌古十四首  其七','釋可湘','宋','宋诗','song-poetry','','[]','望見毗耶彼上人，十中有九喪精魂。',32,'全唐诗/poet.song.217000.json','["望見毗耶彼上人，十中有九喪精魂。", "只消一箇渾崙石，打破群賢不二門。"]'),
('2894b8c7-56fa-4e01-bcab-db20421e26cc','頌古十四首  其八','釋可湘','宋','宋诗','song-poetry','','[]','千年相逐太無知，你道金剛齊是誰。',32,'全唐诗/poet.song.217000.json','["千年相逐太無知，你道金剛齊是誰。", "如是住時休說破，從教老漢自生疑。"]'),
('646558a0-b3f4-4a74-8e3f-e02c2e4c0cbb','頌古十四首  其九','釋可湘','宋','宋诗','song-poetry','','[]','七處徵它天外天，毫光直射阿難肩。',32,'全唐诗/poet.song.217000.json','["七處徵它天外天，毫光直射阿難肩。", "瞿曇忒煞憐兒切，逼得鮎魚上竹竿。"]'),
('6c08a96a-9357-43e1-b4c0-805b36ff061b','頌古十四首  其一○','釋可湘','宋','宋诗','song-poetry','','[]','還還還後更無還，一箇閑人天地間。',32,'全唐诗/poet.song.217000.json','["還還還後更無還，一箇閑人天地間。", "昨夜大蟲遭虎咬，皮毛落盡體元斑。"]'),
('5b12506b-da45-4a34-a274-eec0df47f6d9','頌古十四首  其一一','釋可湘','宋','宋诗','song-poetry','','[]','不向經頭識本真，紙堆討甚法王身。',32,'全唐诗/poet.song.217000.json','["不向經頭識本真，紙堆討甚法王身。", "未開梵夾承當去，免作循行數墨人。"]'),
('aff9890b-2ca6-4b53-96a6-c3913a370368','頌古十四首  其一二','釋可湘','宋','宋诗','song-poetry','','[]','有句無句藤倚樹，大似旱天開水路。',32,'全唐诗/poet.song.217000.json','["有句無句藤倚樹，大似旱天開水路。", "正當樹倒與藤枯，看看平地波濤注。"]'),
('2c635beb-7fee-437f-8e9d-4a02e8264ce2','頌古十四首  其一三','釋可湘','宋','宋诗','song-poetry','','[]','上樹垂機值虎頭，自知覆水已難收。',32,'全唐诗/poet.song.217000.json','["上樹垂機值虎頭，自知覆水已難收。", "猶能覿面呵呵笑，轉却三春作九秋。"]'),
('04ff10de-febf-48c7-a7bc-3df9f47fd036','頌古十四首  其一四','釋可湘','宋','宋诗','song-poetry','','[]','三番痛棒打馿腰，直往高安一款招。',32,'全唐诗/poet.song.217000.json','["三番痛棒打馿腰，直往高安一款招。", "急水灘頭翻巨浪，信知家富小兒驕。"]'),
('abd943e8-e5d2-4dfc-99a5-4d17a2de94cc','示衆','釋可湘','宋','宋诗','song-poetry','','[]','別傳一脈漲曹溪，萬法都來和不齊。',32,'全唐诗/poet.song.217000.json','["別傳一脈漲曹溪，萬法都來和不齊。", "葉落歸根至今日，江南猶有鷓鴣啼。"]'),
('7950d611-b016-4804-bf4d-5adf96d7d2ea','出山相贊','釋可湘','宋','宋诗','song-poetry','','[]','峭巍巍，孤迥迥。',32,'全唐诗/poet.song.217000.json','["峭巍巍，孤迥迥。", "棄王宮，棲雪嶺。", "分明凍得眼生星，幡然踏破千峰頂。"]'),
('b1c829ad-2fa3-4fb6-96dd-ddf6f39c0bec','觀音贊  其一','釋可湘','宋','宋诗','song-poetry','','[]','觀以耳觀，聽以眼聽。',66,'全唐诗/poet.song.217000.json','["觀以耳觀，聽以眼聽。", "道不虛行，谷不虛應。", "施無畏之力，滅煩惱之病。", "與諸佛同一慈心，與群生共一悲命。", "若非菩薩超越世出，世間焉能獲二殊勝。"]'),
('4ff998ff-5592-492f-87af-35d576417ca3','觀音贊  其二','釋可湘','宋','宋诗','song-poetry','','[]','聲色海中，隨波發現。',40,'全唐诗/poet.song.217000.json','["聲色海中，隨波發現。", "駕一葉之優曇，開普門之方便。", "洛伽山，慈悲岸，無十萬億國之遠。"]'),
('0cb433f7-f364-48cd-9c98-3e7bcc1212f3','思惟相贊','釋可湘','宋','宋诗','song-poetry','','[]','聲以眼聞，色以耳見。',32,'全唐诗/poet.song.217000.json','["聲以眼聞，色以耳見。", "萬法融通，六根互換。", "作是思惟時，十方佛皆現。"]'),
('5047f3d5-28ec-4cda-b1ae-afdfa893a85f','達磨贊  其一','釋可湘','宋','宋诗','song-poetry','','[]','萬里見梁王，無風波浪起。',24,'全唐诗/poet.song.217000.json','["萬里見梁王，無風波浪起。", "不得一莖蘆，幾乎沉殺你。"]'),
('9455239c-c514-4cf0-b2bd-87fbcebf4262','達磨贊  其二','釋可湘','宋','宋诗','song-poetry','','[]','一無聖，二不識，忠言逆耳投江北。',36,'全唐诗/poet.song.217000.json','["一無聖，二不識，忠言逆耳投江北。", "入水見長人，梁王方失色。", "千古萬古空相憶。"]'),
('8450064c-c500-45e2-8b40-8f1b76fdaaa1','布袋贊  其一','釋可湘','宋','宋诗','song-poetry','','[]','兜率宮，長汀市，逆行順行，誰弗識你。',34,'全唐诗/poet.song.217000.json','["兜率宮，長汀市，逆行順行，誰弗識你。", "有些滯貨不能藏，到處逢人亂拈起。"]'),
('895344c9-d8e4-4eef-8482-e9d1fe60dbd4','布袋贊  其二','釋可湘','宋','宋诗','song-poetry','','[]','未下生，先行脚。',34,'全唐诗/poet.song.217000.json','["未下生，先行脚。", "袋却乾坤，簸弄自若。", "一汀流水白漫漫，杖子何曾探得著。"]'),
('1214687b-7865-4a67-98a5-76e2470d6ca0','布袋贊  其三','釋可湘','宋','宋诗','song-poetry','','[]','破布袋，甚奇特。',34,'全唐诗/poet.song.217000.json','["破布袋，甚奇特。", "背負肩駝，不肯拋擲。", "只知入水去求人，爭奈脚跟浮逼逼。"]'),
('a5fc8653-6f5c-488c-b31f-20b9dbb0b00c','寒山贊  其一','釋可湘','宋','宋诗','song-poetry','','[]','一句子，少機杼。',28,'全唐诗/poet.song.217000.json','["一句子，少機杼。", "作是思惟時，吾心在何許。", "芭蕉葉上三更雨。"]'),
('9f0e6f68-5c3c-4dc0-b08f-af484b82dd12','寒山贊  其二','釋可湘','宋','宋诗','song-poetry','','[]','一見重岩壁立，挺然氣宇爭高。',28,'全唐诗/poet.song.217000.json','["一見重岩壁立，挺然氣宇爭高。", "默默思量覓句，可憐走却金毛。"]'),
('94e86d0c-afa3-40ae-a77f-793b8e9d6911','拾得贊  其一','釋可湘','宋','宋诗','song-poetry','','[]','生苕箒，提在手。',28,'全唐诗/poet.song.217000.json','["生苕箒，提在手。", "放下絕諸塵，轉掃復轉有。", "松門十里春如晝。"]'),
('12a5e740-af7a-45f1-83a6-6c147c7d9eb9','拾得贊  其二','釋可湘','宋','宋诗','song-poetry','','[]','磨墨趲人下筆，肚裡難禁技癢。',28,'全唐诗/poet.song.217000.json','["磨墨趲人下筆，肚裡難禁技癢。", "頻頻轉腦回頭，不知失了白象。"]'),
('38dc7691-db48-4370-b0ab-e9e7bffb1f12','朝陽穿破衲贊','釋可湘','宋','宋诗','song-poetry','','[]','寸鐵在手，橫穿豎穿。',20,'全唐诗/poet.song.217000.json','["寸鐵在手，橫穿豎穿。", "劄不入處，日輪昇天。"]'),
('3893d947-a79d-480d-a023-af3e171d4bc3','對月了殘經贊','釋可湘','宋','宋诗','song-poetry','','[]','黑荳未芽，朝數暮數。',20,'全唐诗/poet.song.217000.json','["黑荳未芽，朝數暮數。", "開得眼來，月圓當戶。"]'),
('fc06366d-959f-4605-82e9-848b8582ef25','贊真覺像化姜布','釋可湘','宋','宋诗','song-poetry','','[]','喫德山惡辣，耐同參逼拶。',39,'全唐诗/poet.song.217000.json','["喫德山惡辣，耐同參逼拶。", "蕩除露布葛藤，直得水底火發。", "阿剌剌，夫是之謂真覺菩薩。"]'),
('7d1a2dfb-5cfa-4b68-b69d-27c1b64ea491','真覺贊','釋可湘','宋','宋诗','song-poetry','','[]','德山全其顛，岩頭插其尾。',28,'全唐诗/poet.song.217000.json','["德山全其顛，岩頭插其尾。", "逼成一箇老於菟，兩眼眈眈沒牙齒。"]'),
('49af2774-e145-4c9c-b841-031a35d8f3da','文殊贊','釋可湘','宋','宋诗','song-poetry','','[]','七佛命之爲師，法王稱之爲子。',66,'全唐诗/poet.song.217000.json','["七佛命之爲師，法王稱之爲子。", "五時開演，始終輔贊世尊。", "三昧常行，談笑發揮龍女。", "曾現百千妙相，迦葉椎不能舉。", "自言我真文殊，其餘是甚伴侶。"]'),
('3601a879-c909-477a-8f4b-4a3a40bf9dd4','維摩贊','釋可湘','宋','宋诗','song-poetry','','[]','諳菩薩之法式，現居士之儀形，聞如來名。',66,'全唐诗/poet.song.217000.json','["諳菩薩之法式，現居士之儀形，聞如來名。", "跳下妙喜世界，憫衆生苦，示疾毗耶離城。", "萬化出於神變，一喙猶如建瓴。", "洎扣不二之法，何得默而無聲。"]'),
('4343baa0-e8b5-47ad-ad82-912cc394b944','馬郎婦贊','釋可湘','宋','宋诗','song-poetry','','[]','携魚籃，呈粉面，勾動馬家郎，眼花山影轉。',36,'全唐诗/poet.song.217000.json','["携魚籃，呈粉面，勾動馬家郎，眼花山影轉。", "七軸蓮經念到頭，乞與黄金骨一串。"]'),
('eccc1376-84be-4b7d-a314-72c5943d3117','靈照女贊','釋可湘','宋','宋诗','song-poetry','','[]','拋世業，蹈玄機。',36,'全唐诗/poet.song.217000.json','["拋世業，蹈玄機。", "阿爺無藉頼，女子更頑皮。", "情知未若貧而樂，特故沿街賣笊籬。"]'),
('543060f8-36a1-4077-9b35-c2b8c96b84a6','玄沙贊','釋可湘','宋','宋诗','song-poetry','','[]','換却頭顱脫謝家，南臺江上足生涯。',32,'全唐诗/poet.song.217000.json','["換却頭顱脫謝家，南臺江上足生涯。", "爛膿滴滴無人會，笑倒白蘋紅蓼花。"]'),
('64da018a-bcdf-4f3e-a5eb-3dbb3899faf6','船子贊','釋可湘','宋','宋诗','song-poetry','','[]','藥山之子石頭孫，饑過心荒浪裡奔。',32,'全唐诗/poet.song.217000.json','["藥山之子石頭孫，饑過心荒浪裡奔。", "得箇錦鱗如許大，看來當與道吾分。"]'),
('61fcff71-180e-405a-94d0-9812a21ad1b6','圓照和尚頂相奚翁請贊','釋可湘','宋','宋诗','song-poetry','','[]','一筆傳來，是何形狀。',46,'全唐诗/poet.song.217000.json','["一筆傳來，是何形狀。", "彷彿宸封老樹王，亭亭撐出凌霄上。", "無些子枝葉，有十分氣量，端的叢林之榜樣。"]'),
('81a18896-0bfe-442c-908c-2f12505ddf27','石溪和尚頂相柏堂請贊','釋可湘','宋','宋诗','song-poetry','','[]','咄者老和尚，可煞慈悲相。',66,'全唐诗/poet.song.217000.json','["咄者老和尚，可煞慈悲相。", "清影落人間，香名透天上。", "彈瑕纇於八方，迪精明於萬象。", "石骨崚嶒，溪光蕩漾。", "一筆傳來，衆工絕唱，凌霄峰頂堆青嶂。"]'),
('99cfbd8e-27ca-4801-a94d-caff3b6a1807','佛光法師真相致藏主請贊','釋可湘','宋','宋诗','song-poetry','','[]','僧中英，教中傑。',86,'全唐诗/poet.song.217000.json','["僧中英，教中傑。", "掛宋朝金襴，肆台衡木舌。", "如天河翻，如巖石裂，萎花風掃雨新奇，電影已收雷未絕。", "若是五逆兒郎，見徹明徹描邈得徹。", "信知這老和尚，已說今說當如是說。", "白雲推出團團月。"]'),
('3dcf9f24-f867-4c7d-8ff6-b0c61a465e6c','自贊  其一','釋可湘','宋','宋诗','song-poetry','','[]','我本無此相，硬畫箇模樣。',58,'全唐诗/poet.song.217000.json','["我本無此相，硬畫箇模樣。", "譬夫天台華頂峰，陰晴顯晦幾般狀。", "顧陸妙丹青，也只寫不像。", "寫得像，望他頂𩕳頭，何啻四萬八千丈。"]'),
('f4969707-7c0d-4106-83f7-b425830439a8','自贊  其二','釋可湘','宋','宋诗','song-poetry','','[]','謂是絕岸，眼裡著楔。',36,'全唐诗/poet.song.217000.json','["謂是絕岸，眼裡著楔。", "謂非絕岸，水中撈月。", "描不成，見不徹，分明頭戴雪山雪。"]'),
('dabe5199-41d1-4228-b4bc-578221eb259d','自贊  其三','釋可湘','宋','宋诗','song-poetry','','[]','衝開碧落，攧碎斷崖。',22,'全唐诗/poet.song.217000.json','["衝開碧落，攧碎斷崖。", "箇般摽致，其誰與偕。", "咦。"]'),
('bf150b15-7970-4f83-8bc8-cdae02fcf2a5','九巖常住請贊','釋可湘','宋','宋诗','song-poetry','','[]','單絲作線，獨掌打拍。',38,'全唐诗/poet.song.217000.json','["單絲作線，獨掌打拍。", "改樣畫貓兒，令一般體格。", "攪得蒙泉徹底渾，領邊那免千斤軛。"]'),
('3ecb7cf5-aa4c-4a68-bbe1-eeac2474f1f0','浄社莊長老請贊','釋可湘','宋','宋诗','song-poetry','','[]','似真非真，似假非假。',42,'全唐诗/poet.song.217000.json','["似真非真，似假非假。", "遠遠描邈將來，雙眉移在眼下。", "誰其爲之，西山浄社，切忌認馿而作馬。"]'),
('88344b93-fa71-4e90-8cdf-2d5930bf4552','杭州普圓庵請贊','釋可湘','宋','宋诗','song-poetry','','[]','花插不萌枝，衣披無縫襖。',88,'全唐诗/poet.song.217000.json','["花插不萌枝，衣披無縫襖。", "百萬人前輥綉毬，八十翁翁忘却老。", "挨開千聖門，乾坤只把一毛吞。", "拶透長安道，浄穢不禁苕箒掃。", "當年曾蹈須彌盧，而今覺見衆山小。", "布丹青，打之遶，貓兒洗面自道好。"]'),
('a9cce0c8-c4a2-483e-a5a1-257528888372','高峰妙長老頂相沈一居士請贊','釋可湘','宋','宋诗','song-poetry','','[]','去却一，拈得七。',57,'全唐诗/poet.song.217000.json','["去却一，拈得七。", "拶破疑團，咄咄咄。", "跳上天目山，據却獅子窟。", "返擲有餘態，江湖聲響出。", "且喜吾家有此郎，賽過天下大禪佛。"]'),
('15867ddb-8733-4c4c-8256-f6388d5948c9','石壁','釋可湘','宋','宋诗','song-poetry','','[]','喝不開兮鑿不開，春風幾度長莓苔。',32,'全唐诗/poet.song.218000.json','["喝不開兮鑿不開，春風幾度長莓苔。", "趙州拄杖雖粗糲，未必親曾靠著來。"]'),
('fbcffc7f-822c-4510-a481-60c0d1bf909a','海南','釋可湘','宋','宋诗','song-poetry','','[]','大地山河滾浪花，丙丁童子眼瞇𥊚。',32,'全唐诗/poet.song.218000.json','["大地山河滾浪花，丙丁童子眼瞇𥊚。", "回頭打得重溟透，赤脚波斯進象牙。"]'),
('616ab3fe-2bd4-405e-b17b-90f9bfcae892','一山','釋可湘','宋','宋诗','song-poetry','','[]','萬機俱罷口門緘，喚作如如落二三。',32,'全唐诗/poet.song.218000.json','["萬機俱罷口門緘，喚作如如落二三。", "拶得通身歸峭壁，善財不到別峰參。"]'),
('d6b25499-8134-41da-9921-6d826cf7c6dc','問庵','釋可湘','宋','宋诗','song-poetry','','[]','撞入柴門扣有麽，趙州用打不防家。',32,'全唐诗/poet.song.218000.json','["撞入柴門扣有麽，趙州用打不防家。", "依前只把拳頭豎，未必蒿湯當得茶。"]'),
('75034b6d-794f-4789-83ec-f339ffd0719b','雪巖','釋可湘','宋','宋诗','song-poetry','','[]','片片不於他處落，當陽突出嶮崖機。',32,'全唐诗/poet.song.218000.json','["片片不於他處落，當陽突出嶮崖機。", "此時築著聱禪客，卒急龐公未得歸。"]'),
('3ef70157-4d80-4167-91f0-56d86e0866d9','空谷','釋可湘','宋','宋诗','song-poetry','','[]','者畔纔呼那畔應，萬千樵子逐虛聲。',32,'全唐诗/poet.song.218000.json','["者畔纔呼那畔應，萬千樵子逐虛聲。", "探尋直是無蹤跡，只見青山青又青。"]'),
('fe1dfbea-084f-4773-8b50-0f7e57512c11','獨山','釋可湘','宋','宋诗','song-poetry','','[]','雨洗風磨孤迥迥，樹凋葉落峭巍巍。',32,'全唐诗/poet.song.218000.json','["雨洗風磨孤迥迥，樹凋葉落峭巍巍。", "惟茲一事無兼带，澤廣如何掩得伊。"]'),
('b433934f-7f31-4244-bb93-cd0801fe099c','枕肱軒','釋可湘','宋','宋诗','song-poetry','','[]','全身放倒恣憨癡，肘臂分明曲向誰。',32,'全唐诗/poet.song.218000.json','["全身放倒恣憨癡，肘臂分明曲向誰。", "更要夢中重說夢，我無木枕可來推。"]'),
('f25b52a9-436a-4c4e-be1f-8eb77bffe57c','漁浦接待','釋可湘','宋','宋诗','song-poetry','','[]','吳山那畔越山前，有飯充饑有榻眠。',32,'全唐诗/poet.song.218000.json','["吳山那畔越山前，有飯充饑有榻眠。", "到此縱能休歇去，帝鄉猶隔一潮船。"]'),
('362a0e9d-3740-4f8a-b9f2-0ba37418fe9e','謝送圓照和尚法衣','釋可湘','宋','宋诗','song-poetry','','[]','迦葉師兄守底衣，四邊將見逐雲飛。',32,'全唐诗/poet.song.218000.json','["迦葉師兄守底衣，四邊將見逐雲飛。", "雪峰知是吾家物，合掌低頭捧取歸。"]'),
('2175f712-1fff-4fad-9751-7a28342b38fd','送珙首座歸溫州','釋可湘','宋','宋诗','song-poetry','','[]','江月松風何處無，戒珠心印强名模。',32,'全唐诗/poet.song.218000.json','["江月松風何處無，戒珠心印强名模。", "煩君歸問老真覺，因甚闍梨氣不除。"]'),
('5f30d54a-0bf3-4635-95b5-61471c3526ee','示禪客','釋可湘','宋','宋诗','song-poetry','','[]','啟咨和尚意如何，一句相酬早事多。',32,'全唐诗/poet.song.218000.json','["啟咨和尚意如何，一句相酬早事多。", "問未絕聲猶一問，不知鷂子過新羅。"]'),
('ad0e8e0c-7da9-4260-a167-255c1a6b5cdf','浄庵居士求頌','釋可湘','宋','宋诗','song-poetry','','[]','不書心字涴窗門，玉混泥沙體自分。',32,'全唐诗/poet.song.218000.json','["不書心字涴窗門，玉混泥沙體自分。", "萬慮頓忘諸穢息，碧天無滓水無痕。"]'),
('d0618bea-53a7-4ffd-b644-fa91c0325514','送證侍者歸里','釋可湘','宋','宋诗','song-poetry','','[]','臨老三回住雪山，無絃琴子逐時彈。',32,'全唐诗/poet.song.218000.json','["臨老三回住雪山，無絃琴子逐時彈。", "夜來一曲最高韻，瀉作西江十八灘。"]'),
('aef35cda-c787-423b-a0aa-60141b45aa08','送小師心印遊方','釋可湘','宋','宋诗','song-poetry','','[]','自從落脚出娘胎，一印何曾打失來。',32,'全唐诗/poet.song.218000.json','["自從落脚出娘胎，一印何曾打失來。", "滿目春山春水綠，重重綿縫爲誰開。"]'),
('4a0b383e-6bb7-4321-9475-c0eeadb3515a','忙古參政造金塔盛舍利','釋可湘','宋','宋诗','song-poetry','','[]','撒下摩尼六七顆，湧高窣堵十三層。',32,'全唐诗/poet.song.218000.json','["撒下摩尼六七顆，湧高窣堵十三層。", "分明一點鈞心現，豈是黄金煉得成。"]'),
('ad89243a-212f-45dd-bfb5-6dc3f386ada2','寄神光末宗和尚','釋可湘','宋','宋诗','song-poetry','','[]','萬丈神光滌世昏，莫知誰信有乾坤。',32,'全唐诗/poet.song.218000.json','["萬丈神光滌世昏，莫知誰信有乾坤。", "三山眼底多尊宿，那箇來敲老觀門。"]'),
('7fad7c85-d899-4885-b3c1-85d319481a76','大維那求頌','釋可湘','宋','宋诗','song-poetry','','[]','仰山推枕玩嬌兒，等是機前展大悲。',32,'全唐诗/poet.song.218000.json','["仰山推枕玩嬌兒，等是機前展大悲。", "何必換頭呈素面，重堆脂粉畫蛾眉。"]'),
('6d408e2d-5d90-4880-903f-bc227c3319f0','寄秀峰烏石長老','釋可湘','宋','宋诗','song-poetry','','[]','三年魚鴈杳相聞，閩浙雖分意不分。',32,'全唐诗/poet.song.218000.json','["三年魚鴈杳相聞，閩浙雖分意不分。", "幾度臨風揩老眼，冷看烏石嶺頭雲。"]'),
('f918955b-00d0-4dc7-927f-01d0d28d9265','山居懷舊隠','釋斯植','宋','宋诗','song-poetry','','["\u8861\u5c71"]','靜地獨登臨，虛閑稱此心。',48,'全唐诗/poet.song.218000.json','["靜地獨登臨，虛閑稱此心。", "猿聲過木少，花影入池深。", "春殿依殘日，晴烟散遠林。", "因思南嶽寺，長起石床吟。"]'),
('12720b76-4d84-428b-a312-c238f7d51b61','金陵道中','釋斯植','宋','宋诗','song-poetry','','[]','望遠生愁思，淒涼處處同。',48,'全唐诗/poet.song.218000.json','["望遠生愁思，淒涼處處同。", "青山迷舊塚，芳草蔽閑宮。", "雨過城樓月，潮迴鼓角風。", "十年懷古恨，多在六朝中。"]'),
('1e41e04c-e4d5-4652-8d1c-12c8461e6b34','喜人歸幽棲','釋斯植','宋','宋诗','song-poetry','','[]','霄漢分携久，吟懷思欲迷。',48,'全唐诗/poet.song.218000.json','["霄漢分携久，吟懷思欲迷。", "相逢春草外，歸隠石房西。", "澗急禽聲少，松摇月影低。", "要知人靜夜，猶自怯猿啼。"]'),
('f7762e95-fbe2-4636-af60-65c18deab78b','水石山居','釋斯植','宋','宋诗','song-poetry','','["\u534e\u5c71"]','靜極青山裏，松花滿石床。',48,'全唐诗/poet.song.218000.json','["靜極青山裏，松花滿石床。", "春風思華嶽，夜雨夢瀟湘。", "人影歸林薄，猿聲出澗長。", "心如無別事，同此閉閑房。"]'),
('048716e0-56c3-4783-bedc-9763f5414fde','江村晚望','釋斯植','宋','宋诗','song-poetry','','[]','何處問歸程，滄茫入句清。',48,'全唐诗/poet.song.218000.json','["何處問歸程，滄茫入句清。", "雲生峰頂白，月近水邊明。", "芳草連平楚，晴樓出遠城。", "此身南北外，漁火是閑情。"]'),
('03d64f71-7f13-44eb-993d-a0a151af92fd','登雲漢閣','釋斯植','宋','宋诗','song-poetry','','[]','高閣勢凌虛，天涯入望微。',48,'全唐诗/poet.song.218000.json','["高閣勢凌虛，天涯入望微。", "雲藏山鳥影，春滿野人衣。", "積雨催花盡，寒樵背日歸。", "焚香端坐處，似覺世塵稀。"]'),
('c149f7f6-39ce-4a40-9f62-b28d00832673','子規','釋斯植','宋','宋诗','song-poetry','','[]','遊魂如可見，况復雨霏霏。',48,'全唐诗/poet.song.218000.json','["遊魂如可見，况復雨霏霏。", "隔水棲無地，經春叫不歸。", "影隨芳樹沒，聲入野花飛。", "那忍東風裏，淒涼上客衣。"]'),
('9c0dcd54-62ec-4a42-ad00-f29d7f6c660e','暮春感懷呈勿齋提舉','釋斯植','宋','宋诗','song-poetry','','[]','浮世事非真，吟多白髮新。',48,'全唐诗/poet.song.218000.json','["浮世事非真，吟多白髮新。", "身居京寺久，夢到石橋頻。", "日落煙生樹，花殘草自春。", "坐看今夜月，應與舊房鄰。"]'),
('c24cafc9-861f-4723-8315-a2a5d8af7a57','長洲夜泊','釋斯植','宋','宋诗','song-poetry','','[]','吳楚昔曾遊，凄凉滿客舟。',48,'全唐诗/poet.song.218000.json','["吳楚昔曾遊，凄凉滿客舟。", "因思千古事，空起十年愁。", "目盡他山少，江流遠地秋。", "今宵猶有月，不似庾公樓。"]'),
('41bf4adf-6cd7-4677-a791-9e147c247fc0','寄梅叟法師','釋斯植','宋','宋诗','song-poetry','','["\u8861\u5c71"]','一從飛錫後，迢遞各天涯。',48,'全唐诗/poet.song.218000.json','["一從飛錫後，迢遞各天涯。", "春事隨流水，行人問落花。", "住當南嶽寺，門對赤城霞。", "遥憶焚香處，松高月影斜。"]'),
('daaf2f3d-188a-4d7a-9b02-fcd15f6f68af','金陵懷古','釋斯植','宋','宋诗','song-poetry','','[]','天津橋上望，如在玉門關。',48,'全唐诗/poet.song.218000.json','["天津橋上望，如在玉門關。", "月過東西浦，江分遠近山。", "凄凉三尺墓，興廢六朝間。", "千古登臨地，寒潮自往還。"]'),
('32945dda-e5ef-4d65-ad89-1dd60c591322','送覺上人','釋斯植','宋','宋诗','song-poetry','','[]','送君千里去，又見落花飛。',48,'全唐诗/poet.song.218000.json','["送君千里去，又見落花飛。", "水國今宵別，天涯隔歲歸。", "岸多春樹密，灘小夕陽微。", "後夜扁舟月，應逢宿鳥稀。"]'),
('30fc3432-1d43-4b1e-b545-cc93838d7d55','訪故人','釋斯植','宋','宋诗','song-poetry','','[]','石榻相期久，閑尋到野房。',48,'全唐诗/poet.song.218000.json','["石榻相期久，閑尋到野房。", "春歸芳草暗，雲入楚山長。", "人影分孤驛，鷄聲落曙桑。", "凄凉千古事，回首兩茫茫。"]'),
('5a2c8bfb-a1ea-42c3-8469-77a043ec154b','寄深居馮發管','釋斯植','宋','宋诗','song-poetry','','[]','相懷千里外，空望極遥天。',48,'全唐诗/poet.song.218000.json','["相懷千里外，空望極遥天。", "處世唯今日，看花憶去年。", "春風生島樹，夜月滿漁船。", "此後閑尋處，應須借榻眠。"]'),
('a8d54267-5bba-47ca-95c4-faefdab45325','寄靜佳朱明府','釋斯植','宋','宋诗','song-poetry','','[]','翰苑留名久，城邊半掩扉。',48,'全唐诗/poet.song.218000.json','["翰苑留名久，城邊半掩扉。", "聲隨淮水遠，吟入楚天微。", "吏靜看山坐，鄉遥撫劍歸。", "清虛無別事，嘉政在璇璣。"]'),
('50943169-41e0-4c44-b296-54edfe12b416','旅中寄故人','釋斯植','宋','宋诗','song-poetry','','[]','世路長安裏，三年別釣磯。',48,'全唐诗/poet.song.218000.json','["世路長安裏，三年別釣磯。", "只因吟事僻，寧免識人非。", "性拙趨時少，家貧過客稀。", "春風歸去日，同采故山薇。"]'),
('d64c1e0a-9c2d-42b5-a4bb-06342d845120','西園即事','釋斯植','宋','宋诗','song-poetry','','[]','一徑落花紅，回廊復舊蹤。',48,'全唐诗/poet.song.218000.json','["一徑落花紅，回廊復舊蹤。", "千峰遥隔水，萬木遠涵空。", "沙鳥晴雲外，寒帆夕照中。", "幾宵曾宿此，江月夜相通。"]'),
('0694b73a-c39c-4840-9c65-34891943db7f','旅中偶成','釋斯植','宋','宋诗','song-poetry','','[]','風吹客袂寒，飄泊在長安。',48,'全唐诗/poet.song.218000.json','["風吹客袂寒，飄泊在長安。", "對雨春題盡，看雲夜坐殘。", "遠山平楚水，蒼漢接吳灘。", "遥憶天台寺，相携去不難。"]'),
('8d53ab57-145a-4ac5-abf7-5255779d2ff3','懷芳林處士','釋斯植','宋','宋诗','song-poetry','','[]','相思不可見，江路正迢迢。',48,'全唐诗/poet.song.218000.json','["相思不可見，江路正迢迢。", "煙樹同吟遠，關河入望遥。", "晝長花影轉，風定篆香銷。", "遥憶君居處，鍾聲隔暮潮。"]'),
('474c22a3-adb8-4598-9ac5-42aee16b052d','送靈耀之姑蘇','釋斯植','宋','宋诗','song-poetry','','[]','一身唯在道，清苦獨知君。',48,'全唐诗/poet.song.218000.json','["一身唯在道，清苦獨知君。", "世路終成別，山光不共分。", "晚天寒欲雨，春樹夜生雲。", "此去他鄉寺，猿聲各自聞。"]'),
('ddbcbe26-b966-453b-935f-287458173f36','元夕','釋斯植','宋','宋诗','song-poetry','','[]','滿眼春光萬物華，小橋楊柳近人家。',32,'全唐诗/poet.song.218000.json','["滿眼春光萬物華，小橋楊柳近人家。", "誰將上下樓臺月，化作金蓮一夜花。"]'),
('9d0b2476-7a44-4a87-8447-abacf1107338','偶成','釋斯植','宋','宋诗','song-poetry','','[]','東風玉勒馬蹄輕，多少遊人上鳳城。',32,'全唐诗/poet.song.218000.json','["東風玉勒馬蹄輕，多少遊人上鳳城。", "燕子不來春寂寞，海棠花發近清明。"]'),
('452ea92c-5fa3-4a70-bd15-3ae5e678b677','邊上','釋斯植','宋','宋诗','song-poetry','','[]','邊風斜日下長關，春到年年草自生。',32,'全唐诗/poet.song.218000.json','["邊風斜日下長關，春到年年草自生。", "萬里戰場兵甲靜，近來應少北人行。"]'),
('fc75d715-d747-4721-9700-3a1991eaad39','山家','釋斯植','宋','宋诗','song-poetry','','[]','一溪流水遶煙霞，路入青松第幾家。',32,'全唐诗/poet.song.218000.json','["一溪流水遶煙霞，路入青松第幾家。", "胡蝶傍人飛不去，隔牆開盡碧桃花。"]'),
('02f5e999-e71b-40c6-bf28-be8b053074ba','晚來','釋斯植','宋','宋诗','song-poetry','','[]','晚來無語立東風，一片閑情在碧空。',32,'全唐诗/poet.song.218000.json','["晚來無語立東風，一片閑情在碧空。", "人老杜鵑渾不管，柳花飛盡夕陽紅。"]'),
('73f98cf2-3ccc-4a6e-9e23-47317f43c059','西湖晚望','釋斯植','宋','宋诗','song-poetry','','["\u897f\u6e56"]','久雨初晴睡正長，春蛙鳴遍舊池塘。',32,'全唐诗/poet.song.218000.json','["久雨初晴睡正長，春蛙鳴遍舊池塘。", "小亭寂寞斜陽裏，一陣東風過木香。"]'),
('e3f38651-2449-47de-b8a7-e2d7517d24e4','寒食','釋斯植','宋','宋诗','song-poetry','','[]','江南江北紙錢飛，處處人家拜塚時。',32,'全唐诗/poet.song.218000.json','["江南江北紙錢飛，處處人家拜塚時。", "杜宇不禁寒食雨，五更啼血上花枝。"]'),
('fe6d7f10-555c-45f0-a5df-c8d5e20fefcc','堤上','釋斯植','宋','宋诗','song-poetry','','[]','楊柳垂絲拂畫船，杏花零落斷橋邊。',32,'全唐诗/poet.song.218000.json','["楊柳垂絲拂畫船，杏花零落斷橋邊。", "半山烟雨東風惡，更向西亭聽杜鵑。"]'),
('645f3fe6-0a7f-44e2-bf4e-ffad045c774e','林間','釋斯植','宋','宋诗','song-poetry','','[]','猿鶴忘機不計年，芭蕉晴綠半平簷。',32,'全唐诗/poet.song.218000.json','["猿鶴忘機不計年，芭蕉晴綠半平簷。", "青山似與身相入，盡日無人自下簾。"]'),
('cbbe0bd3-4977-41e0-b8b1-9b9d018155a3','客懷','釋斯植','宋','宋诗','song-poetry','','[]','杜宇聲殘客興頻，柳花飛絮滿江濱。',32,'全唐诗/poet.song.218000.json','["杜宇聲殘客興頻，柳花飛絮滿江濱。", "可憐波底蛾眉月，猶照他鄉夢裏人。"]'),
('447a127d-dbc2-4535-b3eb-bbaedeba52ae','夏夕雨中','釋斯植','宋','宋诗','song-poetry','','[]','滿林鍾磬夜偏長，古鼎閑焚柏子香。',32,'全唐诗/poet.song.218000.json','["滿林鍾磬夜偏長，古鼎閑焚柏子香。", "石榻未成芳草夢，西風吹雨過池塘。"]'),
('eec3d9f6-a2af-464c-890f-634c7cbce726','過吳','釋斯植','宋','宋诗','song-poetry','','[]','柳橋槐市暫經過，飄泊汀洲得意多。',32,'全唐诗/poet.song.218000.json','["柳橋槐市暫經過，飄泊汀洲得意多。", "夜月已忘吳主恨，畫船空有采蓮歌。"]'),
('53b99031-5b98-411a-90fe-b394ec7ee640','清華夜坐','釋斯植','宋','宋诗','song-poetry','','[]','開盡黄花滿短籬，靜聽隣屋夜敲碁。',32,'全唐诗/poet.song.218000.json','["開盡黄花滿短籬，靜聽隣屋夜敲碁。", "清華池上三更月，僧在松邊未有詩。"]'),
('5b5f64fd-e333-42fa-8a21-594325377a76','山居','釋斯植','宋','宋诗','song-poetry','','[]','晚策登臨日欲斜，小溪流水是生涯。',32,'全唐诗/poet.song.218000.json','["晚策登臨日欲斜，小溪流水是生涯。", "道人睡起鶴飛去，閑盡青松一樹花。"]'),
('a2747f0d-cc67-46b1-af71-d5ae09e4b9fc','春夜','釋斯植','宋','宋诗','song-poetry','','[]','玉樓臺畔柳生煙，况是春風杜宇天。',32,'全唐诗/poet.song.218000.json','["玉樓臺畔柳生煙，况是春風杜宇天。", "一片月光凉似水，半扶花影上鞦韆。"]'),
('9b739d16-cd8d-41ec-a0b5-5e2991cf3acc','古樂府  其一','釋斯植','宋','宋诗','song-poetry','','[]','携君石上琴，彈我窗前月。',24,'全唐诗/poet.song.218000.json','["携君石上琴，彈我窗前月。", "月缺又還圓，誰能免離別。"]'),
('fcb961dc-3d09-4b00-b25c-73c55a977739','古樂府  其二','釋斯植','宋','宋诗','song-poetry','','[]','青山叫子規，行人淚如雨。',24,'全唐诗/poet.song.218000.json','["青山叫子規，行人淚如雨。", "子規不肯歸，行人不能去。"]'),
('81970c71-bd4c-48b7-8b7f-213b64cc7ac6','古樂府  其三','釋斯植','宋','宋诗','song-poetry','','[]','欲買采菱船，野水無人識。',24,'全唐诗/poet.song.218000.json','["欲買采菱船，野水無人識。", "野水去不迴，迢迢暮山碧。"]'),
('3bd0b373-8e0f-437d-9534-4ccf651596eb','古樂府  其四','釋斯植','宋','宋诗','song-poetry','','[]','早作西州行，暮作西州宿。',24,'全唐诗/poet.song.218000.json','["早作西州行，暮作西州宿。", "楊柳忽風生，年年芳草綠。"]'),
('70516283-d45d-4c0e-9c80-a97a8bed3d66','古樂府  其五','釋斯植','宋','宋诗','song-poetry','','[]','蘭死根亦香，人死不知處。',24,'全唐诗/poet.song.218000.json','["蘭死根亦香，人死不知處。", "人死不堪悲，蘭香化爲霧。"]'),
('a79696df-987b-4974-8b2c-4c37002a271b','古樂府  其六','釋斯植','宋','宋诗','song-poetry','','[]','山鷄啼一聲，深院日當午。',24,'全唐诗/poet.song.218000.json','["山鷄啼一聲，深院日當午。", "世無同心人，入此薜蘿裏。"]'),
('5d88cfc9-257d-4056-aa35-be08d562a33e','古樂府  其七','釋斯植','宋','宋诗','song-poetry','','[]','晚步入松陰，歛霽人影絕。',24,'全唐诗/poet.song.218000.json','["晚步入松陰，歛霽人影絕。", "唯聞太古音，聽之心膽裂。"]'),
('c746c8d1-7b4a-4df0-b88a-f2c45d84a95f','古樂府  其八','釋斯植','宋','宋诗','song-poetry','','[]','一入經戰場，白馬不足數。',24,'全唐诗/poet.song.218000.json','["一入經戰場，白馬不足數。", "白馬不敢嘶，春風在場圃。"]'),
('e366130c-3670-4769-98b5-585ba965acfc','古樂府  其九','釋斯植','宋','宋诗','song-poetry','','[]','青雲千里心，白鷺一點雪。',24,'全唐诗/poet.song.218000.json','["青雲千里心，白鷺一點雪。", "誰將玉笛吹，吹下關山月。"]'),
('8b10b6b6-fd69-4111-bc79-cd090e9b95a6','寄衣曲  其一','釋斯植','宋','宋诗','song-poetry','','[]','自君之出矣，壁上琵琶君記取。',46,'全唐诗/poet.song.218000.json','["自君之出矣，壁上琵琶君記取。", "日日望君君不歸，自君去後徒相憶。", "欲剪征衣寄贈君，天涯望斷無消息。"]'),
('33444aa1-5df1-402f-a4ed-4c064f20091a','寄衣曲  其二','釋斯植','宋','宋诗','song-poetry','','[]','自君之出矣，欲寄征衣淚如雨。',94,'全唐诗/poet.song.218000.json','["自君之出矣，欲寄征衣淚如雨。", "征衣未寄心已悲，一寸相思隔千里。", "湘江水是巫山雲，巫山雲是湘江水。", "湘江兩岸芳草深，湘江日夜多行人。", "行人去去天之涯，門對落花三兩家。", "家家有酒謳且歌，醉來月下彈琵琶。"]'),
('e6110579-f9e8-438d-98d4-0b74ae229458','韜光庵','釋斯植','宋','宋诗','song-poetry','','[]','石澗長松行十里，杖蔾從此得遲留。',64,'全唐诗/poet.song.218000.json','["石澗長松行十里，杖蔾從此得遲留。", "青霄望去山河遠，白水看來日月流。", "老樹葉殘霜鬼哭，斷崖雲冷洞猿愁。", "韜光名在身何在，今古茫茫幾白頭。"]'),
('1773f155-12e8-43e5-9bd7-bb4f423c536c','旅懷','釋斯植','宋','宋诗','song-poetry','','[]','十年不倚謝公樓，滿眼凄凉上客舟。',64,'全唐诗/poet.song.218000.json','["十年不倚謝公樓，滿眼凄凉上客舟。", "往事盡隨流水去，青山長憶故人遊。", "海門風起天將暮，渡口雲生樹欲秋。", "絡緯自啼花自落，更堪回首是他州。"]'),
('52036ca0-d9fb-4459-8f85-924600bb24e7','賦老將','釋斯植','宋','宋诗','song-poetry','','[]','獵獵征旗促曉鞍，幾迴臨陣練兵官。',64,'全唐诗/poet.song.218000.json','["獵獵征旗促曉鞍，幾迴臨陣練兵官。", "黄沙滿塞黄雲暗，白馬嘶風白日寒。", "漢語肯隨蠻地改，戰袍猶带血腥乾。", "如今韜略渾無用，瘦骨蕭條甲胄寬。"]'),
('3299dee5-9904-4d8f-986b-f3bf12e169fd','過桃源','釋斯植','宋','宋诗','song-poetry','','[]','□□□□□□□，生涯心在鳳凰臺。',64,'全唐诗/poet.song.218000.json','["□□□□□□□，生涯心在鳳凰臺。", "桃花曉落水流去，山鳥晚啼風送來。", "古樹影摇霜月滿，冷猿聲裂碧雲開。", "長關春有愁人分，驛馬相逢去不回。"]'),
('1903af63-61ed-4eb5-9468-b37d6ecabc4e','過故城','釋斯植','宋','宋诗','song-poetry','','[]','故城深巷長蒼苔，一度經過一度哀。',64,'全唐诗/poet.song.218000.json','["故城深巷長蒼苔，一度經過一度哀。", "尚有樓臺攙雨出，豈無花柳向春開。", "十年心事今宵夢，千里家書昨日迴。", "莫上灞陵橋上望，楚天雲盡蜀波來。"]'),
('9f815fa3-8c59-4e85-8297-6623b125f404','挽周彥良','釋斯植','宋','宋诗','song-poetry','','[]','白首功成未十年，寡妻相弔泣江干。',64,'全唐诗/poet.song.218000.json','["白首功成未十年，寡妻相弔泣江干。", "詩名似水聲還遠，世事如雲夢已殘。", "楊柳滿堤人去後，海棠深巷雨初乾。", "東風忽起青山淚，雖有君書不忍看。"]'),
('ece69060-3f92-4df4-9668-fb5f36504818','思歸感興','釋斯植','宋','宋诗','song-poetry','','[]','久客空江上，閑吟對石門。',48,'全唐诗/poet.song.218000.json','["久客空江上，閑吟對石門。", "青山非遠近，流水自朝昏。", "夜月添鄉夢，春風入燒痕。", "翻思南郭路，迢遞隔烟村。"]'),
('228e8476-6d7d-433e-889d-0b5e33e93f07','蘭谷','釋斯植','宋','宋诗','song-poetry','','[]','空谷寄深雲，靈根自不群。',48,'全唐诗/poet.song.218000.json','["空谷寄深雲，靈根自不群。", "地閑平草長，香遠隔溪聞。", "靜與騷人佩，清同楚客分。", "唯應千載後，餘韻在湘濆。"]'),
('bbec691b-597f-4c00-ac41-5fadb6a41d25','多福寺','釋斯植','宋','宋诗','song-poetry','','[]','野鹿自成群，山中少隠君。',48,'全唐诗/poet.song.218000.json','["野鹿自成群，山中少隠君。", "鐘聲兩寺合，人語一溪分。", "泉響松間雨，苔生石上紋。", "多年僧住此，半榻鎖閑雲。"]'),
('e9d99d80-1dce-4735-9f3a-2d46c59473a7','挽芸居祕校','釋斯植','宋','宋诗','song-poetry','','[]','世上名猶在，閑情豈足悲。',48,'全唐诗/poet.song.218000.json','["世上名猶在，閑情豈足悲。", "自憐吟日少，唯恨識君遲。", "蘭閣人亡後，寒林月上時。", "十年青史夢，只有老天知。"]'),
('3c8f6f14-37d3-4247-9901-5596fa93447f','與子入山來','釋斯植','宋','宋诗','song-poetry','','[]','與子入山來，永夜不得睡。',60,'全唐诗/poet.song.218000.json','["與子入山來，永夜不得睡。", "但聞松子聲，敲落梧桐樹。", "月到窗愈明，秋風瀉流水。", "古奏三兩絃，知音不知處。", "唯有白面猿，閑中自來去。"]'),
('2d7baf47-f144-4daf-8440-5b4a5ffd1ef2','春晚','釋斯植','宋','宋诗','song-poetry','','[]','滿地落花流水，傷心芳草青時。',28,'全唐诗/poet.song.218000.json','["滿地落花流水，傷心芳草青時。", "江上數聲杜宇，更堪一笛橫吹。"]'),
('48882175-6a81-4f69-a65c-eb902e4fd20b','寄勿齋提舉','釋斯植','宋','宋诗','song-poetry','','[]','滿林煙樹已紛紛，溪上猿聲不共聞。',32,'全唐诗/poet.song.218000.json','["滿林煙樹已紛紛，溪上猿聲不共聞。", "唯有青山半庭月，夜深應與故人分。"]'),
('7f8900df-b58f-4155-a549-d6f796414995','門柳','釋斯植','宋','宋诗','song-poetry','','[]','看盡門前柳，愁多白髮新。',24,'全唐诗/poet.song.218000.json','["看盡門前柳，愁多白髮新。", "灞橋風雨夜，離別是何人。"]'),
('38f0f82a-636f-4a5a-8a05-d67d14ff5d66','遠山','釋斯植','宋','宋诗','song-poetry','','[]','萬里色蒼然，春烟夕照邊。',24,'全唐诗/poet.song.218000.json','["萬里色蒼然，春烟夕照邊。", "舊過南岳寺，曾向雨中看。"]'),
('ea1edab6-1653-4d3e-adf0-5d85df8c5026','石城秋夜','釋斯植','宋','宋诗','song-poetry','','[]','漠漠青山水自流，西風烟樹幾經秋。',32,'全唐诗/poet.song.218000.json','["漠漠青山水自流，西風烟樹幾經秋。", "舊時歌舞人遊地，月滿江城十二樓。"]'),
('04d87621-2402-4251-902c-f6b9419cbc9e','春日同友人遊湖上','釋斯植','宋','宋诗','song-poetry','','[]','十里湖邊路，垂楊映馬蹄。',48,'全唐诗/poet.song.218000.json','["十里湖邊路，垂楊映馬蹄。", "水光平野闊，山影繞樓低。", "夜雨生青草，春風濕紫泥。", "興來無限意，同此片時題。"]'),
('01d7a1dc-f896-4b87-a97a-10e50ac63405','巖棲分韻得深字','釋斯植','宋','宋诗','song-poetry','','[]','寂寞空齋裏，閑情起暮吟。',48,'全唐诗/poet.song.218000.json','["寂寞空齋裏，閑情起暮吟。", "路長沙鳥盡，人在翠微深。", "遠樹煙中沒，寒花竹外尋。", "自嫌名與利，誰識此生心。"]'),
('914daff2-e4e8-4658-94e8-365cdb4d3b77','邊城客思','釋斯植','宋','宋诗','song-poetry','','[]','客裏厭芳塵，凄凉又問津。',48,'全唐诗/poet.song.218000.json','["客裏厭芳塵，凄凉又問津。", "向南人去遠，歸北馬嘶頻。", "野水荒城暮，孤舟海樹春。", "故鄉非久別，已覺鬢毛新。"]'),
('b00b7683-1e9e-4924-904f-e5e9f966bc36','吳中即事','釋斯植','宋','宋诗','song-poetry','','[]','世事交情淺，傷心獨倚欄。',48,'全唐诗/poet.song.218000.json','["世事交情淺，傷心獨倚欄。", "海雲經雨重，秦樹入秋殘。", "潮落吳天遠，風生夢澤寒。", "英雄千古地，回首是長安。"]'),
('6b695ea2-bb06-4f13-b622-3e2633182ef2','過越','釋斯植','宋','宋诗','song-poetry','','[]','渺渺天涯路，扁舟去不窮。',48,'全唐诗/poet.song.218000.json','["渺渺天涯路，扁舟去不窮。", "水花隨岸盡，山影落江空。", "往事千年夢，漁歌一夜風。", "詩成唯有月，清致與誰同。"]'),
('efb2c7e4-9c37-4a75-97f4-7fb2e2b06ecf','天竺山居','釋斯植','宋','宋诗','song-poetry','','[]','對雨吟方穩，西風忽晚晴。',48,'全唐诗/poet.song.218000.json','["對雨吟方穩，西風忽晚晴。", "野花沿澗白，秋意入簾清。", "淺水藏魚影，重林隔磬聲。", "是非塵外事，誰可繼高名。"]'),
('1e20ecec-8bcc-4a25-a97d-886715c73ef5','故宮懷古','釋斯植','宋','宋诗','song-poetry','','[]','暮天雲盡遠山空，夜夜西風入漢宮。',32,'全唐诗/poet.song.218000.json','["暮天雲盡遠山空，夜夜西風入漢宮。", "鐵笛一聲千古恨，月明人在女牆中。"]'),
('d80d10cf-a5bb-4239-aa12-ff38221d7ff5','落葉詞','釋斯植','宋','宋诗','song-poetry','','[]','片片飛來總是秋，更於何處復添愁。',32,'全唐诗/poet.song.218000.json','["片片飛來總是秋，更於何處復添愁。", "自憐枝上無收管，却带慇懃出御溝。"]'),
('db46d427-b866-47fb-8d06-24be550afd11','暮春雨中感懷','釋斯植','宋','宋诗','song-poetry','','[]','回首郡城東，春殘碧樹中。',48,'全唐诗/poet.song.218000.json','["回首郡城東，春殘碧樹中。", "落花千點恨，疏雨一簾風。", "白雪侵新鬢，歸心逐斷鴻。", "茫茫事如此，何必怨途窮。"]'),
('e411a62d-e089-426f-a10c-f46f9fc6a922','江寺晚眺','釋斯植','宋','宋诗','song-poetry','','[]','盡日無多事，閑行一徑陰。',48,'全唐诗/poet.song.218000.json','["盡日無多事，閑行一徑陰。", "人歸秋寺晚，月滿夜堂深。", "海闊頻生霧，城荒遠見林。", "青山與華髮，空愧百年心。"]'),
('15ee255d-366d-4518-9d02-3fcf3d2001f1','照影','釋斯植','宋','宋诗','song-poetry','','[]','性與兒童異，飄蓬二十年。',24,'全唐诗/poet.song.218000.json','["性與兒童異，飄蓬二十年。", "照來池上影，恰似未生前。"]'),
('05afae5d-1a1b-4385-ba55-08cdb9639c48','世事','釋斯植','宋','宋诗','song-poetry','','[]','世事皆浮雲，人間幾朝暮。',24,'全唐诗/poet.song.218000.json','["世事皆浮雲，人間幾朝暮。", "不知溪上山，猶有桃源路。"]'),
('da844607-5f71-40e7-8703-7863a67b45f0','莫恨','釋斯植','宋','宋诗','song-poetry','','[]','寂寞雲深地，山空葉落時。',24,'全唐诗/poet.song.218000.json','["寂寞雲深地，山空葉落時。", "自憐爲隠僻，莫恨月來遲。"]'),
('7aae2cf6-b74b-41a2-a6f5-dd5cbf5b87be','昨夜','釋斯植','宋','宋诗','song-poetry','','[]','草堂雲去後，人境兩茫茫。',24,'全唐诗/poet.song.218000.json','["草堂雲去後，人境兩茫茫。", "忽見青松老，翻疑昨夜霜。"]'),
('c45c12dd-ebe0-4a1d-ae56-1cc42d1182c8','長安曉發','釋斯植','宋','宋诗','song-poetry','','[]','雨過樓臺已禁煙，野風吹絮滿長安。',32,'全唐诗/poet.song.218000.json','["雨過樓臺已禁煙，野風吹絮滿長安。", "夜來寂寞沙汀下，楚水吳雲一樣看。"]'),
('7d8502df-759e-4793-bf8d-74ac64d49f4f','聞子規','釋斯植','宋','宋诗','song-poetry','','[]','十年已起故鄉情，客裏凄凉不耐聽。',32,'全唐诗/poet.song.218000.json','["十年已起故鄉情，客裏凄凉不耐聽。", "啼到蜀天空有恨，水流依舊月還明。"]'),
('598da6c8-dd8f-4c5c-9ba2-4d6cc905e859','自謂','釋斯植','宋','宋诗','song-poetry','','[]','自謂清貧苦，那知即是安。',48,'全唐诗/poet.song.218000.json','["自謂清貧苦，那知即是安。", "路從平去好，事到口開難。", "松老心長在，花紅色易殘。", "浮生既如許，渾作夢中看。"]'),
('016e7f37-7009-4684-8fc8-031207a3f0ed','宿雲山房','釋斯植','宋','宋诗','song-poetry','','[]','縹渺沉虛碧，清池見宿雲。',48,'全唐诗/poet.song.218000.json','["縹渺沉虛碧，清池見宿雲。", "松聲臨石斷，山影與泉分。", "芳草經年夢，幽禽隔徑聞。", "倚欄吟未盡，紅日又將曛。"]'),
('4a28663a-4b26-460e-a5e5-dcc645976b50','偶成柬續芸','釋斯植','宋','宋诗','song-poetry','','[]','相看又一春，花亂馬前塵。',48,'全唐诗/poet.song.218000.json','["相看又一春，花亂馬前塵。", "湖海他鄉路，煙霞幾處人。", "草連閑地遠，鳥入暮山頻。", "多少淒涼事，那堪白髮新。"]'),
('c5562cf5-7553-41e6-85d1-d33302a9d67a','鐵笛倦長吹','釋斯植','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','鐵笛倦長吹，虛空劍寒倚。',112,'全唐诗/poet.song.218000.json','["鐵笛倦長吹，虛空劍寒倚。", "俯仰陰晴天，泰山不可視。", "蕩槳歸白雲，回首滄波裏。", "人生無百年，世事已如此。", "既與榮辱同，興廢乃相似。", "春風從何來，紛紛競桃李。", "至士本無心，誤爲詩所使。", "縱步夕照間，養性在芳芷。", "天涯一夜杜鵑愁，萬里行人度湘水。"]'),
('3abe41f8-f99c-40b1-ac6f-ad143be02cdf','對梅分韻得堂字','釋斯植','宋','宋诗','song-poetry','','[]','霜風吹短髮，值此天氣凉。',84,'全唐诗/poet.song.218000.json','["霜風吹短髮，值此天氣凉。", "行行陰壑中，萬樹皆含芳。", "相對發微詠，安用持華觴。", "嗟彼咸平人，清風生我腸。", "花非不及時，衆鳥何迴翔。", "歸看兩壁間，畫者猶蒼蒼。", "抱此幽露姿，願登君子堂。"]'),
('770608e7-8ac7-4adb-ada6-66365340e671','老去','釋斯植','宋','宋诗','song-poetry','','[]','老去厭芳菲，思歸未得歸。',24,'全唐诗/poet.song.218000.json','["老去厭芳菲，思歸未得歸。", "夕陽溪上樹，花作去年飛。"]'),
('9e68a186-4d93-451f-99b9-93070d6b1a83','苕溪舟次','釋斯植','宋','宋诗','song-poetry','','[]','扁舟烟重冷漁蓑，兩岸人家浸小河。',32,'全唐诗/poet.song.218000.json','["扁舟烟重冷漁蓑，兩岸人家浸小河。", "芳草自生春自老，落花隨雨晚風多。"]'),
('ebe6ff5f-127a-4761-93db-b601c8434c11','送故人之江東','釋斯植','宋','宋诗','song-poetry','','[]','鳳城花氣浥旌旗，又見春風上馬時。',32,'全唐诗/poet.song.218000.json','["鳳城花氣浥旌旗，又見春風上馬時。", "不是灞橋難話別，垂楊空折去年枝。"]'),
('dea8f1fd-7904-4184-a597-6506133c06b1','丙辰元夜','釋斯植','宋','宋诗','song-poetry','','[]','淡河斜浸月光浮，看盡青山更倚樓。',32,'全唐诗/poet.song.218000.json','["淡河斜浸月光浮，看盡青山更倚樓。", "殘燭怕寒元夕夜，小欄花影伴人愁。"]'),
('7bdcfd0a-d0d6-43f0-abf9-c08544277e43','清明','釋斯植','宋','宋诗','song-poetry','','[]','堤上尋春步較遲，馬嘶芳草燕差池。',32,'全唐诗/poet.song.218000.json','["堤上尋春步較遲，馬嘶芳草燕差池。", "南樓烟雨清明日，正是佳人墮淚時。"]'),
('ee3af31d-4d9a-4f9e-806f-abb176b5720c','江淮傷感','釋斯植','宋','宋诗','song-poetry','','[]','水流花片濕輕紅，多少英雄逐曉風。',32,'全唐诗/poet.song.218000.json','["水流花片濕輕紅，多少英雄逐曉風。", "三百餘年歌管地，數聲歡怨不相同。"]'),
('bffd5178-92c2-4ba7-baf7-a17ccfca480f','送故人之天台','釋斯植','宋','宋诗','song-poetry','','[]','新綠又成陰，歸期直到今。',48,'全唐诗/poet.song.218000.json','["新綠又成陰，歸期直到今。", "人行芳草遠，犬吠落花深。", "野店春寒雨，江城橘樹林。", "無情名利事，休繫一生心。"]'),
('fd85526c-6c05-48d7-8a7d-1dc8e881f9ca','送敏上人歸永嘉','釋斯植','宋','宋诗','song-poetry','','[]','風光苦變遷，客裏對殘年。',48,'全唐诗/poet.song.218000.json','["風光苦變遷，客裏對殘年。", "別我此時路，問鄉何處船。", "斷雲連雨雪，落日遠人煙。", "又向龍湫畔，開扉近瀑泉。"]'),
('dd52de18-f9e2-4994-bb5c-428ea66425b9','上竺寺','釋斯植','宋','宋诗','song-poetry','','[]','古寺寒橋路，鍾聲靜忽聞。',48,'全唐诗/poet.song.218000.json','["古寺寒橋路，鍾聲靜忽聞。", "數峰平處合，一水衆谿分。", "老樹煙蘿雨，殘燈石塔雲。", "閑心寄幽寂，似覺遠塵紛。"]'),
('cc98fcf4-e756-481b-bbd3-521278e2b7ff','山中即事','釋斯植','宋','宋诗','song-poetry','','[]','千峰當此境，誰可共登臨。',48,'全唐诗/poet.song.218000.json','["千峰當此境，誰可共登臨。", "月過秋池靜，雲歸古木深。", "懶觀前去事，已悟未來心。", "更欲尋詩伴，相携向石林。"]'),
('2f85ac53-0f1c-4250-ae55-a5f5236b9abd','對梅寄人','釋斯植','宋','宋诗','song-poetry','','[]','欲問江梅信，吟筇带晚霞。',48,'全唐诗/poet.song.218000.json','["欲問江梅信，吟筇带晚霞。", "笑看今日樹，開遍幾年花。", "疏影生來瘦，寒枝折處斜。", "要教人寄遠，何地是君家。"]'),
('45936f2b-6575-4616-9346-2c057e973f71','春日','釋斯植','宋','宋诗','song-poetry','','[]','人生厭別離，老去更何爲。',48,'全唐诗/poet.song.218000.json','["人生厭別離，老去更何爲。", "獨對清明雨，閑吟社日詩。", "野蜂成蜜早，海燕入簾遲。", "未盡尋春興，應須愧後期。"]'),
('cda51c45-0954-4a3b-bc1a-7baaec4fa844','夜坐有感','釋斯植','宋','宋诗','song-poetry','','[]','角送重城月，微風入夜凉。',48,'全唐诗/poet.song.218000.json','["角送重城月，微風入夜凉。", "身輕長是寄，吟苦未應忘。", "坐久燈成燼，愁多鬢欲霜。", "百年還老去，誰可繼餘芳。"]'),
('4b7e7a62-afe5-44fd-864a-9e98f8d77d91','送人之吳','釋斯植','宋','宋诗','song-poetry','','[]','無心學隠淪，此去向吳津。',48,'全唐诗/poet.song.218000.json','["無心學隠淪，此去向吳津。", "千古是非地，一燈烟雨村。", "烽塵連楚戍，榆柳隔淮春。", "別後新吟句，何人可共論。"]'),
('e602c487-e0b8-472a-8097-67fd4fa38e52','題天竺巖栖山房','釋斯植','宋','宋诗','song-poetry','','[]','一室寄雲隈，凭欄日幾迴。',48,'全唐诗/poet.song.218000.json','["一室寄雲隈，凭欄日幾迴。", "無風山自雨，有主燕還來。", "野徑通樵遠，巖花向晚開。", "舊時題數壁，今已半蒼苔。"]'),
('c7217102-3712-4937-8c94-08ac6ff44cc4','丁巳燈夕前六日觀抱拙寄敏齋韻因事有感走筆以賦','釋斯植','宋','宋诗','song-poetry','','[]','萍跡倚春風，春光苦未濃。',48,'全唐诗/poet.song.218000.json','["萍跡倚春風，春光苦未濃。", "人間連日事，塵外一宵鐘。", "遠雁書難寄，殘碑字已封。", "幽人住城市，清夢兩三重。"]'),
('784a6960-ab61-4b42-b0ce-2419c90c0c9f','送隠士游京淮','釋斯植','宋','宋诗','song-poetry','','[]','送君湖柳下，未別已關情。',48,'全唐诗/poet.song.218000.json','["送君湖柳下，未別已關情。", "古塞去程遠，寒江入夢清。", "野雲低水樹，山雨閉春城。", "到處逢知己，虛傳隠姓名。"]'),
('460e6366-6f09-4248-ba54-5cb0b4fd172e','雨夜','釋斯植','宋','宋诗','song-poetry','','[]','雨雪寒窗下，孤燈夜不眠。',48,'全唐诗/poet.song.218000.json','["雨雪寒窗下，孤燈夜不眠。", "衰殘如舊日，榮達是何年。", "已覺觀書妄，方參入世緣。", "存心在仁理，何必後人傳。"]'),
('20e41668-9459-424d-9ee7-f8690e488326','晚春偶題呈正甫先生','釋斯植','宋','宋诗','song-poetry','','[]','老來春去怯凭欄，今古興亡一笑間。',32,'全唐诗/poet.song.218000.json','["老來春去怯凭欄，今古興亡一笑間。", "滿徑落紅人不到，杜鵑啼雨入空山。"]'),
('8e10153c-c0fd-43b6-81cb-508478da3f6d','山居遣興','釋斯植','宋','宋诗','song-poetry','','[]','山寺閉脩竹，偏宜靜者居。',48,'全唐诗/poet.song.218000.json','["山寺閉脩竹，偏宜靜者居。", "觀空心已悟，集理事常虛。", "日月供吟筆，乾坤入草廬。", "何如釣臺叟，得計在樵漁。"]'),
('17aee653-f2f4-4e93-af8b-d491f9f59e45','登吳山','釋斯植','宋','宋诗','song-poetry','','[]','嵯峨宮樹靄晴空，吳越迢迢一望中。',64,'全唐诗/poet.song.218000.json','["嵯峨宮樹靄晴空，吳越迢迢一望中。", "幾處笙歌人遠近，萬重花柳路西東。", "風生簾幕春雲碧，水遶樓臺海日紅。", "沙鳥自飛還自宿，百年無計與誰同。"]'),
('7425e833-abb7-4be1-822e-9b95f6a94380','題彭澤後人吟樓','釋斯植','宋','宋诗','song-poetry','','[]','結屋在雲端，悠然趣自安。',48,'全唐诗/poet.song.218000.json','["結屋在雲端，悠然趣自安。", "江山隨望遠，星月近人寒。", "劍氣當空正，詩情對酒寬。", "往來庭畔叟，只作晉時看。"]'),
('ff807f36-e7b7-4a6d-9aaa-2845f01e35f9','挽白雲趙宗丞','釋斯植','宋','宋诗','song-poetry','','[]','天上樓成日，人間獨喪君。',48,'全唐诗/poet.song.218000.json','["天上樓成日，人間獨喪君。", "料知生死事，還與去來分。", "夜月江村路，春風嶺樹雲。", "交餘多感槩，那忍見遺文。"]'),
('1809fcc8-4a71-41f9-a530-21658aed6807','遣懷','釋斯植','宋','宋诗','song-poetry','','[]','愁極鬢成絲，滄江夢未歸。',48,'全唐诗/poet.song.218000.json','["愁極鬢成絲，滄江夢未歸。", "鳥啼山雨急，春盡故人稀。", "曉潤侵吟壁，寒雲繞竹扉。", "向來詩滿束，應是與心違。"]'),
('b4f8e2c5-e8a3-40ca-a8f6-4a71e2d74401','秋思','釋斯植','宋','宋诗','song-poetry','','[]','雨過山城日又西，西風一陣木犀開。',32,'全唐诗/poet.song.218000.json','["雨過山城日又西，西風一陣木犀開。", "莫將心事憑秋雁，恐带邊愁入夢來。"]'),
('8cbe6b9b-30c3-42f5-84ab-bee28d6f76c0','客路和胡元魯出入韻','釋斯植','宋','宋诗','song-poetry','','[]','十載天涯客，浮雲不定身。',48,'全唐诗/poet.song.218000.json','["十載天涯客，浮雲不定身。", "烟波春雨渡，燈火夜漁村。", "世事空爲累，人心未覺仁。", "何時留片石，歸老古松根。"]'),
('0fbbc3de-e97d-430f-9a83-407f5eff7898','淮邊柳','釋斯植','宋','宋诗','song-poetry','','[]','寂寞淮邊柳，春來自舞腰。',24,'全唐诗/poet.song.218000.json','["寂寞淮邊柳，春來自舞腰。", "恨生爭戰地，不得近官橋。"]'),
('f7fd23ab-e701-411a-9096-3ff37d0448d2','雪鴣','釋斯植','宋','宋诗','song-poetry','','[]','風吹蘆葦鳴，殘雪滿橋板。',24,'全唐诗/poet.song.218000.json','["風吹蘆葦鳴，殘雪滿橋板。", "不見棹回人，愁立沙汀晚。"]'),
('d0a1cb50-cbcd-420e-ba68-5ae9e14f5cd2','鳴鳩','釋斯植','宋','宋诗','song-poetry','','[]','何處芳草多，相呼向深塢。',24,'全唐诗/poet.song.218000.json','["何處芳草多，相呼向深塢。", "竹外立寒枝，山南又春雨。"]'),
('90d9563d-1889-4261-b0b5-1f8f91c0a6cc','道宮','釋斯植','宋','宋诗','song-poetry','','[]','千年興廢地，仙訣字猶存。',48,'全唐诗/poet.song.218000.json','["千年興廢地，仙訣字猶存。", "露重雲生樹，壇空月到門。", "心清無外事，靜極是真源。", "此境非凡世，何人與續言。"]'),
('dbe6c9ee-ade2-4eb9-b533-1c770d19d582','塞北','釋斯植','宋','宋诗','song-poetry','','[]','兵戰何時息，邊塵染客旌。',48,'全唐诗/poet.song.218000.json','["兵戰何時息，邊塵染客旌。", "亂鴉啼又歇，荒草死還生。", "島雨連秋曙，江風入雁聲。", "近淮民自悅，應是宦情清。"]'),
('6d2199ae-b83d-4f25-937f-3563903a5467','東齋書事','釋斯植','宋','宋诗','song-poetry','','[]','客裏吟情懶，天涯望欲昏。',48,'全唐诗/poet.song.218000.json','["客裏吟情懶，天涯望欲昏。", "斷雲流澗水，殘月照衡門。", "猿嘯它山樹，砧聲何處村。", "浮名身外事，於此不須論。"]'),
('b306347d-251f-43b1-81a3-3768a30bb6b7','傚樊川體','釋斯植','宋','宋诗','song-poetry','','[]','吟邊繞架書千卷，壁上梅花水一瓢。',64,'全唐诗/poet.song.218000.json','["吟邊繞架書千卷，壁上梅花水一瓢。", "世事盡從忙裏過，年華空向靜中消。", "山雲宿雨籠殘日，汀草浮香滿小橋。", "對此不須惆悵去，野人今已悟吹簫。"]'),
('75fda20e-9576-4fb8-8d9a-261a2e9810c9','觀化','釋斯植','宋','宋诗','song-poetry','','[]','閑觀造化餘，靜極悅自性。',24,'全唐诗/poet.song.218000.json','["閑觀造化餘，靜極悅自性。", "胡蝶忽飛來，吾心已無競。"]'),
('4a8688e3-a9fc-4f49-a3f5-572fb46a72fb','和路字','釋斯植','宋','宋诗','song-poetry','','[]','青山何人家，芳草滿樵路。',24,'全唐诗/poet.song.218000.json','["青山何人家，芳草滿樵路。", "猿鶴未歸來，殘月照煙樹。"]'),
('dc875ddd-34cd-488b-a1c2-a66b5ba39e9c','宿雲軒','釋斯植','宋','宋诗','song-poetry','','[]','千峰雲未還，數樹芭蕉綠。',24,'全唐诗/poet.song.218000.json','["千峰雲未還，數樹芭蕉綠。", "風雨暗黄昏，何人共幽獨。"]'),
('68a09e3f-7109-4c66-8d34-0d71af34686f','從軍行','釋斯植','宋','宋诗','song-poetry','','[]','茫茫塞月籠寒霧，萬里征人不知數。',96,'全唐诗/poet.song.218000.json','["茫茫塞月籠寒霧，萬里征人不知數。", "年少難消壯志多，精銳連營肅貔虎。", "從軍何日見軍迴，但見日日長淮雨。", "烽烟散漫滿路岐，邊聲颯颯秋風起。", "天涯荒草馬成群，放去彎弓亂飛舞。", "夜深更聽胡女歌，古來白骨多於土。"]'),
('58b9c8bb-8dc9-445a-8232-e98b224f3cba','湖上晚望','釋斯植','宋','宋诗','song-poetry','','[]','繞堤楊柳暗漁舟，二月風光淡似秋。',32,'全唐诗/poet.song.218000.json','["繞堤楊柳暗漁舟，二月風光淡似秋。", "幾度笙歌人散後，夕陽依舊滿紅樓。"]'),
('52b5b901-65c1-4090-9fa0-61d643314ed0','送人謁所知','釋斯植','宋','宋诗','song-poetry','','[]','西風忽別離，滿袖百篇詩。',48,'全唐诗/poet.song.218000.json','["西風忽別離，滿袖百篇詩。", "取己尚如此，問人應可知。", "山寒城角遠，地闊海帆遲。", "料想回車日，相看是歲期。"]'),
('f29449be-2cfa-44a9-8395-80b4f8430ca2','山中寓意','釋斯植','宋','宋诗','song-poetry','','[]','白髮今如許，自吟還自愁。',48,'全唐诗/poet.song.218000.json','["白髮今如許，自吟還自愁。", "滿山晴葉雨，四壁老蛩秋。", "看水知心靜，觀雲覺事浮。", "數年衰感意，揮淚不能收。"]'),
('6260eb77-65a7-4cf1-8ce5-f300dfefc678','丙辰季夏避暑山中長松脩竹恍若蓬萊異人之居走筆索句以紀其事','釋斯植','宋','宋诗','song-poetry','','[]','六月厭煩襟，縱步情未足。',72,'全唐诗/poet.song.218000.json','["六月厭煩襟，縱步情未足。", "愛此石徑長，緲緲清溪曲。", "古道何人居，門閑對脩竹。", "好鳥發新聲，靜極成幽獨。", "山風吹晚凉，山影摇紅綠。", "翹首興未闌，青猿睡初熟。"]'),
('65974ab5-cd35-4252-b952-9d71b918828e','送人遊吳','釋斯植','宋','宋诗','song-poetry','','[]','闔門煙靄外，地闊水城高。',48,'全唐诗/poet.song.218000.json','["闔門煙靄外，地闊水城高。", "蜃氣蒸吟鬢，霜風入縕袍。", "數程秋岸雨，一飯野船蒿。", "若問當時事，人誇有二豪。"]'),
('11e3d324-4ac8-4216-9797-3acbecdcc76c','丙辰季夏雨中','釋斯植','宋','宋诗','song-poetry','','[]','天涯身尚寄，何日向東州。',48,'全唐诗/poet.song.218000.json','["天涯身尚寄，何日向東州。", "一夜霜欺鬢，連朝雨送愁。", "夢多吟作祟，閑極懶爲讎。", "若問浮生事，無心即是謀。"]'),
('571d563f-9e31-46a4-b339-a74968abf173','寄彭澤後人','釋斯植','宋','宋诗','song-poetry','','[]','不爲折腰事，田園足野情。',48,'全唐诗/poet.song.218000.json','["不爲折腰事，田園足野情。", "筆粘春霧重，詩带晚唐清。", "柳巷閑漁艇，山扉對水城。", "論心暫來往，無愧遠公名。"]'),
('64a78259-c6d0-4da3-a8db-f455614b1a5b','寄靜佳朱明府','釋斯植','宋','宋诗','song-poetry','','[]','傷心獨立舊池臺，日日西風送雨來。',32,'全唐诗/poet.song.218000.json','["傷心獨立舊池臺，日日西風送雨來。", "別後思君無限事，一封書發兩番開。"]'),
('66d828f1-2400-4c30-a90c-d4c768434076','葉','釋斯植','宋','宋诗','song-poetry','','[]','天涯誰與寄相思，殘片疏疏尚戀枝。',32,'全唐诗/poet.song.218000.json','["天涯誰與寄相思，殘片疏疏尚戀枝。", "一自西風寒勒後，凋零能得幾多時。"]'),
('25965f96-d56e-443c-a000-a38cfc4053b3','柳','釋斯植','宋','宋诗','song-poetry','','[]','汴水隋堤總寂寥，春風吹恨未曾消。',32,'全唐诗/poet.song.218000.json','["汴水隋堤總寂寥，春風吹恨未曾消。", "長條本自無拘束，也向人前學舞腰。"]'),
('c0e523f8-8bcf-4bce-a68c-d23c736b51e2','春陰書事呈正甫先生  其一','釋斯植','宋','宋诗','song-poetry','','[]','二月花陰已覺遲，黄昏簾幕燕歸時。',32,'全唐诗/poet.song.218000.json','["二月花陰已覺遲，黄昏簾幕燕歸時。", "小欄獨立無人處，春雨春寒總欠詩。"]'),
('9bdeb452-6493-4223-a53a-de08f977409c','春陰書事呈正甫先生  其二','釋斯植','宋','宋诗','song-poetry','','[]','江湖寥落轉飄蓬，歸夢年年逐去鴻。',32,'全唐诗/poet.song.218000.json','["江湖寥落轉飄蓬，歸夢年年逐去鴻。", "吟鬢一番春又半，杏花無語立東風。"]'),
('e2ed915c-03ba-48a9-b863-fc51d7e4744d','金陵道上','釋斯植','宋','宋诗','song-poetry','','[]','一望江山去不迴，斷碑荒草舊宮臺。',32,'全唐诗/poet.song.218000.json','["一望江山去不迴，斷碑荒草舊宮臺。", "六朝陳跡皆如夢，夜夜寒潮送月來。"]'),
('749f67b9-ac80-47fb-917d-e7d8f5391f13','山行','釋斯植','宋','宋诗','song-poetry','','[]','巖邊結屋與樵鄰，流水桃花幾度春。',32,'全唐诗/poet.song.218000.json','["巖邊結屋與樵鄰，流水桃花幾度春。", "行到碧雲無盡處，深山怪木老如人。"]'),
('072c9357-8d8c-4eac-b68a-e35b3e14836e','詠古','釋斯植','宋','宋诗','song-poetry','','[]','欲尋仙闕覓仙丹，仙在瀛洲縹緲間。',32,'全唐诗/poet.song.218000.json','["欲尋仙闕覓仙丹，仙在瀛洲縹緲間。", "一自祖龍東去後，更無人到會稽山。"]'),
('0689f60b-d404-4ec4-aebe-afc28f4aef6a','送張十二秀才至維揚','釋斯植','宋','宋诗','song-poetry','','[]','江山迢遞水東流，芳草無情管別愁。',32,'全唐诗/poet.song.218000.json','["江山迢遞水東流，芳草無情管別愁。", "若聽春風商女曲，天涯人在古揚州。"]'),
('c5f600b2-b7c3-427d-b1eb-9a46a5d88731','偶成','釋斯植','宋','宋诗','song-poetry','','[]','漁歌聽盡欲狂吟，一徑人家柳影深。',32,'全唐诗/poet.song.218000.json','["漁歌聽盡欲狂吟，一徑人家柳影深。", "天意似嫌花信早，東風吹雨又成陰。"]'),
('6e71ef50-61a3-4a5c-aa34-1d0483326dc6','雪中寄巖泉','釋斯植','宋','宋诗','song-poetry','','[]','吟罷新詩祇自看，曉風吹恨上闌干。',32,'全唐诗/poet.song.218000.json','["吟罷新詩祇自看，曉風吹恨上闌干。", "夜來雪滿前山路，誰對梅花說歲寒。"]'),
('5c0dbd51-eb6b-4811-bd7a-673d0f02ebe2','春日湖上五首  其一','釋斯植','宋','宋诗','song-poetry','','[]','繞堤莎草綠纖纖，老裏吟情覺未厭。',32,'全唐诗/poet.song.218000.json','["繞堤莎草綠纖纖，老裏吟情覺未厭。", "應是踏青天氣近，柳條多插野人簷。"]'),
('10843c58-a3ef-4562-8811-f24c97eef0d3','春日湖上五首  其二','釋斯植','宋','宋诗','song-poetry','','[]','曉山漠漠盡烟霏，四面樓臺白鳥稀。',32,'全唐诗/poet.song.218000.json','["曉山漠漠盡烟霏，四面樓臺白鳥稀。", "芳草年年湖上路，柳花風送釣船歸。"]'),
('ac8247ac-4c80-4698-b258-0fde8231a661','春日湖上五首  其三','釋斯植','宋','宋诗','song-poetry','','[]','樂天遺跡暫徘徊，路入深雲滿徑苔。',32,'全唐诗/poet.song.218000.json','["樂天遺跡暫徘徊，路入深雲滿徑苔。", "花影上欄吟未穩，東風空倩蝶飛來。"]'),
('c3582a07-fd4d-4da1-a302-08abfadd47f3','春日湖上五首  其四','釋斯植','宋','宋诗','song-poetry','','[]','雨餘蛙吹歇池塘，庭院人閑日正長。',32,'全唐诗/poet.song.218000.json','["雨餘蛙吹歇池塘，庭院人閑日正長。", "獨倚畫欄看不盡，海棠無處是山光。"]'),
('2510f805-b51a-4522-b2b3-a936e69ab4ff','春日湖上五首  其五','釋斯植','宋','宋诗','song-poetry','','[]','今朝纔得是閑身，來往琳宮不厭頻。',32,'全唐诗/poet.song.218000.json','["今朝纔得是閑身，來往琳宮不厭頻。", "燕葺舊巢春又暮，風光一半屬遊人。"]'),
('33254014-7e55-4053-a1e0-7dd0e393f92a','與趙五話別','釋斯植','宋','宋诗','song-poetry','','[]','送君無計路漫漫，玉笛聲悲遠戍間。',32,'全唐诗/poet.song.218000.json','["送君無計路漫漫，玉笛聲悲遠戍間。", "自是行人多有恨，離情吹不到陽關。"]'),
('d2ee037b-8441-49a8-a1b0-3d1188dfde57','首夏','釋斯植','宋','宋诗','song-poetry','','[]','新篁摇綠雨初晴，彩簟風生一枕清。',32,'全唐诗/poet.song.218000.json','["新篁摇綠雨初晴，彩簟風生一枕清。", "昨日小亭幽夢覺，隔簾花影弄鶑聲。"]'),
('7762200d-d752-41a8-ad7f-2434e92c29cd','湘竹詞','釋斯植','宋','宋诗','song-poetry','','[]','湘魂何自怨，千古尚名存。',24,'全唐诗/poet.song.218000.json','["湘魂何自怨，千古尚名存。", "不種庭邊竹，那知有淚痕。"]'),
('029508e3-1a2b-4cd3-84de-22906adc10b7','池上曲','釋斯植','宋','宋诗','song-poetry','','[]','曉雨生池荷，圓珠漾新綠。',24,'全唐诗/poet.song.218000.json','["曉雨生池荷，圓珠漾新綠。", "入手不成珠，空歌彩蓮曲。"]'),
('2f1ee191-8036-478e-8307-9b5f3c8f8254','和子履雍家園詩','釋斯植','宋','宋诗','song-poetry','','[]','長橋南走羣山間，中有雍子之名園。',128,'全唐诗/poet.song.218000.json','["長橋南走羣山間，中有雍子之名園。", "蒼雲蔽天竹色凈，暖香撲地花氣繁。", "飛泉來從遠嶺背，林下曲折寒波翻。", "珍禽不可見毛質，數聲清絕如哀彈。", "我來據石弄琴瑟，惟恐日暮登歸軒。", "塵紛剝落耳目異，只疑夢入仙家村。", "知君襟尚我同好，作詩閎放莫可攀。", "高篇絕景兩不及，久之想像空冥煩。"]'),
('94e4f093-d609-4ff4-bd4f-5f0fc43ae74d','送李容甫歸北都','釋斯植','宋','宋诗','song-poetry','','[]','先生讀書不下堂，堂上有客語浪浪。',204,'全唐诗/poet.song.218000.json','["先生讀書不下堂，堂上有客語浪浪。", "弟子出觀如堵牆，怪君眉彩生光芒。", "北都晁夫子，一別久相望。", "君來道信問，使我開肺腸。", "三日不改服，猶覺芝蘭香。", "平生寡投分，一笑且云樂。", "慇懃發黄卷，鈍吻慳應酢。", "大杵撞啞鐘，已厭音響惡。", "更慚河伯觀，未易窮海若。", "索寞歲華晚，颼颼黄葉秋。", "歸心劇流水，忽忽不可留。", "固知此鱣鯨，肯託尋常溝。", "直須見老聃，可化南榮儔。", "海州歲有沖天鵠，卵如萍實光琢玉，蜀鷄眇然何敢伏。", "羽成不須求日浴，一舉將驚萬人目。"]'),
('9f45d3c8-4edb-4156-b7cb-1eb91dba27c7','句','釋斯植','宋','宋诗','song-poetry','','[]','小桃自與春風惡，花不隨人獨下樓。',16,'全唐诗/poet.song.218000.json','["小桃自與春風惡，花不隨人獨下樓。"]'),
('3a9292df-e35c-4827-b8ed-4bab057a6fd8','偈頌七十六首  其一','釋子益','宋','宋诗','song-poetry','','[]','我此一門，初無關鍵。',27,'全唐诗/poet.song.218000.json','["我此一門，初無關鍵。", "半合半開，東扇西扇。", "千聞不如一見。"]'),
('dac1cd78-7021-4a71-9030-5f5d976a31a1','偈頌七十六首  其二','釋子益','宋','宋诗','song-poetry','','[]','不行喝，不行棒。',18,'全唐诗/poet.song.218000.json','["不行喝，不行棒。", "負命衲僧，不釣自上。"]'),
('cd2fe700-1e47-4b62-950d-f8e0066709af','偈頌七十六首  其三','釋子益','宋','宋诗','song-poetry','','[]','一字不著畫，八字沒兩丿。',24,'全唐诗/poet.song.218000.json','["一字不著畫，八字沒兩丿。", "文彩甚分明，何待重饒舌。"]'),
('f159981b-02cb-4e89-86bf-4c22cead3e95','偈頌七十六首  其四','釋子益','宋','宋诗','song-poetry','','[]','行不到處行一步，說不到處道一句。',34,'全唐诗/poet.song.218000.json','["行不到處行一步，說不到處道一句。", "徑山諸公見義勇爲，靈隠師伯拔劍相助。"]'),
('55272154-a33b-4849-9fbb-ca55f8bc99e1','偈頌七十六首  其五','釋子益','宋','宋诗','song-poetry','','[]','黄梅夜半，雞足峰前。',20,'全唐诗/poet.song.218000.json','["黄梅夜半，雞足峰前。", "承虛接響，互相熱瞞。"]'),
('a972130c-4000-4519-a0be-c0d57d46bd09','偈頌七十六首  其六','釋子益','宋','宋诗','song-poetry','','[]','最初句，向上機。',34,'全唐诗/poet.song.218000.json','["最初句，向上機。", "瞿曇不會，達磨不知。", "知不知，雨餘千嶂碧，春水一溪肥。"]'),
('0ac14a9f-76bb-4e89-a972-df3fcea4c8bd','偈頌七十六首  其七','釋子益','宋','宋诗','song-poetry','','[]','一槌便就，顢顢頇頇。',36,'全唐诗/poet.song.218000.json','["一槌便就，顢顢頇頇。", "不假一槌，無端無端。", "忙裏工夫閑處覓，閙中消息靜中觀。"]'),
('6faf0435-9b68-45d8-b114-836cfcc3b536','偈頌七十六首  其八','釋子益','宋','宋诗','song-poetry','','[]','天上月圓，人間月半。',32,'全唐诗/poet.song.218000.json','["天上月圓，人間月半。", "明眼衲僧，見似不見。", "盞子撲落地，楪子成七片。"]'),
('d4580718-ce61-4271-acfe-3b622ae90634','偈頌七十六首  其九','釋子益','宋','宋诗','song-poetry','','[]','向上一路，千聖不傳。',47,'全唐诗/poet.song.218000.json','["向上一路，千聖不傳。", "未曾擬議，早隔大千。", "雪峰輥毬，禾山打皷，仰山插鍬，地藏種田。", "短綆那汲深泉。"]'),
('fafe408c-a418-4368-b697-8306adeb085f','偈頌七十六首  其一○','釋子益','宋','宋诗','song-poetry','','[]','去年今日逢冬節，撲頭撲面迎霜雪。',40,'全唐诗/poet.song.218000.json','["去年今日逢冬節，撲頭撲面迎霜雪。", "今年冬節又來臨，屋角梅花弄曉晴。", "笑它魯史謾書雲。"]'),
('7f7886ef-eba1-48ea-8c97-9986aa4efdfc','偈頌七十六首  其一一','釋子益','宋','宋诗','song-poetry','','[]','與麽寒，何處避。',36,'全唐诗/poet.song.218000.json','["與麽寒，何處避。", "冰稜上，深雪裏。", "有來由，沒巴鼻。", "丹霞燒木佛，院主眉鬚墮。"]'),
('74480af5-954f-4717-b7e0-8d5ba9a67585','偈頌七十六首  其一二','釋子益','宋','宋诗','song-poetry','','[]','信手拈來，萬選萬中。',32,'全唐诗/poet.song.218000.json','["信手拈來，萬選萬中。", "輕若鴻毛輕，重似丘山重。", "雖是死蛇，也要活弄。"]'),
('c285f637-75cc-4227-992a-a5c78c45fd48','偈頌七十六首  其一三','釋子益','宋','宋诗','song-poetry','','[]','四九三十六，夜眠如露宿。',42,'全唐诗/poet.song.218000.json','["四九三十六，夜眠如露宿。", "銀海眩生花，玉樓寒起粟。", "翻笑二祖立雪謾齊腰，活埋一片無瑕玉。"]'),
('4e167080-67cd-4f04-abfe-93c2d03877b2','偈頌七十六首  其一四','釋子益','宋','宋诗','song-poetry','','[]','昨日雨，今日晴。',20,'全唐诗/poet.song.218000.json','["昨日雨，今日晴。", "桃花開口笑，無處覓靈雲。"]'),
('fa8a3f33-4f9c-4eec-9084-33ecef54d434','偈頌七十六首  其一五','釋子益','宋','宋诗','song-poetry','','[]','二千年前，通身是垢。',36,'全唐诗/poet.song.218000.json','["二千年前，通身是垢。", "二千年後，滿面埃塵。", "直饒九曲黄河水，洗到馿年也不清。"]'),
('0afdc86e-455e-4892-bff0-2683a4a16f9a','偈頌七十六首  其一六','釋子益','宋','宋诗','song-poetry','','[]','潑天聲價陳睦州，咬人火急瞌睡虎。',73,'全唐诗/poet.song.218000.json','["潑天聲價陳睦州，咬人火急瞌睡虎。", "行不到處行一步，道不到處道一句。", "德山臨濟眼𥉌𥉍，棒喝交馳無所措。", "興化忍俊不禁，隨例赫日光中飛白雨，照顧濕却袈裟角。"]'),
('217d838b-5008-4a71-8c55-524bdb814a51','偈頌七十六首  其一七','釋子益','宋','宋诗','song-poetry','','[]','世事悠悠，不如山丘。',30,'全唐诗/poet.song.218000.json','["世事悠悠，不如山丘。", "卧藤蘿下，塊石枕頭。", "許由洗耳，巢父飲牛。"]'),
('1de469c1-94af-4333-bea8-a6b5f74ca8f6','偈頌七十六首  其一八','釋子益','宋','宋诗','song-poetry','','[]','名不得，狀不得。',48,'全唐诗/poet.song.218000.json','["名不得，狀不得。", "脫胎換骨方，起死回生訣。", "信得及底，不消一服，諸病頓除，脫體安樂。", "何必善財重採藥。"]'),
('9ff08cd5-335a-4e96-80f7-b59d89bbd7dd','偈頌七十六首  其一九','釋子益','宋','宋诗','song-poetry','','[]','一日復一日，眨眼過半夏。',60,'全唐诗/poet.song.218000.json','["一日復一日，眨眼過半夏。", "興化老無知，鉢盂安柄欛。", "引得四海參玄人，三三兩兩聚頭商量這個話。", "阿呵呵，六月賣松風，人間恐無價。"]'),
('8092065e-dac4-4f73-b79a-e0b61bd8d688','偈頌七十六首  其二○','釋子益','宋','宋诗','song-poetry','','[]','欲明此道，須遇其人。',20,'全唐诗/poet.song.218000.json','["欲明此道，須遇其人。", "其人既遇，十倍收成。"]'),
('c37de271-96e8-44b9-89b2-da80bd607935','偈頌七十六首  其二一','釋子益','宋','宋诗','song-poetry','','[]','秋未霜，菊正芳。',46,'全唐诗/poet.song.218000.json','["秋未霜，菊正芳。", "千朶萬朶香吐蕊，三枝兩枝金樣黄。", "不作世諦流布，亦非佛法商量。", "九月九日是重陽。"]'),
('ce1cc1ad-f119-46d1-9eb5-7f44e29cb239','偈頌七十六首  其二二','釋子益','宋','宋诗','song-poetry','','[]','怪得深夜寒，破曉清霜重。',52,'全唐诗/poet.song.218000.json','["怪得深夜寒，破曉清霜重。", "雙澗水無聲，千峰雲欲凍。", "這裏冷湫湫，那邊熱鬨鬨。", "不知那個得便宜，慚愧楊岐老凍膿。"]'),
('9e07c593-cbe3-41c1-8cea-2ca6753afe69','偈頌七十六首  其二三','釋子益','宋','宋诗','song-poetry','','[]','格外提持，斗轉星移。',44,'全唐诗/poet.song.218000.json','["格外提持，斗轉星移。", "智藏不會，海兄不知。", "尀耐睦州擔板漢，教壞臨濟小廝兒。", "此意明明說向誰。"]'),
('08b4e520-50c7-47ff-af8e-dfc244f7460d','偈頌七十六首  其二四','釋子益','宋','宋诗','song-poetry','','[]','見見之時，羯諦羯諦。',42,'全唐诗/poet.song.218000.json','["見見之時，羯諦羯諦。", "見非是見，波羅羯諦。", "見猶離見，波羅僧羯諦。", "見莫能及，菩提薩婆訶。"]'),
('d8b39d94-d806-429e-9536-f3c307568607','偈頌七十六首  其二五','釋子益','宋','宋诗','song-poetry','','[]','天寒地冷，晝短夜長。',28,'全唐诗/poet.song.218000.json','["天寒地冷，晝短夜長。", "死灰撥盡，沒可商量。", "昨夜三更月到窗。"]'),
('f2cc9bff-212e-4d85-949c-b15e0e1e4ed0','偈頌七十六首  其二六','釋子益','宋','宋诗','song-poetry','','[]','作無所作，爲無所爲。',35,'全唐诗/poet.song.218000.json','["作無所作，爲無所爲。", "灰頭土面，带水拖泥。", "恁麽要見興化，快須照顧兩莖眉。"]'),
('52d780ae-1438-4245-9a92-f4a961a07bd6','偈頌七十六首  其二七','釋子益','宋','宋诗','song-poetry','','[]','正法輪，輕撥轉。',26,'全唐诗/poet.song.218000.json','["正法輪，輕撥轉。", "日出中天，雲開嶽面，如優曇花時一現。"]'),
('cf731cac-45c2-49ee-9038-df7ebd5c9047','偈頌七十六首  其二八','釋子益','宋','宋诗','song-poetry','','[]','玄沙不出嶺，拄杖生根休用剪。',28,'全唐诗/poet.song.218000.json','["玄沙不出嶺，拄杖生根休用剪。", "保壽不渡河，鉢盂無柄不須安。"]'),
('d4152d67-35a5-4378-8a4d-af7596bd5554','偈頌七十六首  其二九','釋子益','宋','宋诗','song-poetry','','[]','酷暑炎炎何處避，不在鑊湯爐炭裏。',32,'全唐诗/poet.song.218000.json','["酷暑炎炎何處避，不在鑊湯爐炭裏。", "北窗一枕黑甜餘，細聽松風雜流水。"]'),
('610839b1-0988-4585-b63f-9853fc076589','偈頌七十六首  其三○','釋子益','宋','宋诗','song-poetry','','[]','一見便見，天回地轉。',42,'全唐诗/poet.song.218000.json','["一見便見，天回地轉。", "宗通說通，風虎雲龍。", "只如百丈被馬祖一喝，因甚三日耳聾。", "閩蜀同風。"]'),
('dcf785e6-edcb-4f6e-ab44-c24fd9e04659','偈頌七十六首  其三一','釋子益','宋','宋诗','song-poetry','','[]','日可冷，月可熱，衆魔不能壞真說。',40,'全唐诗/poet.song.218000.json','["日可冷，月可熱，衆魔不能壞真說。", "且作麽生是真說，屋頭泉溜響無休，砌下寒蛩聲更切。"]'),
('764af3eb-1f03-41a6-b6f7-bb090ab2cc3a','偈頌七十六首  其三二','釋子益','宋','宋诗','song-poetry','','[]','一日復一日，一秋復一秋。',32,'全唐诗/poet.song.218000.json','["一日復一日，一秋復一秋。", "從頭屈指數，屈指又從頭，烏飛兔走幾時休。"]'),
('1cbc7ddf-027e-4c86-a953-c0a47690d54a','偈頌七十六首  其三三','釋子益','宋','宋诗','song-poetry','','[]','得路塞路，過橋斷橋。',44,'全唐诗/poet.song.218000.json','["得路塞路，過橋斷橋。", "不拘兩岸，不滯中流。", "直饒你會得步行騎水牛，我更問你，空手因甚把鋤頭。"]'),
('18516b99-44bf-4034-b37c-6dddd91ddda4','偈頌七十六首  其三四','釋子益','宋','宋诗','song-poetry','','[]','冬前冬後，沙飛石走。',43,'全唐诗/poet.song.218000.json','["冬前冬後，沙飛石走。", "時節到來，不容袖手。", "興化雖無驅風走電之謀，也要應個時候，一九二九。"]'),
('d041cdc5-026a-433c-b33e-c06890132d48','偈頌七十六首  其三五','釋子益','宋','宋诗','song-poetry','','[]','十聲槌下定綱宗，送去迎來事一同。',32,'全唐诗/poet.song.218000.json','["十聲槌下定綱宗，送去迎來事一同。", "豎百橫千有通變，笊籬無柄舀春風。"]'),
('4c81cd94-05b7-4885-8c76-304e5ab7a379','偈頌七十六首  其三六','釋子益','宋','宋诗','song-poetry','','[]','般若鋒，金剛焰。',30,'全唐诗/poet.song.218000.json','["般若鋒，金剛焰。", "覿面當機，突出難辨。", "春風一陣來，落花飛片片。"]'),
('86d026df-0684-49bc-af3c-2ec908fa367b','偈頌七十六首  其三七','釋子益','宋','宋诗','song-poetry','','[]','憶昔玉几時，分贓不合火。',38,'全唐诗/poet.song.218000.json','["憶昔玉几時，分贓不合火。", "今日驀相逢，依然衆恁麽。", "不恁麽，睦州擔板，雲門脚跛。"]'),
('4f7c393b-6081-4e97-8a55-6349669aef36','偈頌七十六首  其三八','釋子益','宋','宋诗','song-poetry','','[]','心如虛空不可量，聖君壽量亦如是。',32,'全唐诗/poet.song.218000.json','["心如虛空不可量，聖君壽量亦如是。", "將如是法報皇恩，天上人間更無比。"]'),
('006ba335-c085-411a-8af0-5474d66d9b51','偈頌七十六首  其三九','釋子益','宋','宋诗','song-poetry','','[]','一夏九十日，半月已過了。',31,'全唐诗/poet.song.218000.json','["一夏九十日，半月已過了。", "有問蠟人冰，鼻孔仍依舊。", "我手何似佛手。"]'),
('4aa24a6e-c561-40eb-b6a1-09192aaf305c','偈頌七十六首  其四○','釋子益','宋','宋诗','song-poetry','','[]','是句亦剗，非句亦剗。',42,'全唐诗/poet.song.218000.json','["是句亦剗，非句亦剗。", "德山焚疏鈔，臨濟燒禪板。", "堪悲堪笑，一對無孔鐵鎚，馿年夢見正法眼。"]'),
('6c798e9a-1024-40b1-9af5-282ae3ffbc2d','偈頌七十六首  其四一','釋子益','宋','宋诗','song-poetry','','[]','古佛心，即于今。',26,'全唐诗/poet.song.218000.json','["古佛心，即于今。", "春風浩浩，春雨霖霖，高山流水少知音。"]'),
('942e9fc0-eae1-495d-98fa-84703ae63864','偈頌七十六首  其四二','釋子益','宋','宋诗','song-poetry','','[]','法身充塞太虛空，出沒何曾有定蹤。',32,'全唐诗/poet.song.218000.json','["法身充塞太虛空，出沒何曾有定蹤。", "獨許波旬知此意，半偷歡喜半搥胸。"]'),
('07cdc828-5e31-42bf-8cb5-01b2f74b9893','偈頌七十六首  其四三','釋子益','宋','宋诗','song-poetry','','[]','時節既至，其理自彰。',42,'全唐诗/poet.song.218000.json','["時節既至，其理自彰。", "井井秧浮綠，村村麥弄黄。", "半窗山月白，一枕竹風凉，笑倒山前鄧八郎。"]'),
('bfe13219-4be3-4e79-aaea-ea977ea35eab','偈頌七十六首  其四四','釋子益','宋','宋诗','song-poetry','','[]','進以禮，退以禮。',68,'全唐诗/poet.song.218000.json','["進以禮，退以禮。", "錄得語一篇，不在紙衣裏。", "所以智藏被馬師塗糊，克賓遭興化鈍置。", "千古之下，掛人唇齒。", "恩大難酬，痛入骨髓。", "檢點將來，玄沙道底。"]'),
('648ddd05-d9bd-48c0-be87-3601953be6f0','偈頌七十六首  其四五','釋子益','宋','宋诗','song-poetry','','[]','覺性海中，圓無不融。',40,'全唐诗/poet.song.218000.json','["覺性海中，圓無不融。", "聞時富貴，見後貧窮。", "窮則變，變則通，草鞋獰似虎，拄杖活如龍。"]'),
('d29c35bc-2e7a-4d14-b85b-cfa2e3951b34','偈頌七十六首  其四六','釋子益','宋','宋诗','song-poetry','','[]','十五日已前明似鏡，十五日已後曲如鎌。',36,'全唐诗/poet.song.218000.json','["十五日已前明似鏡，十五日已後曲如鎌。", "正當十五日，無人知此意，令我憶南泉。"]'),
('eed3fb3f-2383-4c1d-aeca-435526ed105b','偈頌七十六首  其四七','釋子益','宋','宋诗','song-poetry','','[]','秋江清，秋月白。',48,'全唐诗/poet.song.218000.json','["秋江清，秋月白。", "登高雙眼空，獨步乾坤窄。", "隻手未曾舉，黄菊已盈握。", "好彩從來奔齪家，隨分一盞茱萸茶。"]'),
('d749637e-bca9-46c8-91f9-978c6a6b31ec','偈頌七十六首  其四八','釋子益','宋','宋诗','song-poetry','','[]','東司頭，糞坑上。',45,'全唐诗/poet.song.218000.json','["東司頭，糞坑上。", "臭氣薰天，如何近傍。", "一屙便了底，痛與一錐。", "的的卓卓底，三十拄杖。", "有功者賞。"]'),
('e6b16bc7-fc0b-4d22-927a-1c3ae091f8bf','偈頌七十六首  其四九','釋子益','宋','宋诗','song-poetry','','[]','常光現前，壁立萬仞。',33,'全唐诗/poet.song.218000.json','["常光現前，壁立萬仞。", "者裏一劃劃斷，別有一條捷徑。", "明眼人，因甚落井。"]'),
('313c80b2-3c9b-4c8d-9c39-5e1846b28bfe','偈頌七十六首  其五○','釋子益','宋','宋诗','song-poetry','','[]','親從寶山來，收得寶山寶。',56,'全唐诗/poet.song.218000.json','["親從寶山來，收得寶山寶。", "一片玉無瑕，千峰雲脫帽。", "九蓮峰畔無處藏，兜率宮中卒難討。", "歸來打鼓普請看，盤走珠兮珠走盤。"]'),
('192834a4-a36e-4f09-82fa-d99d89a88398','偈頌七十六首  其五一','釋子益','宋','宋诗','song-poetry','','[]','六陰既窮，群魔自殄。',54,'全唐诗/poet.song.218000.json','["六陰既窮，群魔自殄。", "一陽來復，吾道大亨。", "拄杖豎，十方世界一時豎。", "拄杖橫，十方世界一時橫。", "兵隨印轉，將逐符行。"]'),
('35f6ae6a-303b-4895-b380-7f54fd2bc0c3','偈頌七十六首  其五二','釋子益','宋','宋诗','song-poetry','','[]','未入山時，氣衝牛斗。',36,'全唐诗/poet.song.218000.json','["未入山時，氣衝牛斗。", "出得山來，衣穿露肘。", "更言午夜見明星，不知面皮厚多少。"]'),
('327c158f-c00d-436f-b622-2c906c4a0b92','偈頌七十六首  其五三','釋子益','宋','宋诗','song-poetry','','[]','六出花飛，無地卓錐。',38,'全唐诗/poet.song.218000.json','["六出花飛，無地卓錐。", "填溝塞壑，絕毫絕厘。", "嗄，忽驚捲盡青山去，又喜重携春色歸。"]'),
('d87b0bbc-54e6-482f-9442-8d50717df14d','偈頌七十六首  其五四','釋子益','宋','宋诗','song-poetry','','[]','至玄至妙，至奧至微。',42,'全唐诗/poet.song.218000.json','["至玄至妙，至奧至微。", "不可以識識，不可以智知。", "與麽會得，咈㖃啒㖀。", "不與麽會，鳳林吒之。"]'),
('5813724d-e4f8-4140-913f-51da2f498912','偈頌七十六首  其五五','釋子益','宋','宋诗','song-poetry','','[]','拄杖生根劫外春，斬新拈出示諸人。',32,'全唐诗/poet.song.218000.json','["拄杖生根劫外春，斬新拈出示諸人。", "擘開華岳千峰秀，放出黄河一派清。"]'),
('6e223f47-a87c-41fd-ba2e-363496d494b7','偈頌七十六首  其五六','釋子益','宋','宋诗','song-poetry','','[]','問處分明答處親，太平天子太平臣。',32,'全唐诗/poet.song.218000.json','["問處分明答處親，太平天子太平臣。", "等閑喝散千峰雪，此土西天一樣春。"]'),
('bba963b8-6cef-43dd-987f-0f90b7f568f1','偈頌七十六首  其五七','釋子益','宋','宋诗','song-poetry','','[]','現成公案，了無遷變。',52,'全唐诗/poet.song.218000.json','["現成公案，了無遷變。", "入得門來，一見便見。", "左顧則獅子嚬呻，右盼則象王迴轉。", "靈山一會儼然存，捏聚春風成一片。"]'),
('b871a919-11de-4278-a290-ed960b3d1f2d','偈頌七十六首  其五八','釋子益','宋','宋诗','song-poetry','','[]','九十長期，三分過二。',40,'全唐诗/poet.song.218000.json','["九十長期，三分過二。", "覺海浪平，鐵船無底。", "寒山子水牯牛作麽生，切不得道大家在這裏。"]'),
('df3e48a2-1e5e-4d41-91e8-56706a5f97be','偈頌七十六首  其五九','釋子益','宋','宋诗','song-poetry','','[]','伏暑未收，金風漸作。',20,'全唐诗/poet.song.218000.json','["伏暑未收，金風漸作。", "彈指聲中，門開樓閣。"]'),
('f16caff3-09b7-458b-a30a-1e00160ba1ce','偈頌七十六首  其六○','釋子益','宋','宋诗','song-poetry','','[]','菊花黄，茱萸香。',18,'全唐诗/poet.song.218000.json','["菊花黄，茱萸香。", "時節既至，其理自彰。"]'),
('3e7e21a3-3c09-42d0-87e1-2bde1b5ede39','偈頌七十六首  其六一','釋子益','宋','宋诗','song-poetry','','[]','作家相見，啐啄尤乖。',30,'全唐诗/poet.song.218000.json','["作家相見，啐啄尤乖。", "達士相逢，握鞭回首。", "撿點將來，已落第二。"]'),
('f92859bf-b01b-4b2c-b547-ab51437aea52','偈頌七十六首  其六二','釋子益','宋','宋诗','song-poetry','','[]','六載雪山修，幾乎沒合殺。',24,'全唐诗/poet.song.218000.json','["六載雪山修，幾乎沒合殺。", "半夜覩明星，和盲勃睟瞎。"]'),
('9ae03600-ad84-4a6e-8cb5-04533f0cd14e','偈頌七十六首  其六三','釋子益','宋','宋诗','song-poetry','','[]','語底默底不是，非語非默亦非。',28,'全唐诗/poet.song.218000.json','["語底默底不是，非語非默亦非。", "虛庵有一轉語，用處絕毫絕厘。"]'),
('19df122c-bb33-4cb7-80da-f4b8a5409211','偈頌七十六首  其六四','釋子益','宋','宋诗','song-poetry','','[]','春已過半，百花競芳。',36,'全唐诗/poet.song.218000.json','["春已過半，百花競芳。", "有些佛法，如何商量。", "千言萬語無人會，又逐流鶑過短牆。"]'),
('2e89d18f-22e9-40cc-9720-062f6f041082','偈頌七十六首  其六五','釋子益','宋','宋诗','song-poetry','','[]','有拄杖與拄杖，擊木無聲。',36,'全唐诗/poet.song.218000.json','["有拄杖與拄杖，擊木無聲。", "無拄杖奪拄杖，敲空作響。", "還見芭蕉和尚麽，莫妄想。"]'),
('087a86f4-2b8f-456b-9859-9ffbad84e4da','偈頌七十六首  其六六','釋子益','宋','宋诗','song-poetry','','[]','瞿曇色相紫金容，雨後青山插半空。',32,'全唐诗/poet.song.218000.json','["瞿曇色相紫金容，雨後青山插半空。", "覿面當機如不薦，桃花依舊笑春風。"]'),
('207112a0-7086-4c8d-a286-681641c0104c','偈頌七十六首  其六七','釋子益','宋','宋诗','song-poetry','','[]','定本無門，從何而入。',36,'全唐诗/poet.song.218000.json','["定本無門，從何而入。", "坐斷兩頭，中亦不立。", "沒可把，絕承當，風來一陣芰荷香。"]'),
('29dd6537-92c7-4b5b-adb8-e073d9d5f1f2','偈頌七十六首  其六八','釋子益','宋','宋诗','song-poetry','','[]','虛空年與壽山同，答處由來在問宗。',32,'全唐诗/poet.song.218000.json','["虛空年與壽山同，答處由來在問宗。", "但見皇風成一片，不知何處是疆封。"]'),
('ec477793-3097-4306-9c3d-697ac0406262','偈頌七十六首  其六九','釋子益','宋','宋诗','song-poetry','','[]','世尊不說說，迦葉不聞聞。',26,'全唐诗/poet.song.218000.json','["世尊不說說，迦葉不聞聞。", "兩个無孔鐵鎚，打就一合乾坤。"]'),
('9ece1b6c-6dff-4894-82bd-afc26fd87204','偈頌七十六首  其七○','釋子益','宋','宋诗','song-poetry','','[]','直下是，直下是。',24,'全唐诗/poet.song.218000.json','["直下是，直下是。", "賺殺人，疑殺你。", "上是天，下是地。"]'),
('c2e84e0b-f6c0-4f47-abdc-7ae5488136c2','偈頌七十六首  其七一','釋子益','宋','宋诗','song-poetry','','[]','律管吹灰，勾芒布令。',20,'全唐诗/poet.song.218000.json','["律管吹灰，勾芒布令。", "六國風清，九天雲靜。"]'),
('daebf0c5-f112-439c-91d2-0a6a55e85fef','偈頌七十六首  其七二','釋子益','宋','宋诗','song-poetry','','[]','二月十五，瞿曇滅度。',38,'全唐诗/poet.song.218000.json','["二月十五，瞿曇滅度。", "文殊頓足普賢悲，外道拊掌波旬舞。", "甜瓜徹蒂甜，苦瓠連根苦。"]'),
('05a0ced0-0737-4fbb-8f26-7419a4330bc1','偈頌七十六首  其七三','釋子益','宋','宋诗','song-poetry','','[]','識得一，萬事畢。',36,'全唐诗/poet.song.218000.json','["識得一，萬事畢。", "佛法颺在它方，世法拈靠一壁。", "有問奇特因緣，立秋已過五日。"]'),
('53506fc6-0c65-469e-9690-eecf7fc649d6','偈頌七十六首  其七四','釋子益','宋','宋诗','song-poetry','','[]','此段光明，輝天鑒地。',44,'全唐诗/poet.song.218000.json','["此段光明，輝天鑒地。", "靈山錯話，曹溪錯指。", "霧暗雲屯兮歷歷常明，地陷天崩兮也只如是。", "賺殺你。"]'),
('ab26dacf-6221-489b-8a71-5d40602bcbcc','偈頌七十六首  其七五','釋子益','宋','宋诗','song-poetry','','[]','有一則語，久欲拈出。',27,'全唐诗/poet.song.218000.json','["有一則語，久欲拈出。", "未動舌頭，遍界狼藉。", "且作麽生收拾。"]'),
('a7a03def-bc07-47f6-9092-2f2ecd28333a','偈頌七十六首  其七六','釋子益','宋','宋诗','song-poetry','','[]','臘月二十五，一曲重新舉。',42,'全唐诗/poet.song.218000.json','["臘月二十五，一曲重新舉。", "唱寡兮和稀，韻高兮調古。", "堪悲堪笑老東山，謾說豆子山前打瓦鼓。"]'),
('2e670cb0-f7b1-4482-97cb-5aaa304d0724','頌古十一首  其一','釋子益','宋','宋诗','song-poetry','','[]','心手相忘，二俱得妙，箭箭中的。',31,'全唐诗/poet.song.218000.json','["心手相忘，二俱得妙，箭箭中的。", "未脫窠臼脫窠臼，好手手中呈好手。"]'),
('11e4995a-02e8-499a-95cf-a988c22be11b','頌古十一首  其二','釋子益','宋','宋诗','song-poetry','','[]','多處添些已是訛，少處減些還是誑。',32,'全唐诗/poet.song.218000.json','["多處添些已是訛，少處減些還是誑。", "幾多著眼看機輪，誰知不在機輪上。"]'),
('b4811a3c-40c2-4156-9bd2-110e9e6a8dc6','頌古十一首  其三','釋子益','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','狗子佛性無，鐵船水上浮。',24,'全唐诗/poet.song.218000.json','["狗子佛性無，鐵船水上浮。", "順風帆未掛，已過洞庭湖。"]'),
('d126f06b-e222-4669-8753-0570fbb58601','頌古十一首  其四','釋子益','宋','宋诗','song-poetry','','[]','鈍如出匣吹毛劍，快似堅剛百煉鎚。',32,'全唐诗/poet.song.218000.json','["鈍如出匣吹毛劍，快似堅剛百煉鎚。", "直下低頭禮三拜，得便宜處落便宜。"]'),
('cb331ab0-6896-4b76-9cdb-2fb0e02f10ce','頌古十一首  其五','釋子益','宋','宋诗','song-poetry','','[]','出與未出，蓮花荷葉。',20,'全唐诗/poet.song.218000.json','["出與未出，蓮花荷葉。", "老倒智門，舌頭無骨。"]'),
('2b1384c8-e0fe-4034-8e1d-d29a41dcd16f','頌古十一首  其六','釋子益','宋','宋诗','song-poetry','','[]','盡道趙州勘婆子，不知婆子勘趙州。',32,'全唐诗/poet.song.218000.json','["盡道趙州勘婆子，不知婆子勘趙州。", "有意氣時添意氣，不風流處也風流。"]'),
('6234c4a9-7443-400b-a54b-dae14c09776e','頌古十一首  其七','釋子益','宋','宋诗','song-poetry','','[]','不是風兮不是旛，活人只在笑談間。',32,'全唐诗/poet.song.218000.json','["不是風兮不是旛，活人只在笑談間。", "面前坦坦平平路，背後重重疊疊山。"]'),
('15773006-7818-4222-927d-5755b77a5999','頌古十一首  其八','釋子益','宋','宋诗','song-poetry','','[]','拋磚引玉老香嚴，打著南邊動北邊。',32,'全唐诗/poet.song.218000.json','["拋磚引玉老香嚴，打著南邊動北邊。", "聽事不真鍾作甕，至今千古錯流傳。"]'),
('454b9ba8-b9db-4e62-8e61-cae9dfe6f756','頌古十一首  其九','釋子益','宋','宋诗','song-poetry','','[]','撥草瞻風尋劍客，桃花一見便忻然。',32,'全唐诗/poet.song.218000.json','["撥草瞻風尋劍客，桃花一見便忻然。", "直饒真到不疑地，放下更參三十年。"]'),
('1206cc61-3c9e-4d43-8e3e-95f190aaef3a','頌古十一首  其一○','釋子益','宋','宋诗','song-poetry','','[]','地藏栽田博飯，大似饑過心荒。',36,'全唐诗/poet.song.218000.json','["地藏栽田博飯，大似饑過心荒。", "聽它三三兩兩，佛法浩浩商量。", "杓柄那知有短長。"]'),
('429d08a1-c41d-4c1c-99cc-fc7b4f5cc294','頌古十一首  其一一','釋子益','宋','宋诗','song-poetry','','[]','撼樹良久，好手手中呈好手。',42,'全唐诗/poet.song.218000.json','["撼樹良久，好手手中呈好手。", "得用得體，一不成兮二不是。", "三十拄杖放渠儂，大似賊過後張弓。"]'),
('d866f219-aa45-4054-b56b-bd7cf350af3d','出山相贊','釋子益','宋','宋诗','song-poetry','','[]','捏雙拳，衣露肘。',34,'全唐诗/poet.song.218000.json','["捏雙拳，衣露肘。", "謂悟明星，有甚分曉。", "本爲修行利濟人，誰知變作不唧𠺕。"]'),
('8f57af52-c87f-4b3b-9dee-fe62bb3e0272','觀音贊','釋子益','宋','宋诗','song-poetry','','[]','楊柳枝頭，琉璃瓶裏。',36,'全唐诗/poet.song.218000.json','["楊柳枝頭，琉璃瓶裏。", "一滴渾無，千波競起。", "步步金蓮襯足生，何曾踏著自家底。"]'),
('cbcf160e-3d04-45bd-93f1-f839d75dd6a4','啞子觀音贊','釋子益','宋','宋诗','song-poetry','','[]','贊者舌禿，畫者口啞。',20,'全唐诗/poet.song.218000.json','["贊者舌禿，畫者口啞。", "籃裏錦鱗，愈增高價。"]'),
('017720ec-3fd6-44c7-bba4-be98690a6cba','維摩贊','釋子益','宋','宋诗','song-poetry','','[]','俗氣不除，病在一默。',20,'全唐诗/poet.song.218000.json','["俗氣不除，病在一默。", "扁鵲盧醫，醫你不得。"]'),
('b3ef3dac-dc9c-4609-986d-4b5c69715891','達磨携履贊','釋子益','宋','宋诗','song-poetry','','[]','赤雙脚，携隻履。',26,'全唐诗/poet.song.218000.json','["赤雙脚，携隻履。", "自東自西，誰不識你。", "最難掩是當門齒。"]'),
('aad51ca5-6edb-41ef-aa3f-563fafc3dffc','布袋贊','釋子益','宋','宋诗','song-poetry','','[]','布袋橫拖，肚皮捺下。',28,'全唐诗/poet.song.218000.json','["布袋橫拖，肚皮捺下。", "行貨有些，沒人酬價。", "拊背覓錢真奉化。"]'),
('234e16e6-6b18-4669-8e5a-1c4ef9bdaec0','寒山把蕉葉執筆贊','釋子益','宋','宋诗','song-poetry','','[]','吟詩吟未就，執筆且搜枯。',24,'全唐诗/poet.song.218000.json','["吟詩吟未就，執筆且搜枯。", "欲寫芭蕉上，依前一字無。"]'),
('b54e2975-26d5-45ff-9386-eb41840cd621','拾得携苕箒贊','釋子益','宋','宋诗','song-poetry','','[]','往來雙磵路，脚下起塵埃。',24,'全唐诗/poet.song.218000.json','["往來雙磵路，脚下起塵埃。", "苕箒忙忙掃，何曾掃得來。"]'),
('69908d1b-36bc-4c38-8c1c-af1621c96d61','靈照女贊','釋子益','宋','宋诗','song-poetry','','[]','家業盡拋離，沿街賣笊籬。',24,'全唐诗/poet.song.218000.json','["家業盡拋離，沿街賣笊籬。", "胸中無限意，不許老龐知。"]'),
('9f248952-38bb-4556-9b3a-da835a44b38f','朝陽贊','釋子益','宋','宋诗','song-poetry','','[]','者邊才補了，又見那邊穿。',24,'全唐诗/poet.song.218000.json','["者邊才補了，又見那邊穿。", "不覺日又夜，爭教人少年。"]'),
('7908237b-5170-4ae3-938a-286dfee7acc3','對月贊','釋子益','宋','宋诗','song-poetry','','[]','黑豆忙忙數，教休不肯休。',24,'全唐诗/poet.song.218000.json','["黑豆忙忙數，教休不肯休。", "幸然明似鏡，何用曲如鈎。"]'),
('ad4ec8f1-eac5-43af-a445-37cc13a37e01','佛鑑和尚贊','釋子益','宋','宋诗','song-poetry','','[]','雨過五峰，雲橫玉几。',69,'全唐诗/poet.song.218000.json','["雨過五峰，雲橫玉几。", "日面月面，只這便是。", "道是佛鑑，舌拄梵天。", "道非佛鑑，眉毛拖地。", "更言兩對君王，三奉詔旨。", "看來元是陰平界上雍師波，誰不識你。"]'),
('8a07d13a-063d-4239-b484-0d82a074755b','自贊慶成長老請','釋子益','宋','宋诗','song-poetry','','[]','怡山頂不露，上有通天竅。',66,'全唐诗/poet.song.218000.json','["怡山頂不露，上有通天竅。", "事事總不知，虛明肯自照。", "個樣䖃苴川僧，如何描邈得就。", "慶成訐露人前，早是外揚家醜。", "不用別舉話頭，我手何似佛手。"]'),
('05d0a5bd-2d7b-4a16-b49b-e87f5050f507','禮開山伏虎祖師塔','釋子益','宋','宋诗','song-poetry','','[]','羊腸知幾折，行盡水村村。',48,'全唐诗/poet.song.218000.json','["羊腸知幾折，行盡水村村。", "捫壁穿雲棧，攀蘿過石門。", "尋蹤知虎在，繞塔見師存。", "他日重來地，松枝拂蘚痕。"]'),
('94a6b0c3-0732-447e-b655-aa8553108d41','綿州曇上人求語上徑山','釋子益','宋','宋诗','song-poetry','','[]','解唱東山瓦鼓歌，不知節拍有誵訛。',32,'全唐诗/poet.song.218000.json','["解唱東山瓦鼓歌，不知節拍有誵訛。", "要教聲響如當日，快向凌霄走一遭。"]'),
('71b3ba92-7171-4859-a7fb-7e84e89be9cb','祥侍者化供','釋子益','宋','宋诗','song-poetry','','[]','祥禪爲衆下山來，七十高僧笑滿腮。',32,'全唐诗/poet.song.218000.json','["祥禪爲衆下山來，七十高僧笑滿腮。", "袖裏金鎚曾未動，千門萬戶一時開。"]'),
('1825e637-af20-4a63-852c-ba0103058701','偶成','釋子益','宋','宋诗','song-poetry','','[]','那得工夫過一關，從空放下絕追攀。',64,'全唐诗/poet.song.218000.json','["那得工夫過一關，從空放下絕追攀。", "松風不入是非耳，竹逕肯通人我山。", "有問對談惟莫莫，無心袖手只閑閑。", "忽聞枝上靈禽語，似笑山翁癡復頑。"]'),
('d529f60a-69a7-4f11-8808-23ff3a06f0aa','一上人之徑山','釋子益','宋','宋诗','song-poetry','','[]','一處纔通處處通，凌霄突兀對青龍。',32,'全唐诗/poet.song.218000.json','["一處纔通處處通，凌霄突兀對青龍。", "道途不涉最親句，只在平常日用中。"]'),
('4dbef6ea-91a7-4474-89b9-67b47fe7e90c','欽禪人之天童','釋子益','宋','宋诗','song-poetry','','[]','興化三門開兩邊，聚頭噇飯不談禪。',32,'全唐诗/poet.song.218000.json','["興化三門開兩邊，聚頭噇飯不談禪。", "天童有問其中事，收割今年勝去年。"]'),
('d2d75269-1a20-4623-b48d-052f11966cf5','傳上人之徑山','釋子益','宋','宋诗','song-poetry','','[]','佛祖不傳希世寶，千人萬人覷不破。',32,'全唐诗/poet.song.218000.json','["佛祖不傳希世寶，千人萬人覷不破。", "五峰相見索看時，切忌傾出一栲栳。"]'),
('0ab80394-29d3-4d66-83b6-8dabcff50322','全上人之仰山','釋子益','宋','宋诗','song-poetry','','[]','集雲峰下四藤條，千載誰知恨未銷。',32,'全唐诗/poet.song.218000.json','["集雲峰下四藤條，千載誰知恨未銷。", "去去全身擔荷得，石龍依舊碧岧嶤。"]'),
('7f86317d-7cea-44bf-8f31-7bf49f9f2e24','祖典座往南嶽','釋子益','宋','宋诗','song-poetry','','["\u8861\u5c71"]','寂寞相從恰四年，不曾談著祖師禪。',32,'全唐诗/poet.song.218000.json','["寂寞相從恰四年，不曾談著祖師禪。", "杖藜七十二峰去，點破瀟湘水底天。"]'),
('9a572e52-b1c1-4aee-b276-7ed0c3094ee9','化夏供','釋子益','宋','宋诗','song-poetry','','[]','興化年來徹骨貧，口生白醭面生塵。',32,'全唐诗/poet.song.218000.json','["興化年來徹骨貧，口生白醭面生塵。", "不知那個無思算，來飽無心閑道人。"]'),
('522cea6f-04c7-4c87-ba31-ccc7ffbd6579','贈月蓬相士','釋子益','宋','宋诗','song-poetry','','[]','月蓬岩下電，相心不相面。',24,'全唐诗/poet.song.218000.json','["月蓬岩下電，相心不相面。", "劍關不露鋒，向甚處相見。"]'),
('a8379cf3-aaca-493a-b07e-c292432d3a38','小師慧清遊山','釋子益','宋','宋诗','song-poetry','','[]','行脚不遇人，不如屋裏坐。',50,'全唐诗/poet.song.218000.json','["行脚不遇人，不如屋裏坐。", "那事本現成，何須外邊討。", "東行西行，驀忽築著脚指頭。", "定笑玄沙，錯認橘皮喚作火。"]'),
('c37491f1-fbd6-4045-acc9-8eeb53fd86ea','題瑞雲峰','釋子益','宋','宋诗','song-poetry','','[]','山行百折路重重，到頂回頭眼界空。',32,'全唐诗/poet.song.218000.json','["山行百折路重重，到頂回頭眼界空。", "但覺衲衣冰樣冷，不知身在瑞雲峰。"]'),
('ff050238-8f96-4d25-ab20-34568776a4bc','題幽林寺','釋子益','宋','宋诗','song-poetry','','[]','幽林卓錫地，香火續深禪。',48,'全唐诗/poet.song.218000.json','["幽林卓錫地，香火續深禪。", "但見樹迷戶，不知頭頂天。", "雲開青嶂聳，瀑濺雪珠懸。", "一脈來何處，曹溪萬丈淵。"]'),
('181869c4-b274-40bc-9a8e-e7702099f487','謝東禪月湖以諸祖偈頌見示','釋子益','宋','宋诗','song-poetry','','[]','家貧路富鼻遼天，各立門風辱祖先。',32,'全唐诗/poet.song.218000.json','["家貧路富鼻遼天，各立門風辱祖先。", "爭似太平無事客，長伸兩脚放憨眠。"]'),
('c80a9458-6f28-4157-b020-3ce5341e9564','讀書趣','趙崇潔','宋','宋诗','song-poetry','','[]','溪流靜閲萬籤書，未許傳訛雜魯魚。',64,'全唐诗/poet.song.218000.json','["溪流靜閲萬籤書，未許傳訛雜魯魚。", "洙泗淵源應出活，宮牆高大獨生虛。", "乾坤容我承三極，造化憑誰托一噓。", "從此已知身即道，便便熟路駕輕車。"]'),
('34a16ee2-7d99-4cee-a91e-260c11bfd6b5','遊亭晚酌','趙崇潔','宋','宋诗','song-poetry','','[]','一樽對酌晚臨溪，詩景撩人興不迷。',64,'全唐诗/poet.song.218000.json','["一樽對酌晚臨溪，詩景撩人興不迷。", "風約灘聲侵座冷，月移花影落簷低。", "銀箋白雪心先吐，玉斝黄流手漫提。", "自慶一時文物會，肯拚身世醉如泥。"]'),
('f0258918-25ce-4ade-83f5-5c5dc1972826','九鯉湖','吳有定','宋','宋诗','song-poetry','','[]','昔聞九仙靈，今登九仙地。',24,'全唐诗/poet.song.218000.json','["昔聞九仙靈，今登九仙地。", "裊裊一爐香，寥寥千載事。"]'),
('c9c66df2-e8ad-4505-b45b-17d63214dda1','臨終書偈','釋文頠','宋','宋诗','song-poetry','','[]','空山頑質世偏須，禪客元慚綺色枯。',32,'全唐诗/poet.song.218000.json','["空山頑質世偏須，禪客元慚綺色枯。", "幾吐烟光供染翰，石田隻字可留無。"]'),
('c788e9a3-4140-4464-a7d5-55bacfc70e17','夜對梅花示彥恭侄  其一','王偘','宋','宋诗','song-poetry','','[]','羈旅不自怡，坐閲芳歲晚。',48,'全唐诗/poet.song.218000.json','["羈旅不自怡，坐閲芳歲晚。", "江湖有莫逆，梅花還到眼。", "平生相慰藉，風期無近遠。", "今夕共短檠，與子興不淺。"]'),
('fc65faed-c263-4cc0-93b6-573343c026ce','夜對梅花示彥恭侄  其二','王偘','宋','宋诗','song-poetry','','[]','羈旅閲世紛，坐念百憂集。',48,'全唐诗/poet.song.218000.json','["羈旅閲世紛，坐念百憂集。", "共子時劇談，滿懷冰雪潔。", "儀型誰有常，梅花靜玉立。", "何用對忘憂，歲寒端有益。"]'),
('88ddde2c-0fe7-45db-ac9a-0e9ae455bd0c','冬日雜興  其一','王偘','宋','宋诗','song-poetry','','[]','庭際幽蘭手自種，託根不與春花共。',64,'全唐诗/poet.song.218000.json','["庭際幽蘭手自種，託根不與春花共。", "冉冉同風數莖竹，襟期元作幽人供。", "如何江湖浪征逐，芳信却因馮翼送。", "多慚獨處歲將晚，尚想清標形曉夢。"]'),
('8f82318f-6e5f-4990-8b9f-13cd564215b0','冬日雜興  其二','王偘','宋','宋诗','song-poetry','','[]','澤國風饕霜力緊，黄落凋殘碧成錦。',64,'全唐诗/poet.song.218000.json','["澤國風饕霜力緊，黄落凋殘碧成錦。", "最憐柿葉與楓林，平園物色正瀟凜。", "造化不翕何所張，獨怪廷朝漏融景。", "天理真機默玩心，悟取靈根發深省。"]'),
('e7460744-082e-4737-a0d2-00c67d0fb520','題畫扁  其一','王偘','宋','宋诗','song-poetry','','[]','野橋人迹少，林靜谷風閑。',24,'全唐诗/poet.song.218000.json','["野橋人迹少，林靜谷風閑。", "誰識孤峰頂，悠然宇宙寬。"]'),
('cbfff4d6-e314-40b9-921b-286772aeb844','題畫扁  其二','王偘','宋','宋诗','song-poetry','','[]','深林擁蒼翠，絕巘頃陂陀。',24,'全唐诗/poet.song.218000.json','["深林擁蒼翠，絕巘頃陂陀。", "便欲褰裳去，乘風逸興多。"]'),
('d009723a-08ce-4e6b-9f42-7fbff9f65a1b','過分水嶺即事次韻','王偘','宋','宋诗','song-poetry','','[]','積陰頗愁寂，一笑晚風生。',48,'全唐诗/poet.song.218000.json','["積陰頗愁寂，一笑晚風生。", "豪爽傳詩韻，清真破俗酲。", "層巒思就隠，大壑戒趨程。", "芳草無人種，連天只麽青。"]'),
('a9d8805e-12d7-4931-bf0a-5508ca025ff2','查林對月','王偘','宋','宋诗','song-poetry','','[]','一天風月近中秋，凝望家山不阻修。',32,'全唐诗/poet.song.218000.json','["一天風月近中秋，凝望家山不阻修。", "漫浪疎林人已倦，心期猶與素光謀。"]'),
('ddfe9b11-00f9-465e-8611-13435dffdf2d','過馮嶺感舊','王偘','宋','宋诗','song-poetry','','[]','危陟山椒下碧灣，籃輿竟日劇千盤。',32,'全唐诗/poet.song.218000.json','["危陟山椒下碧灣，籃輿竟日劇千盤。", "傷心四起經行舊，那復當年綵袖班。"]'),
('43a2d7b6-ab8f-4fe6-9fec-0766688a6ab3','寄玉澗','王偘','宋','宋诗','song-poetry','','[]','山中之樂屬高人，風月無邊取次吟。',32,'全唐诗/poet.song.218000.json','["山中之樂屬高人，風月無邊取次吟。", "但使胸中飽丘壑，莫將片點著埃塵。"]'),
('d90dcbb0-a90d-4458-82bb-93b7dd6705d6','宿平江寺','汪儀鳳','宋','宋诗','song-poetry','','[]','行盡江東又復西，連天汀草淡烟迷。',32,'全唐诗/poet.song.218000.json','["行盡江東又復西，連天汀草淡烟迷。", "回頭悵望家何處，雲外青山一抹低。"]'),
('1b30b926-4030-4226-9df3-7d75644f333d','題豐城驛','汪儀鳳','宋','宋诗','song-poetry','','[]','過盡長亭復短亭，修途隨處月同行。',32,'全唐诗/poet.song.218000.json','["過盡長亭復短亭，修途隨處月同行。", "明朝買得扁舟去，兩岸蘆花夾櫓聲。"]'),
('e8f5c30f-fd5c-46dc-a8cd-69feae0df8eb','閏月見九華菊','翁逢龍','宋','宋诗','song-poetry','','[]','衆草已枯霜，牆陰獨自芳。',48,'全唐诗/poet.song.218000.json','["衆草已枯霜，牆陰獨自芳。", "旋開三四蕊，知爲兩重陽。", "酒恰今朝熟，花多一月香。", "又經風雨後，得爾慰凄凉。"]'),
('567a1b5c-db63-4a12-832e-42c8fed5cad4','天津橋','翁逢龍','宋','宋诗','song-poetry','','[]','下馬過天津，聽傳禁漏頻。',48,'全唐诗/poet.song.218000.json','["下馬過天津，聽傳禁漏頻。", "惟憐一橋月，曾照六朝人。", "金剝宮門字，紅飛粉壁塵。", "中官來宿內，因問帝鄉親。"]'),
('b4ab9465-8704-4e6b-9948-1327b9f9e7ee','金山寺','翁逢龍','宋','宋诗','song-poetry','','[]','波濤湧處浮雙塔，塔影高低樹影邊。',64,'全唐诗/poet.song.218000.json','["波濤湧處浮雙塔，塔影高低樹影邊。", "山下雖無歸寺路，門前却有過淮船。", "石峰隔水難尋水，井脈通泉易得泉。", "聞說老龍歸洞口，幾回驚起定僧禪。"]'),
('f984c653-1072-4fe6-acd3-e9a1306bf89a','祈雪','翁逢龍','宋','宋诗','song-poetry','','[]','谷中草木幾經春，敕額猶存古隸文。',64,'全唐诗/poet.song.218000.json','["谷中草木幾經春，敕額猶存古隸文。", "千里耕桑安土俗，一爐香火奉山君。", "多留姓字溪邊石，慣見旌旗隴上雲。", "太守若賢神自感，夜來入夢雪繽紛。"]'),
('b001ba3a-dfde-4506-baab-7bfb9509ebd9','原西','翁逢龍','宋','宋诗','song-poetry','','[]','原西行來遍，獨影在斜陽。',48,'全唐诗/poet.song.218000.json','["原西行來遍，獨影在斜陽。", "驟雨晴明快，初秋早晚凉。", "猿摇山果落，麝浴澗泉香。", "不向閑中看，爭知城郭忙。"]'),
('7f958b4e-98f0-4320-92e7-e0b88db8986d','上馬','翁逢龍','宋','宋诗','song-poetry','','[]','因行作遊計，上馬未須忙。',48,'全唐诗/poet.song.218000.json','["因行作遊計，上馬未須忙。", "舊路往來熟，新秋早晚凉。", "看圖尋古跡，聽語認同鄉。", "一带陂塘近，西風菱藕香。"]'),
('a4c2aa2a-6d25-40c6-85e7-1c3872990f15','過齊山人居','翁逢龍','宋','宋诗','song-poetry','','[]','自說住居年，山靈夙有緣。',48,'全唐诗/poet.song.218000.json','["自說住居年，山靈夙有緣。", "看經醫病鶴，祭土鑿新泉。", "食相過饑歲，眠蓑度雪天。", "所言非釋老，難與世人傳。"]'),
('cf49cd74-a142-4714-ab3f-daf5a239620c','官滿借居','翁逢龍','宋','宋诗','song-poetry','','[]','盡裝家具已回京，便覺身如片葉輕。',64,'全唐诗/poet.song.218000.json','["盡裝家具已回京，便覺身如片葉輕。", "近市借居人語雜，閉門獨處自心清。", "雨中躡屣青苔滑，燭下梳頭白髮明。", "余亦傍人簷底住，新來巢燕不須驚。"]'),
('07c4ff94-0845-4721-af40-591d9477505b','夜讀','翁逢龍','宋','宋诗','song-poetry','','[]','官事歸來夜雪埋，兒曹燈火小茅齋。',32,'全唐诗/poet.song.218000.json','["官事歸來夜雪埋，兒曹燈火小茅齋。", "人家不必問貧富，但有讀書聲便佳。"]'),
('eb2c5cff-1038-4781-a49b-37884c8cd153','曹娥廟','翁逢龍','宋','宋诗','song-poetry','','[]','再拜靈娥廟，魂清若可招。',48,'全唐诗/poet.song.218000.json','["再拜靈娥廟，魂清若可招。", "幡風吹古渡，帆月落殘潮。", "碑有行人讀，香多野客燒。", "迎神漢朝曲，時聽起雲霄。"]'),
('72c6f3ee-fc29-4d0b-ae4a-d8075aa3889f','曹娥墓','翁逢龍','宋','宋诗','song-poetry','','[]','何朝無朽骨，此地尚清陰。',48,'全唐诗/poet.song.218000.json','["何朝無朽骨，此地尚清陰。", "冢上獨根樹，江邊孤女心。", "化錢燒石燥，落葉漬泥深。", "長有英靈在，風平煙浪沉。"]'),
('c5f9e4c4-14aa-4a78-a564-4670f1efd4ce','潤州五州山','翁逢龍','宋','宋诗','song-poetry','','[]','五州山下路，樵牧自成羣。',48,'全唐诗/poet.song.218000.json','["五州山下路，樵牧自成羣。", "澗淺泉交徑，巖高石礙雲。", "老松前代寺，異草貴人墳。", "更陟重岡望，江淮地勢分。"]'),
('e5aeba5f-2b13-4b7f-98ee-04c2ba36b268','除夜懷弟','翁逢龍','宋','宋诗','song-poetry','','[]','爲官與爲客，相望各天涯。',48,'全唐诗/poet.song.218000.json','["爲官與爲客，相望各天涯。", "明日同添歲，何年共在家。", "梅飄幾片雪，燈結兩心花。", "前月書無報，多因道路賒。"]'),
('07e9ddc1-c53f-4d1b-8f91-47666cd0b628','句','翁逢龍','宋','宋诗','song-poetry','','[]','知君遊世磨不磷，往作道人之石友。',16,'全唐诗/poet.song.218000.json','["知君遊世磨不磷，往作道人之石友。"]'),
('1540ee92-3ac2-4994-8f19-d12b42c07c18','潮陽東山','鄭玠','宋','宋诗','song-poetry','','[]','暮天涼雨急霏霏，十二巫峰高復低。',32,'全唐诗/poet.song.218000.json','["暮天涼雨急霏霏，十二巫峰高復低。", "醉魂不受風飄斷，只恐行雲自濕衣。"]'),
('714dd66e-6e43-4e61-b624-cb078a471e36','初至羅浮','鄭玠','宋','宋诗','song-poetry','','[]','長說羅浮欲到難，清遊今作字民官。',64,'全唐诗/poet.song.218000.json','["長說羅浮欲到難，清遊今作字民官。", "分明蓬島三山色，占得飛雲六月寒。", "寶軸幾函青貝葉，玉蘭無限碧琅玕。", "此來更擬詢遺事，記與靈蹤石上看。"]'),
('7d613010-bef6-4765-94a8-9a39a4b39ca6','葛仙行祠','鄭玠','宋','宋诗','song-poetry','','[]','身爲俗吏趨行部，手爇名香祝有年。',32,'全唐诗/poet.song.218000.json','["身爲俗吏趨行部，手爇名香祝有年。", "五色雀飛應薦祉，七星松古自通仙。"]'),
('9dc632d9-f0cb-40f6-80ab-b940826d1422','丹竈','鄭玠','宋','宋诗','song-poetry','','[]','靈跡曾傳葛稚川，至今丹竈尚依然。',64,'全唐诗/poet.song.218000.json','["靈跡曾傳葛稚川，至今丹竈尚依然。", "誰云碧海三山島，別是朱明一洞天。", "龍出玉京成往事，鶴來華表是何年。", "塵埃勿歎空回首，到得仙山亦有緣。"]'),
('6db1164f-50ef-4c76-ba06-881e45af31c0','觀源洞','鄭玠','宋','宋诗','song-poetry','','[]','麻姑峰頭黄鶴歸，稚川竈上丹霞棲。',80,'全唐诗/poet.song.218000.json','["麻姑峰頭黄鶴歸，稚川竈上丹霞棲。", "寒猿嘯木山月白，正是仙人朝斗時。", "壺天景象何靈杳，松門石徑茸芳草。", "落花滿院香沈沈，緣似劉郎應解到。", "碧溪數聲連暮鐘，夢回已覺松窗曉。"]'),
('25070b09-ef03-426a-83b8-351169147038','白雲庵','鄭玠','宋','宋诗','song-poetry','','[]','羅浮山頭老松樹，中夜長吟送風雨。',64,'全唐诗/poet.song.218000.json','["羅浮山頭老松樹，中夜長吟送風雨。", "病夫幽獨枕書眠，靜聽松聲默無語。", "壁間畫像對書燈，耿耿殘油下饑鼠。", "夢覺跏趺不成寐，要伴禪和聽二鼓。"]'),
('f7091462-768b-4520-a6fb-a1a5f3557887','寄逍遥子','鄭玠','宋','宋诗','song-poetry','','[]','自從夫子仙山去，聞說山中分外清。',32,'全唐诗/poet.song.218000.json','["自從夫子仙山去，聞說山中分外清。", "半夜洞天松月白，野猿吟和讀書聲。"]'),
('4d87ad7a-7ac7-4495-b726-926ad178acff','潮陽尉鄭太玉夢至泉側飲之甚甘明日得之東山上作夢泉記令余作詩爲賦此篇','唐康','宋','宋诗','song-poetry','','[]','入道肯著相，出神得佳泉。',240,'全唐诗/poet.song.218000.json','["入道肯著相，出神得佳泉。", "起尋定中境，偶在山之巔。", "四人蹋𠿕𧇠，數里聞潺湲。", "循聲到巉絕，滿意流甘鮮。", "雖深石可數，太察魚難筌。", "分爲縞練長，濺作珠璣圓。", "一窺宿酲解，三嚥沉疴痊。", "恍惚尚疑夢，歡呼欲成癲。", "山澗短於井，海飲痰生涎。", "那知道在邇，幾作野遺賢。", "事故由人興，物爲知己妍。", "誰陪濠上遊，諒携室中天。", "雖無十丈華，中有一滴禪。", "名酒覺殊勝，宜茶定常煎。", "蘭亭羽觴冷，魚腹青箇連。", "新文來遠矣，開卷猶淙然。", "徑欲抱琴去，臨流聽天全。", "不但受以耳，庶幾神者先。", "寫爲夢泉操，第入樂府篇。", "將前輒復却，萬事付有緣。"]'),
('bd5aefa1-b605-4b36-ab93-735e89202262','句','劉申','宋','宋诗','song-poetry','','[]','一川带遶三平島，萬巘環趨兩翠巒。',16,'全唐诗/poet.song.218000.json','["一川带遶三平島，萬巘環趨兩翠巒。"]'),
('67f51c06-4b0e-4cfa-a262-675e12ba90d7','與正父叔王南運上風聯句','陽醇','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.218000.json','["無正文。"]'),
('9a1d9869-52cf-497a-a1d3-364123c0e64d','與陽正父陽存子上風聯句','王南運','宋','宋诗','song-poetry','','[]','無正文。',4,'全唐诗/poet.song.218000.json','["無正文。"]'),
('271ba3e3-a7d9-475d-b1e7-d0d4a6fec31a','題元子故宅','文有年','宋','宋诗','song-poetry','','[]','漫郎百事皆漫爾，獨有溪山認作吾。',128,'全唐诗/poet.song.218000.json','["漫郎百事皆漫爾，獨有溪山認作吾。", "念無一物鎮泉石，生怕偃蹇羞吾徒。", "靈武中興功掩德，天地大義須人扶。", "寧將善頌寓譎諫，百世聞之立懦夫。", "太師勁氣形於筆，二美能兼自古無。", "後來衮衮下注脚，識者涪翁次石湖。", "松煤狼藉楮山赭，空谷雷響工傳摹。", "徘徊熟玩長太息，世道日與湘流俱。"]'),
('0bc96c16-9bd7-4bcf-8d90-13c213641288','題澹山巖','文有年','宋','宋诗','song-poetry','','[]','爲愛溪山來永州，黄茅白葦使人愁。',96,'全唐诗/poet.song.218000.json','["爲愛溪山來永州，黄茅白葦使人愁。", "驅車遥指崳峰去，峰在瀟江最上頭。", "江轉峰回景奇絕，澹山嵌竇真天設。", "摩挲丹竈酌石泉，髣髴曾遊今幾劫。", "徵君徵君苦避秦，一秦人又一秦人。", "青山踏破無扃鐍，何地堪逃世上塵。"]'),
('50cce57b-8a20-4682-9ead-bd154d09fef4','出郊觀稼','陳塏','宋','宋诗','song-poetry','','[]','數月兩出郊，勸農復觀稼。',192,'全唐诗/poet.song.218000.json','["數月兩出郊，勸農復觀稼。", "始言麥壟春，今已稻畦夏。", "女紅綵紝餘，丁黄耘耔暇。", "暄涼雖不齊，晴雨倏忽乍。", "百豐未爲多，一歉誠所怕。", "蠲逋廣上恩，平糶裁米價。", "毫髮可及民，豈不念夙夜。", "昔有王長官，築堰它山下。", "惠利久益博，神靈此其舍。", "泓深或龍蟄，堅屹無蟻罅。", "定爲三七分，釃爲數十汊。", "石梁貫雲濤，誰敢著足跨。", "流沙從何來，疑有物驅駕。", "人力幾淘浚，壅淤仍障壩。", "旦功終此惠，去沙而變化。", "視古誰比方，鄭白其流亞。"]'),
('9bc9c9ba-f82a-4c4f-a63f-395d82250a33','極目亭','陳塏','宋','宋诗','song-poetry','','[]','誰知極目名亭意，不在登臨與品題。',64,'全唐诗/poet.song.218000.json','["誰知極目名亭意，不在登臨與品題。", "天地兩間同汗漫，江淮一水自東西。", "驚棲何日能歸雁，靈異當年任照犀。", "萬境盡從心上化，靜參飛躍悟端倪。"]'),
('7592de0e-428d-4e62-b2c1-c7ae2e79bc35','懷古堂和陳夢斗詩','陳塏','宋','宋诗','song-poetry','','[]','蛾眉亭下路，舟楫幾經過。',48,'全唐诗/poet.song.218000.json','["蛾眉亭下路，舟楫幾經過。", "晚識黄山面，新添白髮多。", "學仙徒化鶴，病僂喜名駝。", "四上江湖請，金章許換簑。"]'),
('c8636b38-e43b-4fdf-8ff1-1773c947cda5','登十洲之一亭','林元晉','宋','宋诗','song-poetry','','[]','師帥勤民衆務修，挾晴領客過仙洲。',64,'全唐诗/poet.song.218000.json','["師帥勤民衆務修，挾晴領客過仙洲。", "不緣感召豐年好，安得從容暇日遊。", "人在湖山皆自得，政先倉廩百無憂。", "老農不解君王意，却要朝輈爲少留。"]'),
('ca055239-7785-43a0-bcbf-30febdfdb9fa','清明前一日友人招泛東湖  其一','陳宗仁','宋','宋诗','song-poetry','','[]','僧舍經旬只病眠，不知春事滿湖邊。',32,'全唐诗/poet.song.218000.json','["僧舍經旬只病眠，不知春事滿湖邊。", "相携步出城東去，楊柳桃花氣欲烟。"]'),
('6a169ae5-dff0-41aa-ad3e-331851fae028','清明前一日友人招泛東湖  其二','陳宗仁','宋','宋诗','song-poetry','','[]','令節正逢一百五，輕舟閒泛兩三人。',32,'全唐诗/poet.song.218000.json','["令節正逢一百五，輕舟閒泛兩三人。", "弄珠樓下波如酒，醖碧摇紅潏潏新。"]'),
('022d5a64-234e-4629-950f-40042fd905f9','視師頌','常挺','宋','宋诗','song-poetry','','[]','岷山穹隆，岷水浺瀜。',150,'全唐诗/poet.song.218000.json','["岷山穹隆，岷水浺瀜。", "氣鬰葱葱，至和所鍾。", "秀毓臨邛，篤生英雄。", "綽有祖風，唐之鄭公。", "進思盡忠，王臣靡躬。", "萬壑奔洚，砥植在中。", "退思固窮，爲時儒宗。", "啟迪顓蒙，如金在鎔。", "王明泰通，虎嘯風從。", "入覲九重，天子改容。", "時謹邊烽，命公撫戎。", "大江西東，隠若長墉。", "甲兵藏胸，樽俎折衝。", "萬年之功，壽與天同。", "聊述鄙悰，以侑樂工。"]'),
('03166db3-17b1-40fd-84ba-b7e91f41b70c','挽想庵和尚','常挺','宋','宋诗','song-poetry','','[]','想庵住世大玲瓏，脫殻誰知脫屣同。',64,'全唐诗/poet.song.218000.json','["想庵住世大玲瓏，脫殻誰知脫屣同。", "現相維塵非是病，到頭法喜本真空。", "一塵頓滅靈臺上，萬劫都銷烈焰中。", "從此尺丘藏卵塔，白雲流水任西東。"]'),
('0aa55b11-9074-4487-990a-ef6c82f48bf8','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得漢字','常挺','宋','宋诗','song-poetry','','[]','慶元道學家，紫陽諸弟冠。',144,'全唐诗/poet.song.218000.json','["慶元道學家，紫陽諸弟冠。", "正印君得之，理窟講深貫。", "雄文摛玉堂，直筆插東觀。", "粹然中和容，清廟古珪瓚。", "遯翁上封事，猶或以蓍斷。", "君袖秋月章，直造紫皇案。", "赤手搏長鯨，未能分萬段。", "白華久無詩，清風可激頑。", "去身似葉輕，來事如麻亂。", "帝憂大江東，所至有水旱。", "列宿選郎闈，福星下霄漢。", "祇恐席未溫，宣室夜將半。"]'),
('0952b6b7-9f93-46a6-9ee4-bd33c34fe540','賀東道','常挺','宋','宋诗','song-poetry','','[]','隆暑赫炎曦，門弧慶左垂。',48,'全唐诗/poet.song.218000.json','["隆暑赫炎曦，門弧慶左垂。", "東君來出世，西斗降臨時。", "二子麒麟種，三孫鸑鷟兒。", "稱觴門下士，願祝壽期頤。"]'),
('845dea7d-d331-41f5-9ce9-c57ff574cd1b','釋奠詩','虞㠭','宋','宋诗','song-poetry','','[]','正學昭昭責力行，湖湘一派到于今。',64,'全唐诗/poet.song.218000.json','["正學昭昭責力行，湖湘一派到于今。", "好翻愚島詞鋒手，密察濂溪理窟心。", "二水秋清嚴奠禮，九疑雲近想韶音。", "詠歸也覺西風好，須信詩□在泮林。"]'),
('465d921b-adf1-4de6-8361-890d01677c2c','寶唐帖','虞㠭','宋','宋诗','song-poetry','','[]','□□□□未滿看，虛庭小飲勝憑闌。',64,'全唐诗/poet.song.218000.json','["□□□□未滿看，虛庭小飲勝憑闌。", "浮雲盡捲堂堂見，清影將圓處處歡。", "一點神光千里在，三秋佳景四並難。", "人生幾度逢今夕，更覺閒中天地寬。"]'),
('e8eb20a6-d8ea-42db-a36f-2139083a8df9','和知軍毛奎小洞天詩','王贊','宋','宋诗','song-poetry','','[]','使君賦佳什，筆壯過飛泉。',120,'全唐诗/poet.song.218000.json','["使君賦佳什，筆壯過飛泉。", "索遠尋幽地，求深訪洞天。", "山巍雲脚歛，海極日頭偏。", "景喜巖瞻石，臺虛釣隠船。", "高人貪勝概，清海頼無旋。", "擬把張槎泛，何妨謝屐穿。", "心閑塵不染，客好景成妍。", "去去迎三島，看看會七賢。", "醉眠思石枕，緩步惜苔錢。", "再約通宵飲，相邀秉燭椽。"]'),
('0c5da005-b2b2-4ea8-b0e3-5502fbd28f77','贈李崇義應童子科長歌','江湘','宋','宋诗','song-poetry','','[]','通經應童科，詩書尤所長。',288,'全唐诗/poet.song.218000.json','["通經應童科，詩書尤所長。", "生兒有如此，族黨真有光。", "五車舉舌端，觀者遶迴廊。", "嶄然露頭角，志氣何堅剛。", "七歲古所難，一目書五行。", "毋乃天帝孫，爲織雲錦裳。", "自覺我形穢，明珠在我傍。", "麟經究終始，猿臂射藝場。", "覆誦公堂上，時維十月陽。", "同僚發嗟嘆，喜子同舉觴。", "我非韓昌黎，墜緒尋茫茫。", "猶擬作一序，如送童子張。", "讀書宜閉門，不迎亦不將。", "六經漱芳潤，闇然名日彰。", "上書願鬻漢，負鼎期干湯。", "幼學欲壯行，少年非所當。", "細字綴語言，漏聲夜未央。", "短檠提案前，簾幕風露堂。", "博洽精經史，縱橫騖皇王。", "逢源欲深造，不息思自强。", "上必希賢聖，下期爲雋良。", "時乎時不再，夜氣毋牿亡。", "緬想唐宗室，姓名今馨香。", "長吉非凡流，勁詞摩穹蒼。"]'),
('63b15fb1-8b9b-4596-acb2-ffbf1083021b','南峰山','趙善正','宋','宋诗','song-poetry','','[]','山上青天山下溪，白雲流水兩相宜。',32,'全唐诗/poet.song.218000.json','["山上青天山下溪，白雲流水兩相宜。", "丹成共爾南山老，采采松枝亦療饑。"]'),
('40855e75-e3c6-4be2-bd1e-b384007d9fbc','遊雁山寄懷二弟','翁敏之','宋','宋诗','song-poetry','','[]','依棲崇儒里，咫尺鳥名山。',84,'全唐诗/poet.song.218000.json','["依棲崇儒里，咫尺鳥名山。", "奈以紅塵隔，因之舉步艱。", "穿花曉漏徹，何如桑者閑。", "廿載爲形役，今得拂衣還。", "自酌龍湫水，照映鬢毛斑。", "山靈應誚我，對之發赧顔。", "題彼雙脊令，飲啄就清灣。"]'),
('9fd9170d-d35b-48b3-8414-38d9f235841c','雲間','張藴','宋','宋诗','song-poetry','','[]','倦倚柁樓聞鶴唳，半生此地一經過。',64,'全唐诗/poet.song.218000.json','["倦倚柁樓聞鶴唳，半生此地一經過。", "機雲故月荒凉宅，湖海新秋浩蕩波。", "曉𦩘紅蓮商客市，夜窗白苧女兒歌。", "吟邊冷被沙鷗笑，衣化京塵鬢亦皤。"]'),
('80e2d903-7066-4636-8df9-1e22702432f6','江湖偉觀','張藴','宋','宋诗','song-poetry','','[]','隄柳朝朝送酒船，一闌山色越帆煙。',64,'全唐诗/poet.song.218000.json','["隄柳朝朝送酒船，一闌山色越帆煙。", "蓬萊雲氣東溟外，閶闔星辰北斗前。", "突兀向來無此屋，登臨當日有諸賢。", "夕陽過鴈慵回首，吟入關河萬里天。"]'),
('065ad01c-915c-4611-8b34-3f72f274d09d','鳳鶴鵲三題與江社同賦  其一','張藴','宋','宋诗','song-poetry','','[]','一去朝陽寂不聞，西康臺北起寒雲。',32,'全唐诗/poet.song.218000.json','["一去朝陽寂不聞，西康臺北起寒雲。", "梧花竹實年年事，柰此喧啾百鳥羣。"]'),
('e8b80dce-4fb2-4043-9b65-e48e9cd8556a','鳳鶴鵲三題與江社同賦  其二','張藴','宋','宋诗','song-poetry','','[]','立雪精神兩瘦蘆，天風入羽思江湖。',32,'全唐诗/poet.song.218000.json','["立雪精神兩瘦蘆，天風入羽思江湖。", "逋仙梅下曾相識，千載歸來一語無。"]'),
('663b8f43-30b6-47b0-94e8-2c8445fb35d7','鳳鶴鵲三題與江社同賦  其三','張藴','宋','宋诗','song-poetry','','[]','月樹爭枝影共寒，楂楂飛過屋頭山。',32,'全唐诗/poet.song.218000.json','["月樹爭枝影共寒，楂楂飛過屋頭山。", "五陵年少多春悶，一彈千金落等閑。"]'),
('3a577a2f-5459-4ba8-b4e9-2f4925e7598b','顧逕','張藴','宋','宋诗','song-poetry','','[]','海水還清淺，停杯問二豪。',48,'全唐诗/poet.song.218000.json','["海水還清淺，停杯問二豪。", "雨來江色暝，沙長岸容高。", "吏鞅何能脫，王程敢憚勞。", "秋風柁樓底，短髮不禁搔。"]'),
('66417aa3-9817-47ae-9fea-b96a62eca0f0','錢氏東皋','張藴','宋','宋诗','song-poetry','','[]','百年鍾鼓園林在，人物蕭疎更海鄉。',64,'全唐诗/poet.song.218000.json','["百年鍾鼓園林在，人物蕭疎更海鄉。", "藤絡湖嵌山解長，花移鄴本土猶香。", "棋聲靚晝松陰淡，扇影閒秋水氣長。", "莫道官忙行樂少，也分物色到奚囊。"]'),
('951976d6-ec73-4d88-b971-8690a4f542dd','上海','張藴','宋','宋诗','song-poetry','','[]','夢斷三更鶴，蘆邊繫短篷。',48,'全唐诗/poet.song.218000.json','["夢斷三更鶴，蘆邊繫短篷。", "聽潮看海月，坐石受天風。", "物至秋而化，年來我亦翁。", "長歌相勞事，猶喜此樽同。"]'),
('d929df7c-41b0-4015-8176-33d58c2de15d','新晴','張藴','宋','宋诗','song-poetry','','[]','林影熹微曉乍晴，老於世故獨關情。',64,'全唐诗/poet.song.218000.json','["林影熹微曉乍晴，老於世故獨關情。", "連烽未撤邊頭戍，積潦猶妨隴上耕。", "幾爲餉蠶憂濕葉，重因漂麥困饑萌。", "龍公多事多勞耳，萬理由來要得平。"]'),
('37a07ba4-398a-47e7-9791-08d05cf71eb3','錄錄','張藴','宋','宋诗','song-poetry','','[]','錄錄竟何爲，衣塵日以緇。',48,'全唐诗/poet.song.218000.json','["錄錄竟何爲，衣塵日以緇。", "故人閒入夢，久雨頗妨脾。", "燕履登巢息，蜂程載蜜虧。", "獨斟蓮子酒，愁絕杏花詩。"]'),
('8796be19-1f24-401e-ac82-b62d08a78947','除夕','張藴','宋','宋诗','song-poetry','','[]','京國逢除夕，栖遲鬢欲霜。',48,'全唐诗/poet.song.218000.json','["京國逢除夕，栖遲鬢欲霜。", "春聲生竹爆，歲色動椒香。", "戒睡聽鷄早，占詩探繭忙。", "燭花頻送喜，兒女笑烘堂。"]'),
('e3925a9b-bf0b-4b5d-bee2-d2e736a4049f','禱雪天竺由靈鷲過冷泉','張藴','宋','宋诗','song-poetry','','[]','降香天竺去，瀹茗冷泉來。',48,'全唐诗/poet.song.218000.json','["降香天竺去，瀹茗冷泉來。", "新徑石間過，危亭木杪開。", "煙山晴若畫，霜葉濕如灰。", "點檢經行處，今年未見梅。"]'),
('fbb6865b-b60c-4769-98eb-06c65540ffd6','祀事','張藴','宋','宋诗','song-poetry','','[]','誤被雞催起，隃聽漏鼓稀。',48,'全唐诗/poet.song.218000.json','["誤被雞催起，隃聽漏鼓稀。", "書檠風展卷，香碗火生衣。", "困嗅茶猶病，吟餐菊可肥。", "月明天路靚，親到帝旁歸。"]'),
('6879fb4b-c915-4ce7-a920-64ea02b7831c','西湖清明','張藴','宋','宋诗','song-poetry','','["\u897f\u6e56"]','芳天新霽惠風和，軟綠平隄凝不波。',64,'全唐诗/poet.song.218000.json','["芳天新霽惠風和，軟綠平隄凝不波。", "桃李無言看客慣，樓臺如畫占山多。", "游裾匝路填車馬，翠榜開筵鬭綺羅。", "寂寂寒煙生水面，白鷗柰此月明何。"]'),
('058cc50e-2057-4ae2-aa1a-c5f2f8bfca88','酥','張藴','宋','宋诗','song-poetry','','[]','兼味醍醐外，分身乳酪中。',48,'全唐诗/poet.song.218000.json','["兼味醍醐外，分身乳酪中。", "江南鳴穉犢，塞上寄飛鴻。", "乾雨看如幻，生鹽訝漸融。", "臈殘猶有待，煎取牡丹紅。"]'),
('e12d2472-5c96-495f-8435-231339ff8a92','食蠣次韻芸隠','張藴','宋','宋诗','song-poetry','','[]','相黏成什伯，峰聳若山王。',48,'全唐诗/poet.song.218000.json','["相黏成什伯，峰聳若山王。", "攻處須犀鐵，持來出蟹湯。", "梅花霜後味，竹色酒邊香。", "坐憶游閩樂，今年始得嘗。"]'),
('b128c5da-58ad-4c5c-9fef-b781f661b560','次韻月中聞鶴  其一','張藴','宋','宋诗','song-poetry','','[]','月明華表語霜清，萬籟沉沉靜有聲。',32,'全唐诗/poet.song.218000.json','["月明華表語霜清，萬籟沉沉靜有聲。", "一自別來璚樹長，幾回飛夢到曾城。"]'),
('d7b0ffdd-240a-4ba4-b2f4-1b0143279a95','次韻月中聞鶴  其二','張藴','宋','宋诗','song-poetry','','[]','孤影徘徊且月中，流離滿貯酒如空。',32,'全唐诗/poet.song.218000.json','["孤影徘徊且月中，流離滿貯酒如空。", "東皇太一應來下，笑指梅花一信通。"]'),
('b15f4763-f04d-4e1e-a395-8b84ac31b07b','齋宮偶題','張藴','宋','宋诗','song-poetry','','[]','衆綠扶疎雨氣清，柳花吹作小池萍。',32,'全唐诗/poet.song.218000.json','["衆綠扶疎雨氣清，柳花吹作小池萍。", "文窗晝寂齋房邃，三漱華池誦玉經。"]'),
('e10faf5c-800e-4063-a4bf-6e4360daaf40','同寮約游香林分韻得林字','張藴','宋','宋诗','song-poetry','','[]','約我當休沐，同過支道林。',48,'全唐诗/poet.song.218000.json','["約我當休沐，同過支道林。", "棋邊翻覆手，酒外太平心。", "石漱晴湍細，猿吟夏木深。", "歸帆带疎雨，凉意滿幽襟。"]'),
('f375c257-6437-4b37-bf4d-a7cad3c442bd','春朝偶題','張藴','宋','宋诗','song-poetry','','[]','忙裏偷閒答物華，一官隨分是生涯。',64,'全唐诗/poet.song.218000.json','["忙裏偷閒答物華，一官隨分是生涯。", "春風酒棹湖隄柳，曉月吟韉輦路花。", "報喜忽聞枝上鵲，忘機時下屋頭鴉。", "殘年鈍悶今朝盡，重對菱花拂帽紗。"]'),
('33215c4d-e318-49e9-a3ef-d0aeacf06bd7','重游大滌洞天','張藴','宋','宋诗','song-poetry','','[]','澗水泠泠石髮新，松花香靚翠崖深。',64,'全唐诗/poet.song.218000.json','["澗水泠泠石髮新，松花香靚翠崖深。", "雲生不沒仙人跡，丹化猶啼搗藥禽。", "洗眼人多求聖水，醒心吾獨愛清音。", "杖藜更欲過新洞，無柰春空又作陰。"]'),
('759e8256-3dda-468f-8426-0f11d70b25c2','東庵與道者語有感','張藴','宋','宋诗','song-poetry','','[]','瘦策松間日又斜，更過東崦喫僧茶。',64,'全唐诗/poet.song.218000.json','["瘦策松間日又斜，更過東崦喫僧茶。", "丹青嶺樹明寒葉，水墨江天噪亂鴉。", "付酒一杯真樂事，讀書萬卷是愁涯。", "更嘗世故知閒味，河水依然鬢自華。"]'),
('61168c1e-3f91-4ad8-ae9c-9abcd6e847e8','朱柿','張藴','宋','宋诗','song-poetry','','[]','慈恩分種遠，駢實渥如丹。',48,'全唐诗/poet.song.218000.json','["慈恩分種遠，駢實渥如丹。", "垂野華星大，然雲火樹寒。", "蟹螯徵有忌，狌血訝難摶。", "七絕雖堪賞，無勞把核鑽。"]'),
('e8b0ba93-06ce-4c3f-b789-0d5004f7d373','喜李鶴田至次阮雲心韻兼寄  其一','張藴','宋','宋诗','song-poetry','','[]','月樹秋來碧幾尋，古薌熏徹紫芝吟。',32,'全唐诗/poet.song.218000.json','["月樹秋來碧幾尋，古薌熏徹紫芝吟。", "無因得去陪清賞，祇寄山君一寸心。"]'),
('2f498d56-9454-4f9d-a5f8-52addc7c6c67','喜李鶴田至次阮雲心韻兼寄  其二','張藴','宋','宋诗','song-poetry','','[]','澆酒逋梅又幾回，愁吟舊雨獨登臺。',32,'全唐诗/poet.song.218000.json','["澆酒逋梅又幾回，愁吟舊雨獨登臺。", "星星鶴語山窗曉，割得雲心古錦來。"]'),
('649cb3d8-b3ca-4458-a147-5baecf94ae6f','九日','張藴','宋','宋诗','song-poetry','','[]','細看黄花把一枝，東籬猶是昔人非。',64,'全唐诗/poet.song.218000.json','["細看黄花把一枝，東籬猶是昔人非。", "題糕酒外豪心在，吹帽風前素髮稀。", "鴈叫霜天悲故國，鴉翻溪樹背寒暉。", "百年獨有閒居樂，可怪東山事竟違。"]'),
('9167622d-0d4d-4785-89dc-17a7e6734455','道場山','張藴','宋','宋诗','song-poetry','','["\u592a\u6e56"]','訪碑無古迹，丹碧覆嵯峨。',48,'全唐诗/poet.song.218000.json','["訪碑無古迹，丹碧覆嵯峨。", "塔向城中共，山從寺右多。", "疎松小溪路，遠漊太湖波。", "何鍇書堂在，猶嫌隔翠蘿。"]'),
('619de9d2-1913-405a-a916-24086376ad38','何山','張藴','宋','宋诗','song-poetry','','[]','山因人得姓，人去佛來居。',48,'全唐诗/poet.song.218000.json','["山因人得姓，人去佛來居。", "鄰有天章墓，碑無玉局書。", "幽蹊通古郭，荒磵入春畬。", "客子吟鬚冷，高峰夕照餘。"]'),
('03fdd0cf-9d62-44bc-9e6a-eef50270c21b','月泉紀游','張藴','宋','宋诗','song-poetry','','[]','小春霜宇曉，閒訪古招提。',84,'全唐诗/poet.song.218000.json','["小春霜宇曉，閒訪古招提。", "何歲齋魚廢，初弦顧兔迷。", "先民堂上像，寓客柱間題。", "僧戶蜂分小，山形虎穴低。", "松青江廟北，竹老野橋西。", "親汲聊煎茗，深登信杖藜。", "琴師年九十，相見手重携。"]'),
('283b3ee1-0190-4030-8361-8ce1b28b7aae','不寐','張藴','宋','宋诗','song-poetry','','[]','空牀展轉對孤檠，寒漏年長更雨聲。',32,'全唐诗/poet.song.218000.json','["空牀展轉對孤檠，寒漏年長更雨聲。", "如此乾坤閒歲月，明朝華髮滿頭生。"]'),
('c59cb9a1-a38c-4a74-bcc1-a9a4d4d60a5d','寄鶴田','張藴','宋','宋诗','song-poetry','','[]','鶴向孤山去未歸，片雲行鴈與心期。',32,'全唐诗/poet.song.218000.json','["鶴向孤山去未歸，片雲行鴈與心期。", "新詩不著工夫得，雪外看花獨立時。"]'),
('61ff7642-77ca-4308-84e0-22ceb2332197','至後','張藴','宋','宋诗','song-poetry','','[]','陽生七日驗飛葭，衮衮天機歲載華。',32,'全唐诗/poet.song.218000.json','["陽生七日驗飛葭，衮衮天機歲載華。", "江草未圓青帝夢，香芸漏洩與梅花。"]'),
('6eebc392-715e-4e17-89bd-ca90d4acc0f9','霅川次韻鶴田','張藴','宋','宋诗','song-poetry','','[]','苕霅雙流合，帆檣萬里通。',48,'全唐诗/poet.song.218000.json','["苕霅雙流合，帆檣萬里通。", "連山黄獨雪，一鴈白蘋風。", "酒戶春醅淺，魚村晚市同。", "舊游蕉鹿外，未老已成翁。"]'),
('ab055eac-6404-4c33-9007-65b1c4039b6e','歲晏用趙誼父訪雲心韻以寄','張藴','宋','宋诗','song-poetry','','[]','看春知幾度，玄髮故應非。',48,'全唐诗/poet.song.218000.json','["看春知幾度，玄髮故應非。", "世事真猶夢，人生瘦勝肥。", "竹邊隨意入，梅下得詩歸。", "緬想羊何友，湖山樂所依。"]'),
('afd1d0f7-9c3d-4884-b406-3e8c011a5778','正月二日雪','張藴','宋','宋诗','song-poetry','','[]','雨送冬雷了，如簁墮曉晴。',48,'全唐诗/poet.song.218000.json','["雨送冬雷了，如簁墮曉晴。", "縈盈溪樹色，騷殺紙窗聲。", "著瓦消還易，因風凍不成。", "紛紛門外屨，猶自賀元正。"]'),
('ffa3f82e-7611-4768-ae1e-19ec7e3db0c6','送晏桂山赴高沙郡  其一','張藴','宋','宋诗','song-poetry','','[]','青衫赴闕已三遷，紅旆臨州不五年。',64,'全唐诗/poet.song.218000.json','["青衫赴闕已三遷，紅旆臨州不五年。", "舊吏侉榮從事府，新民迎擁使君韉。", "牡丹池館春融日，蒓葉汀洲水漲天。", "自是邊籌談笑辦，歸來仍侍玉皇前。"]'),
('f0cabbe5-24d2-4465-bd91-1fd6f8ce0217','送晏桂山赴高沙郡  其二','張藴','宋','宋诗','song-poetry','','[]','接武容臺彼一時，溪鄉重幸得追隨。',64,'全唐诗/poet.song.218000.json','["接武容臺彼一時，溪鄉重幸得追隨。", "鷗前心事滄浪影，梅下吟情汗漫期。", "感慨中年無近別，徘徊明月有相思。", "殷勤勸醉陽關曉，受盡耶歈只自知。"]'),
('724d51c2-3548-4f11-9760-ef75d29e179d','秋思','張藴','宋','宋诗','song-poetry','','[]','暑退凉生體氣佳，卷簾聽雨感年華。',32,'全唐诗/poet.song.218000.json','["暑退凉生體氣佳，卷簾聽雨感年華。", "西風葉葉梧桐冷，開盡庭前白鶴花。"]'),
('41225d28-88a9-40b5-9381-73ad8e92b295','溪上','張藴','宋','宋诗','song-poetry','','[]','今夕知何夕，吾意亦良適。',108,'全唐诗/poet.song.218000.json','["今夕知何夕，吾意亦良適。", "明月滿船蓬，清風動帷席。", "過雨前溪渾，停雲半空白。", "衰荷無嬌紅，老梧有枯碧。", "頻更燭對棋，仍把酒澆石。", "歲行變暄凉，朋情慨離索。", "相思日以長，孤吟夜方寂。", "露下客衣單，草際螢光奕。", "年年脩玩心，一醉不得惜。"]'),
('5a87c29a-e870-449e-a0eb-41fecba69eda','鶴田還江右','張藴','宋','宋诗','song-poetry','','[]','欲留雲共住，雲去楚天長。',48,'全唐诗/poet.song.218000.json','["欲留雲共住，雲去楚天長。", "此日吾猶惜，中年別易傷。", "搜吟梅下影，賭弈橘中香。", "謹勿移山諾，春風入帝鄉。"]'),
('03fb3216-3ebd-4eb5-a7d5-3e0ee2b33ebe','歸鴈亭','張藴','宋','宋诗','song-poetry','','[]','青雲影裏自由身，幾倚闌干看不真。',32,'全唐诗/poet.song.218000.json','["青雲影裏自由身，幾倚闌干看不真。", "又是江湖春雪盡，年年腸斷玉關人。"]'),
('3d4658c7-fcfb-4fea-9649-406d2086c8ba','午日次韻池襲父','張藴','宋','宋诗','song-poetry','','[]','小泊蘋香柳下磯，重逢佳節感年時。',64,'全唐诗/poet.song.218000.json','["小泊蘋香柳下磯，重逢佳節感年時。", "束蒿偶作人形想，采藥須供國手醫。", "江鏡願爲明主監，楚菰愁賦逐臣詞。", "酒邊聽盡敲篷雨，數日淮南去未遲。"]'),
('b1b5a942-5116-42b2-9278-c629c4e4d309','垂虹  其一','張藴','宋','宋诗','song-poetry','','[]','四岸俱無只有天，烟檣如雨落鷗前。',32,'全唐诗/poet.song.218000.json','["四岸俱無只有天，烟檣如雨落鷗前。", "不知笠澤翁何許，波上清風一萬年。"]'),
('ad1a2139-5e66-4390-92d1-3a2810392d03','垂虹  其二','張藴','宋','宋诗','song-poetry','','[]','憶著前游十四年，三高祠下夕陽船。',32,'全唐诗/poet.song.218000.json','["憶著前游十四年，三高祠下夕陽船。", "無錢買得鱸魚鱠，吟就橘花香裏眠。"]'),
('6f0c68cd-9483-4dbb-b5f6-910a72adb795','姑蘇臺','張藴','宋','宋诗','song-poetry','','[]','故址耕殘草樹秋，無人曾見鹿來游。',32,'全唐诗/poet.song.218000.json','["故址耕殘草樹秋，無人曾見鹿來游。", "甬東亦是當時月，不照笙歌只照愁。"]'),
('50c1111b-4f76-4a0d-b892-8bbff561f95a','虎丘','張藴','宋','宋诗','song-poetry','','[]','曼陀石上無根樹，歷歷生公說法餘。',32,'全唐诗/poet.song.218000.json','["曼陀石上無根樹，歷歷生公說法餘。", "劍水一泓清澈底，至今人說有龍居。"]'),
('7fdba9b5-1b84-4484-a511-fa0f9210a22f','惠山','張藴','宋','宋诗','song-poetry','','[]','石苔滑汰屋連斜，第二泉邊古佛家。',32,'全唐诗/poet.song.218000.json','["石苔滑汰屋連斜，第二泉邊古佛家。", "一壑松風聽不了，却留僧坐自煎茶。"]'),
('310e95a1-5af7-4d43-9997-aa7dc11597ec','楝花','張藴','宋','宋诗','song-poetry','','[]','綠樹菲菲紫白香，猶堪纏黍吊沉湘。',32,'全唐诗/poet.song.218000.json','["綠樹菲菲紫白香，猶堪纏黍吊沉湘。", "江南四月無風訊，青草前頭蝶思狂。"]'),
('1df359ab-3ba6-4e17-b2a5-b3552d1ad3df','毗陵天慶觀龍','張藴','宋','宋诗','song-poetry','','[]','殿陰壁老懷仁筆，頭角崢嶸春起蟄。',32,'全唐诗/poet.song.218000.json','["殿陰壁老懷仁筆，頭角崢嶸春起蟄。", "有時麾斥惠山雲，行雨歸來半身濕。"]'),
('88363c45-a695-4ff3-aef2-8a52479455d2','丹陽道中流寓人','張藴','宋','宋诗','song-poetry','','[]','累土編茅古制庳，官田種秫得沽私。',32,'全唐诗/poet.song.218000.json','["累土編茅古制庳，官田種秫得沽私。", "自言身健無徭役，猶勝平生江北時。"]'),
('3ba7f13e-3930-4856-b1ba-1b182eae83ef','京口運河上','張藴','宋','宋诗','song-poetry','','[]','荒荒永岸水如溝，翁仲無言立上頭。',32,'全唐诗/poet.song.218000.json','["荒荒永岸水如溝，翁仲無言立上頭。", "日日餫舟銜尾去，東南民力尚支不。"]'),
('20d7189a-f7be-484a-a259-2a9fbe539a61','多景樓','張藴','宋','宋诗','song-poetry','','[]','假日此登臨，淒涼北望心。',48,'全唐诗/poet.song.218000.json','["假日此登臨，淒涼北望心。", "戍烽孤障杳，塔影一江深。", "黠虜投鞭想，將軍誓檝吟。", "所嗟人事異，天險古猶今。"]'),
('c344efbe-9e83-415a-b5b6-bd5eecb62858','金山','張藴','宋','宋诗','song-poetry','','[]','江身臺殿切空雲，夜月魚龍影不分。',32,'全唐诗/poet.song.218000.json','["江身臺殿切空雲，夜月魚龍影不分。", "八十老僧相引說，潮痕不上郭公墳。"]'),
('c53e35d1-821f-4258-93ec-3d02510352ee','瓜洲','張藴','宋','宋诗','song-poetry','','[]','如此江濤更有人，佛狸竟死不能兵。',32,'全唐诗/poet.song.218000.json','["如此江濤更有人，佛狸竟死不能兵。", "幅巾短櫂鷗前夢，未省當時有此城。"]'),
('2c973375-ec3e-426b-9149-59dc98a87e6e','維揚即事  其一','張藴','宋','宋诗','song-poetry','','[]','牛斗星邊禹貢州，東南屏蔽大江流。',32,'全唐诗/poet.song.218000.json','["牛斗星邊禹貢州，東南屏蔽大江流。", "向來明月珠簾夢，不信秋風夜柝愁。"]'),
('ad1ee2de-1137-4301-aa88-1d304d879592','維揚即事  其二','張藴','宋','宋诗','song-poetry','','[]','皂角林前野地寬，新塘路口草泥乾。',32,'全唐诗/poet.song.218000.json','["皂角林前野地寬，新塘路口草泥乾。", "天乎如此功名事，成敗觀人自昔難。"]'),
('a2f7af1c-98cf-4938-b64d-e042845ec064','維揚即事  其三','張藴','宋','宋诗','song-poetry','','[]','茅屋蘆門半市坊，居民無事亦軍裝。',32,'全唐诗/poet.song.218000.json','["茅屋蘆門半市坊，居民無事亦軍裝。", "愁來莫上城頭望，西北浮雲接太陽。"]'),
('582e3a77-8cb5-483d-8af0-ef7889ce8004','維揚即事  其四','張藴','宋','宋诗','song-poetry','','[]','月明城上響邊笳，一枕三更夢到家。',32,'全唐诗/poet.song.218000.json','["月明城上響邊笳，一枕三更夢到家。", "不耐楚氛真僻性，賦詩酌酒與瓊花。"]'),
('0a434061-eb88-4af1-a428-04d026cf2c94','維揚即事  其五','張藴','宋','宋诗','song-poetry','','[]','土霧如蒸暴暑天，燭龍偏駐柳邊船。',32,'全唐诗/poet.song.218000.json','["土霧如蒸暴暑天，燭龍偏駐柳邊船。", "三清觀裏風廊午，滿意題詩借榻眠。"]'),
('a9ee001c-3335-4ea9-b6fc-9be710442be9','平山堂吊古','張藴','宋','宋诗','song-poetry','','[]','隔江山色畫圖中，故址荒來與廟通。',64,'全唐诗/poet.song.218000.json','["隔江山色畫圖中，故址荒來與廟通。", "畫地雄吞淮海水，占星高直斗牛宮。", "試評蜀味長泉變，欲唱歐詞古柳空。", "往事茫茫增感慨，聊憑戍卒指西東。"]'),
('786c3612-cdb4-46b8-a191-b22db9f718ce','平山和韻鶴田','張藴','宋','宋诗','song-poetry','','[]','瓊花應自笑南翁，白髮栖栖逐斷蓬。',64,'全唐诗/poet.song.218000.json','["瓊花應自笑南翁，白髮栖栖逐斷蓬。", "兵後百年城郭是，塵間多事古今同。", "孤烟遠堠如常夜，五月窮邊尚冷風。", "可待蒓鱸歸興盡，長吟且復付杯中。"]'),
('a43a1c16-f415-492b-a9ff-7c4c9cc30506','道中觀戽水戲書','張藴','宋','宋诗','song-poetry','','[]','秧馬泥深繭犢閒，燭龍顧影桔槔間。',32,'全唐诗/poet.song.218000.json','["秧馬泥深繭犢閒，燭龍顧影桔槔間。", "尋常六月江南雨，不比君王帑藏慳。"]'),
('b2763ce8-ca4a-4ff7-9a86-a874d298f555','翠蛟亭','張藴','宋','宋诗','song-poetry','','[]','道人鎖蛟天柱半，客來縱蛟作奇觀。',88,'全唐诗/poet.song.218000.json','["道人鎖蛟天柱半，客來縱蛟作奇觀。", "飛風動地輷晴雷，雄拏怒攫石欲開。", "明珠萬斛撒成雨，忽趁流雲入銀浦。", "仙田種玉耕春煙，潤流九里無凶年。", "問蛟蜚去何時還，道人仰笑意自閒。", "月中携手聽潺湲。"]'),
('b3d734a6-a168-4e93-9527-8ffee22d2088','翠蛟亭呈孫元素鍊師','張藴','宋','宋诗','song-poetry','','[]','剡剡星虹白日寒，山香一曲落雲端。',32,'全唐诗/poet.song.218000.json','["剡剡星虹白日寒，山香一曲落雲端。", "乘虬道士排空去，怒雨聲摇碧玉巒。"]'),
('5c88c840-e8c7-4528-bd31-8735082da310','施巖','周坦','宋','宋诗','song-poetry','','[]','人烟斷處逢仙跡，草木深時聽鳥悲。',32,'全唐诗/poet.song.218000.json','["人烟斷處逢仙跡，草木深時聽鳥悲。", "記取畫工描一幅，出山長若在山時。"]'),
('f7650cda-8a1f-40b0-8c53-8a06db35e9de','遊丹山','孫嚞','宋','宋诗','song-poetry','','[]','與客窮幽勝，同登白水山。',48,'全唐诗/poet.song.218000.json','["與客窮幽勝，同登白水山。", "銀濤翻月落，蒼壁倚天寒。", "采藥穿雲塢，圍棋坐石壇。", "因忘歸路晚，紉佩得秋蘭。"]'),
('dd0802f7-dc66-4f53-8e43-530be529dc16','酬汪將軍携遊白雲寺','孫嚞','宋','宋诗','song-poetry','','[]','將軍恒愛客，載酒喜行遊。',48,'全唐诗/poet.song.218000.json','["將軍恒愛客，載酒喜行遊。", "山殿晴雲浴，天香靜磬浮。", "嘉蓮艷寶水，甘露降靈楸。", "徵古一爲瑞，清修思更幽。"]'),
('3deb7071-17b3-42a8-bd59-75ce04b37347','窄嶺','盧方春','宋','宋诗','song-poetry','','[]','危嶺惡有名，窄嶺險無數。',132,'全唐诗/poet.song.218000.json','["危嶺惡有名，窄嶺險無數。", "石鼻卷我車，石牙隠我步。", "空岡蟲九頭，黑身眼四顧。", "擲之聲愈厲，飛前使人怖。", "想當開闢時，已是樵獵路。", "茅臭不成山，瀑斷不成布。", "丫巖升惡猿，蹄涔立饑鷺。", "蘆花大如錢，况乃時寒沍。", "遐征誤假道，撫景自作恕。", "林壑非出倫，筆硯不入務。", "脚怠宿未投，天低日俄暮。"]'),
('8eddbebd-7530-4bcf-b9a1-62eabb49b32a','陟駝巘','盧方春','宋','宋诗','song-poetry','','[]','雨凉陟駝巘，轉歷九十折。',108,'全唐诗/poet.song.218000.json','["雨凉陟駝巘，轉歷九十折。", "短竹亦自陰，小家亦自潔。", "尋草補斷蹊，行人以旱說。", "農哭眼睛落，天懶霹靂歇。", "斯民謂天懶，對此予心熱。", "憑高覽清曠，一峰一氣結。", "峰下桔槔人，踏水脚如血。", "短短赤赤秧，專供毒蝗舌。", "太息重凝眸，青青天骨出。"]'),
('86bffdd1-c1b7-4394-85fb-686c0553eae3','蓮塘','盧方春','宋','宋诗','song-poetry','','[]','蓮塘有清氣，永夜南窗開。',48,'全唐诗/poet.song.218000.json','["蓮塘有清氣，永夜南窗開。", "引滴不待瓢，折筩爲酒杯。", "飲罷坐閒石，林杪風徐來。", "仰天忽大笑，微吟行綠苔。"]'),
('96599309-daf8-4133-9a67-e109925b5927','寄趙東閣','盧方春','宋','宋诗','song-poetry','','[]','棧閣傳鈴夜已深，下方方沸管絃音。',64,'全唐诗/poet.song.218000.json','["棧閣傳鈴夜已深，下方方沸管絃音。", "霜飛初氣侵清坐，月耿斜暉促苦吟。", "蓍草只知浮世事，燈花難說隠人心。", "依然流水高山意，我欲從之學鼓琴。"]'),
('13e5d366-c6e8-40dd-88c6-867d0706a89e','送陸侍御歸越','盧方春','宋','宋诗','song-poetry','','[]','喈喈風雨餘，出晝意何如。',48,'全唐诗/poet.song.218000.json','["喈喈風雨餘，出晝意何如。", "鏡裏無慙色，囊中有諫書。", "寒崖立松柏，清廟失璠璵。", "海內看霜月，光明只似初。"]'),
('836bea9b-1aa8-4d5a-ae96-afcbf61d017b','趙幾道處見趙端行所作','盧方春','宋','宋诗','song-poetry','','[]','新詩奪我目瞳光，哦出松根琥珀香。',64,'全唐诗/poet.song.218000.json','["新詩奪我目瞳光，哦出松根琥珀香。", "李白未題芸草署，郄詵重入桂花鄉。", "遠天閴寂無雷電，南地清凉有雪霜。", "欲到琴□先謁府，滿城清嶂照斜陽。"]'),
('ffa41fe4-62d2-455a-977b-1efe03d94e52','水雲園池','盧方春','宋','宋诗','song-poetry','','[]','貪山上水樓，一望一層秋。',48,'全唐诗/poet.song.218000.json','["貪山上水樓，一望一層秋。", "幽抱發朗詠，驚飛雙白鷗。", "斯文今寂寞，諸老舊風流。", "漁者亦樂此，扣舷清夜游。"]'),
('3eced271-4100-402b-be44-e0f8e8b5bcae','賀墅','岑全','宋','宋诗','song-poetry','','[]','荒村車馬驚鸞鶴，散騎茅堂見杜蘭。',32,'全唐诗/poet.song.218000.json','["荒村車馬驚鸞鶴，散騎茅堂見杜蘭。", "冰玉自甘山水味，慢勞甲第賜長安。"]'),
('2ec162ff-87f1-49dc-af6b-a9344ce8f3e4','獅子巖','繆烈','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','幽巖蕭颯商飈起，一天灝氣涼如水。',128,'全唐诗/poet.song.218000.json','["幽巖蕭颯商飈起，一天灝氣涼如水。", "金井梧飛蘭谷芳，長江浪冷蓴魚美。", "雁字半側銀鈎欹，雲光凈掃光陸離。", "桂花巖下香滿枝，隨意催送到書帷。", "碧潭煙歛琉璃滑，素娥乘鸞下天闕。", "清暉深射水晶宮，虛明澄澈蛟龍窟。", "上下天光一鏡浮，冰輪碾破一天秋。", "今來古往事悠悠，月自升沈水自流。"]'),
('94fe75fe-b284-4b35-baba-9ff06754f6ea','過城南梅庵追憶湖守宋使君叔晦','鄭玠','宋','宋诗','song-poetry','','[]','重過梅庵不記春，花殘樹老綠陰成。',64,'全唐诗/poet.song.218000.json','["重過梅庵不記春，花殘樹老綠陰成。", "開元宰相腸應斷，楚國騷人魄尚清。", "古屋參差疏影動，水池深淺宿枝橫。", "主人祗在雲深處，弄月吟風取次行。"]'),
('d492e2e6-d800-4526-bb9c-ddb73d624c67','憶鄉歌四首  其一','馮夢得','宋','宋诗','song-poetry','','[]','儂是劍南人，慣識故鄉好。',24,'全唐诗/poet.song.218000.json','["儂是劍南人，慣識故鄉好。", "綠葉接紅花，輝映綏安道。"]'),
('f0c37c53-911d-45c4-b9b1-2f51eca4efd3','憶鄉歌四首  其二','馮夢得','宋','宋诗','song-poetry','','[]','炎夏天頗熱，儂門對溪住。',24,'全唐诗/poet.song.218000.json','["炎夏天頗熱，儂門對溪住。", "摇蕩採蓮舟，深處疑風露。"]'),
('7c4d11d0-21cc-49f3-a53c-abb80dc59338','憶鄉歌四首  其三','馮夢得','宋','宋诗','song-poetry','','[]','塞上秋始肅，野草葉葉黄。',24,'全唐诗/poet.song.218000.json','["塞上秋始肅，野草葉葉黄。", "儂家有菊花，灼灼不憂霜。"]'),
('2916f199-85de-42f4-98eb-6f4aad22ebdc','憶鄉歌四首  其四','馮夢得','宋','宋诗','song-poetry','','[]','塞北寒氣逼，對火擁氍毹。',24,'全唐诗/poet.song.218000.json','["塞北寒氣逼，對火擁氍毹。", "猶憶儂家裏，蓬頭兩夾襦。"]'),
('7d70547c-2955-470e-b4f4-b1e6304e8f2f','鳳皇臺','倪垕','宋','宋诗','song-poetry','','[]','鳳皇鳳皇幾千載，鳳皇已去臺空在。',96,'全唐诗/poet.song.218000.json','["鳳皇鳳皇幾千載，鳳皇已去臺空在。", "應多燕雀語畫梁，瞥見蛟龍起滄海。", "二十年前曾來游，野田白鷺涵清秋。", "今夕何夕領賓客，飯盂有飯思貔貅。", "六朝故國金陵道，柳外閑愁仗誰掃。", "掀髯一笑問西風，未必江山知我老。"]'),
('e591ec33-d6d3-4b6f-8bb5-d721bb6d9912','寄立齋二首  其一','戴良齊','宋','宋诗','song-poetry','','[]','玄雲太山阿，倏忽起天際。',72,'全唐诗/poet.song.218000.json','["玄雲太山阿，倏忽起天際。", "悠哉復何心，適與飄風會。", "雲間翔虬螭，蜿蟺炫五彩。", "萬生方顒顒，豈但千里內。", "吾鄉作者幾，俯仰既千載。", "願言慰斯人，名實施四海。"]'),
('f748fe8e-6326-4901-ac6b-012a36922dca','寄立齋二首  其二','戴良齊','宋','宋诗','song-poetry','','[]','蜚鴻時以南，蜚鴻時以北。',72,'全唐诗/poet.song.218000.json','["蜚鴻時以南，蜚鴻時以北。", "翻翻堂上燕，來往逝安適。", "秋聲來九天，星漢浩無極。", "巖巖北有斗，可望不可即。", "極望勞我心，夢想三太息。", "下有縱壑鱗，上有飛雲翼。"]'),
('98835a27-9232-492c-83e9-8707ac152c25','夜坐觀星','戴良齊','宋','宋诗','song-poetry','','[]','中夜不能旦，浩蕩思無期。',72,'全唐诗/poet.song.218000.json','["中夜不能旦，浩蕩思無期。", "茫茫宇宙間，俯仰伊何時。", "起坐憑前欄，粲粲天南垂。", "寒芒燭辰尾，歲德何所司。", "耿耿獨無寐，坐觀樞輪移。", "更籌忽五唱，空中聞子規。"]'),
('f225de5c-2b33-4016-ab3b-ebfb29999c13','批趙氏卷','羅壵','宋','宋诗','song-poetry','','[]','汗牛試卷浩無涯，剗盡雷同別一家。',64,'全唐诗/poet.song.218000.json','["汗牛試卷浩無涯，剗盡雷同別一家。", "冰鑑不容心潦草，風簷寧復眼昏花。", "嘉文似織鮫人組，健筆如輪虎士撾。", "收拾真才報天子，此行端不負皇華。"]'),
('12d6fb2a-bdd6-4961-bcd9-06f42122deb1','和王教暮春出遊','戴埴','宋','宋诗','song-poetry','','[]','矯矯雪霜心，孤貞受命獨。',288,'全唐诗/poet.song.218000.json','["矯矯雪霜心，孤貞受命獨。", "留滯染緇塵，垢面不靧沐。", "背城借一戰，填塹輸前瀆。", "葵心向朝陽，晞光不能燠。", "徒囂終無贏，驅馳惟僕僕。", "豈無豐水滋，永嗟非佳穀。", "呼爾授芻秣，羈紲繫駒犢。", "堪羨我良朋，林桂賸芳馥。", "博覽繹故書，胸中三萬軸。", "悠然西河上，日與英俊逐。", "振鐸揚儒風，函丈紛冠服。", "師友遞響答，循誘教匪扑。", "精進日千里，目駭地脈縮。", "顧我闕黨徒，無成坐欲速。", "披襟莫奮飛，隨羣被私淑。", "枵然藜莧腸，殊未飽公餗。", "彈鋏何時歸，涎沫流肌肉。", "遥想烹太牢，殷勤羹采菽。", "更當春暮時，浴沂衿佩肅。", "心賞弄篇章，絕唱清風穆。", "流水諧朱弦，押强破萬竹。", "孝先謾耐嘲，橫榻便空腹。", "安識物外遊，幽賞機緣熟。", "矧復有良儔，堅久渝晚菊。"]'),
('a76655a7-688f-4cb8-83dd-9260afb30fe1','輦下曲','戴埴','宋','宋诗','song-poetry','','[]','舊來聞說京師樂，香街十里春風箔。',226,'全唐诗/poet.song.218000.json','["舊來聞說京師樂，香街十里春風箔。", "朝踏金梯入鳳樓，暮下瓊鉤延翠幄。", "蛾綠梅花裝，淑質蘭蕙芳。", "笙歌棗下曲，琵琶陌上桑。", "宿酲未解鶑催曉，玉珂策馬長安道。", "解珮遺簪日日歡，不覺紅顔醉中老。", "我謂京國皆繁華，何時飛走登雲車。", "誰知著足緇塵底，八年飄泊空咨嗟。", "蕭蕭竹窗風暗度，耿耿蘭缸燈自語。", "孤坐逢掖凝清霜，獨卧重衾踏寒雨。", "雲雨陽臺夢不成，況欲綺席羅傾城。", "丈人屋上烏啼夜，乾鵲巢中鳩喚晴。", "啼夜夜未央，娟娟素月明。", "喚晴晴未霽，寂寂青春深。", "鳩喚烏啼終有侶，猶勝月兔孀居千萬春。"]'),
('d334cd19-4775-428f-91fd-74dca78b8509','雹','戴埴','宋','宋诗','song-poetry','','[]','玄黓執徐歲，月律終無射。',438,'全唐诗/poet.song.218000.json','["玄黓執徐歲，月律終無射。", "京師連雨雹，小者如彈，大者如拳。", "林柯葉亂下，烏鳶折飛翮。", "屋瓦砉劃遭擊撲，居人顛沛，行道錯愕。", "初疑巨颶掀捲馮夷宮，淵珍散墮光閃爍。", "復疑清霄萬里驅長蛟，泣淚盈盈驟飄薄。", "稜層水精碎，噴噀珠琲滑。", "有識覷天巧，一何景象惡。", "嘗聞聖人在上冬夏無愆伏，亭毒二氣不相剝。", "破塊封條已無異，祉羽無勞驗風角。", "今天子握極衡，運斗樞，景化豫順，羣慝蕭灼。", "精祲胡未孚，冰雨墮霄幕。", "其欲霈廣澤，胡不爲甘霖，沾丐枯焦重甲拆。", "其欲膏土脈，胡不爲晞薤，厭浥瀼瀼普漸洽。", "其欲表誅伐，胡不爲皚𩅀，駟見而霣，草木黄落。", "其欲弭蟄蟲、滋生植，胡不爲嘉平之三白，驅蝗入地千百尺。", "或云水氣專一不解散，胡不爲長河玉岸之寒冰，可納凌室助頒刷。", "或云陰氣脅陽不相入，胡不爲氤氳五色之卿靄，叶應豐穰昭帝德。", "此雹舒不如雨露，慘不如霜雪，結不如冰澌之嚴沍，散不如雲霧之葱鬰。", "天非欲示懲，詎用作戲劇。", "漢儒說證應，紛紛太不一。", "或賢邪易位，或賦斂苛刻，或妻妾失倫，或大臣擅法。", "玄道幽且渺，牽附多穿鑿。", "仲尼百世師，麟經戒侵逼。"]'),
('12e1c5bc-825a-4adf-8667-38ceb3b08480','彗星','戴埴','宋','宋诗','song-poetry','','[]','紹定壬辰閏九月，己酉之夜彗星出。',352,'全唐诗/poet.song.218000.json','["紹定壬辰閏九月，己酉之夜彗星出。", "清臺奏御，正衙避席。", "太官減膳羞，瞽宗徹音樂。", "雞竿肆眚出囚繫，龍扆責躬求讜直。", "精誠徹九垓，德音走重譯。", "圜橋冠带虀鹽生，筦窺熿熿對以臆。", "臣聞泰素朕形，玄黄辨色。", "左旋右轉，一闔一闢。", "來伸往屈四時行，除舊布新寒暑易。", "恢恢天網疎，統理廢厥職。", "東方歲星木主仁，不掃暴刻尚搥剝。", "南方熒惑火主禮，不掃驕蹇習凌弱。", "西方太白金主義，不掃寇盜生亂略。", "北方辰星水主智，不掃蒙蔽長讒慝。", "中央填星土主信，不掃詐欺滋姦猾。", "皇穹遴選綱紀星，出持彗帚掃環域。", "日華機上有九彗，乍上乍下空如筆。", "歸邪向上有兩彗，出也不行見則滅。", "天狗短彗在尾傍，火光炎炎空烜赫。", "天攙類彗雲如斗，蚩尤類彗箕後曲。", "六賊如彗在西方，咸漢带彗居正北。", "驅策舉莫前，彗乃排膠轕。", "不指房心明堂位，不臨箕尾后妃宅。", "不抵參昴詠衾裯，不向牛女逐淫佚。"]'),
('f83acaa1-9b3a-4883-8bbb-69b9edcbb303','和陳府教授見贈','戴埴','宋','宋诗','song-poetry','','[]','遺風洙泗濱，汲古酌犧罇。',48,'全唐诗/poet.song.218000.json','["遺風洙泗濱，汲古酌犧罇。", "魚躍池藻翻，鶑呼庭樹喧。", "樂山不樂水，居城猶居村。", "一朝黄鐘鳴，九畹滋蘭根。"]'),
('c9dceed0-8a8b-4726-b576-d0940ba1b1d7','垂虹亭','朱南杰','宋','宋诗','song-poetry','','[]','憑虛蝃蝀逼人寒，中有危亭百尺寬。',64,'全唐诗/poet.song.218000.json','["憑虛蝃蝀逼人寒，中有危亭百尺寬。", "天接水腰呈絕景，風回帆脚漲狂瀾。", "半篙落日吟將就，一抹晴煙畫亦難。", "不是酒杯今日窄，直須邀月上欄干。"]'),
('a68dd600-956d-4746-b5a4-4c759a9fd849','舟行過平江','朱南杰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蹤跡平生馬少游，功名外物等虛舟。',64,'全唐诗/poet.song.218000.json','["蹤跡平生馬少游，功名外物等虛舟。", "不多飲酒常成醉，自在吟詩祇遣愁。", "已幸一帆離錫邑，更寬兩日到杭州。", "曉來忽見盤門塔，疑是西湖大佛頭。"]'),
('13220adf-2527-4b35-b080-5459e0e62529','楓橋灣酒家有楓橋千古壓波光之句用韻以紀所見','朱南杰','宋','宋诗','song-poetry','','[]','楓橋酒味勝官坊，隨分紅裙取次粧。',64,'全唐诗/poet.song.218000.json','["楓橋酒味勝官坊，隨分紅裙取次粧。", "月照乍圓新氣象，僧閑不減舊風光。", "一橋地勢橫分水，兩岸人家競採桑。", "惟有塔鈴太多管，笑人來往自玎璫。"]'),
('c1149819-75f2-4def-85f4-e0d0d6948af1','出嘉興','朱南杰','宋','宋诗','song-poetry','','[]','舟出嘉禾五里城，僧樓山塔互崢嶸。',64,'全唐诗/poet.song.218000.json','["舟出嘉禾五里城，僧樓山塔互崢嶸。", "酒旗密比隨風舞，漁網橫拖漾日晴。", "畫舫貴人帆去穩，單衣遊女著來輕。", "山歌已接長河堰，到得臨平月又明。"]'),
('574ad98f-78d4-41bc-aea5-1a6d5e7c5580','過長河堰','朱南杰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','帆指長河風力微，漁舟箇箇有魚歸。',64,'全唐诗/poet.song.218000.json','["帆指長河風力微，漁舟箇箇有魚歸。", "一聲水際笛三弄，幾處梅邊竹四圍。", "桑伐遠揚蠶事熟，花消濃艷柳綿飛。", "西湖只在錢塘外，又見孤山梅子肥。"]'),
('11ab1539-a45a-4ecd-be87-27410ca8e658','同劉朋山遊湖邊作','朱南杰','宋','宋诗','song-poetry','','["\u897f\u6e56"]','誰立西湖造化功，峰分南北境相通。',64,'全唐诗/poet.song.218000.json','["誰立西湖造化功，峰分南北境相通。", "四時風物絃歌裏，兩岸人家圖畫中。", "堤柳送迎忘爾汝，棹聲來往自西東。", "風波便作恩波看，此樂君王與衆同。"]'),
('fd0a0405-d6c7-47fb-bfff-6fd4546e59bd','同陳明叔遊湖作','朱南杰','宋','宋诗','song-poetry','','[]','四月湖邊冷若秋，先賢堂下繫扁舟。',64,'全唐诗/poet.song.218000.json','["四月湖邊冷若秋，先賢堂下繫扁舟。", "山頭積翠來新意，波面飄紅憶舊遊。", "無柰楊花欺倦客，已多荷葉護輕鷗。", "堤邊誰道春歸了，猶有一聲黄栗留。"]'),
('8d2f5afd-3c81-4d8d-b4d4-6e89874ee523','和吳𡼣巖韻','朱南杰','宋','宋诗','song-poetry','','[]','春回筆底露潜機，爲怯高吟且遯肥。',64,'全唐诗/poet.song.218000.json','["春回筆底露潜機，爲怯高吟且遯肥。", "又見牛鞭春到日，羞披鶉結舊來衣。", "雪隨著處分單厚，梅不關人自密稀。", "歸計商量今始定，樂哉心事看雲飛。"]'),
('172aaf46-a224-4da8-8bd4-197aebe53e7b','春日呈𡼣巖','朱南杰','宋','宋诗','song-poetry','','[]','朝來慚愧又逢春，總把官身換客身。',64,'全唐诗/poet.song.218000.json','["朝來慚愧又逢春，總把官身換客身。", "堤柳未歸新氣象，窗梅猶带舊精神。", "村居牢落誰沽我，吏醉清閑却笑人。", "打疊故書排日去，一樽隨意踏芳塵。"]'),
('475cfd84-e4d8-42fb-8a1a-7e2147043062','張玉軒南園','朱南杰','宋','宋诗','song-poetry','','[]','南園不與昔時同，綿亙規模十里通。',64,'全唐诗/poet.song.218000.json','["南園不與昔時同，綿亙規模十里通。", "萬石倚山如踞虎，一亭跨水似垂虹。", "虛堂舊占梅邊月，曲徑新添竹外風。", "詩料滿前吟不盡，主人樽酒未應空。"]'),
('dd10ebff-774d-45e4-bf3c-aaea7d5b8019','壽實齋侍郎王先生','朱南杰','宋','宋诗','song-poetry','','[]','崧高維嶽誦生申，整頓乾坤屬舊臣。',64,'全唐诗/poet.song.218000.json','["崧高維嶽誦生申，整頓乾坤屬舊臣。", "天下安危關出處，性中存養自真純。", "便歸紫橐酬公論，已草黄麻授正人。", "天爲皇家錫難老，願將霖雨福斯民。"]'),
('7117c9f1-e331-4f6a-a54c-480d52d53ef3','七夕呈坐間諸友時留平江宿和靖書院次日','朱南杰','宋','宋诗','song-poetry','','[]','葉已鳴秋夜漸長，年年織女會牛郎。',64,'全唐诗/poet.song.218000.json','["葉已鳴秋夜漸長，年年織女會牛郎。", "龍梭暫歇七襄駕，雲袖輕飄百和香。", "輸我晚凉和月飲，任渠明發渡河忙。", "要知工巧元無用，樂得身閑拙不妨。"]'),
('fa9e3aa4-d10e-4435-9009-74ef9b4e420c','和吳梅庵同登白龍對月韻','朱南杰','宋','宋诗','song-poetry','','[]','秋容滿目带微寒，帆穩蘭舟駕碧瀾。',64,'全唐诗/poet.song.218000.json','["秋容滿目带微寒，帆穩蘭舟駕碧瀾。", "照我湖光天共色，襲人花氣露初乾。", "笑談紅袖日中舞，驚動蒼龍水底蟠。", "最是一清無著處，却慚狼籍草杯盤。"]'),
('a2ce39ce-271b-49ac-b5a2-8182400ae562','餞徐衍道知縣','朱南杰','宋','宋诗','song-poetry','','[]','事業文章属當家，刃游餘地宰金沙。',64,'全唐诗/poet.song.218000.json','["事業文章属當家，刃游餘地宰金沙。", "挽回凶歲作豐稔，安集流民絕嘆嗟。", "兩載秋霜威盜賊，一犂春雨沃桑麻。", "寬民實意言難盡，勝種河陽滿縣花。"]'),
('a2663f0f-4408-4fe7-8519-d7cf2f3eeea7','餞海鹽史後樂','朱南杰','宋','宋诗','song-poetry','','[]','秦溪邑大號難治，後樂三年以德爲。',64,'全唐诗/poet.song.218000.json','["秦溪邑大號難治，後樂三年以德爲。", "海闊有樓還舊觀，堂深無日不新詩。", "虛舟祇載來時物，實惠常教去後思。", "相業真傳公不忝，蒼生况是望霖時。"]'),
('75a31fe8-72e6-4767-ad00-36fddda71f52','朱知鎮戎服警盜不憚雪夜酒庫在鎮外不得與戲呈','朱南杰','宋','宋诗','song-poetry','','[]','戎裝元不礙儒冠，盜賊潜窺膽自寒。',64,'全唐诗/poet.song.218000.json','["戎裝元不礙儒冠，盜賊潜窺膽自寒。", "金鼓聲聞三里外，旌旗影庇四民安。", "肯從叶力多君子，愧不同盟是酒官。", "龢氣釀成年可卜，曉來喜見雪漫漫。"]'),
('051c7990-00bf-476d-8aed-75b2d11f0f94','除夜懷劉朋山爲坑司幹官','朱南杰','宋','宋诗','song-poetry','','[]','失脚糟丘又一春，歲除牢落頗關情。',64,'全唐诗/poet.song.218000.json','["失脚糟丘又一春，歲除牢落頗關情。", "誰家不換桃符句，比屋相聞竹爆聲。", "舊友未知能鑄冶，新年宜入孰陶成。", "來朝無甚人交往，樂得齁齁睡到明。"]'),
('a2957b46-405b-4a0b-9334-7f18a9ee98f3','夜坐書懷','朱南杰','宋','宋诗','song-poetry','','[]','挑燈看徹後村詩，忽爾憧憧百所思。',64,'全唐诗/poet.song.218000.json','["挑燈看徹後村詩，忽爾憧憧百所思。", "不待人言已知錯，要知分定盍如斯。", "但求甘旨安無事，浪說榮華自有時。", "倒指新篘當已熟，且煨閩芋一中之。"]'),
('d1cc69c9-c2b3-46f6-b0fd-5323920e2f2e','曉發嘉興府','朱南杰','宋','宋诗','song-poetry','','[]','曉發嘉興府，人家門未開。',48,'全唐诗/poet.song.218000.json','["曉發嘉興府，人家門未開。", "閘關船側過，水漲堰平推。", "濃綠暗官柳，肥紅綻野梅。", "城中簫鼓發，知是使君回。"]'),
('61f2c7a9-20ce-4d90-8579-04195701a41c','舟過吳江縣','朱南杰','宋','宋诗','song-poetry','','[]','寺滿吳江縣，鐘聲兩岸分。',48,'全唐诗/poet.song.218000.json','["寺滿吳江縣，鐘聲兩岸分。", "買魚嫌少室，沽酒欠文君。", "平地橋邊浪，無心嶺外雲。", "篙人添德色，爲策過湖勳。"]'),
('fe9d480f-6cbe-4fef-b91d-b25c33db269f','泊崇德','朱南杰','宋','宋诗','song-poetry','','[]','堰未抵長河，先從古縣過。',48,'全唐诗/poet.song.218000.json','["堰未抵長河，先從古縣過。", "詩舟尋舊岸，酒市鬻新歌。", "傍水人家密，依山僧寺多。", "夷猶觀未足，無柰月明何。"]'),
('1de2884c-d8e5-4f0c-9d39-ca857dc523e8','東新橋值雪','朱南杰','宋','宋诗','song-poetry','','[]','間關入帝鄉，飛雪斷覊腸。',48,'全唐诗/poet.song.218000.json','["間關入帝鄉，飛雪斷覊腸。", "天地皆明白，山川忽老蒼。", "柳眉遮舊影，梅額上新粧。", "客裏急先務，湖邊問短航。"]'),
('a8f49667-d928-4cb4-af17-0cae53000d59','甲辰入京春深猶雪和吳𡼣巖二首  其一','朱南杰','宋','宋诗','song-poetry','','[]','歲事客裏過，今年祇去年。',48,'全唐诗/poet.song.218000.json','["歲事客裏過，今年祇去年。", "甘貧常寂寂，知己孰拳拳。", "花艷卑崇帳，江流羨祖鞭。", "家山芳意動，野騎盍言還。"]'),
('070cba9f-eeab-4fd6-8be1-9f5ebbe75a22','甲辰入京春深猶雪和吳𡼣巖二首  其二','朱南杰','宋','宋诗','song-poetry','','[]','掀髯論時事，莫問是邪非。',48,'全唐诗/poet.song.218000.json','["掀髯論時事，莫問是邪非。", "綠句池邊得，青陽柳外歸。", "夜深嫌薄酒，春淺怯單衣。", "門巷雪撩亂，低頭且掩扉。"]'),
('a79a456d-49b6-4ef4-95e4-90ab8c849b1b','富民犯米四十字以喻之','朱南杰','宋','宋诗','song-poetry','','[]','彼此有人心，人心即訟庭。',48,'全唐诗/poet.song.218000.json','["彼此有人心，人心即訟庭。", "初無深利害，倒自費調亭。", "私意生荆棘，公家有典刑。", "落便宜是益，座右可刊銘。"]'),
('6062f214-8aca-43ca-9d85-5f2096a5f533','孤山觀梅','朱南杰','宋','宋诗','song-poetry','','[]','費盡年年造化功，精神全在雪霜中。',32,'全唐诗/poet.song.218000.json','["費盡年年造化功，精神全在雪霜中。", "一枝映带窗前月，消得逋仙作主翁。"]'),
('4f9f26f8-9760-419d-841b-4d7284b1d903','陳梅隠求詩','朱南杰','宋','宋诗','song-poetry','','[]','旱歲走江湖，那堪又歲除。',48,'全唐诗/poet.song.218000.json','["旱歲走江湖，那堪又歲除。", "隠梅非活計，行李盍寧居。", "自有珠璣集，不携朝貴書。", "酬君無好語，索笑謾躊躇。"]'),
('4f4050db-10bd-4821-a803-61b737fb18c6','林竹翁求跋','朱南杰','宋','宋诗','song-poetry','','[]','何物耐交情，林翁竹借名。',48,'全唐诗/poet.song.218000.json','["何物耐交情，林翁竹借名。", "霜嚴不改操，風勁鎮長清。", "袖裏森珠玉，胸中富甲兵。", "江湖莫相笑，已播逸民聲。"]'),
('bcaca38f-1741-4497-8662-3ea22d011f2c','書考','朱南杰','宋','宋诗','song-poetry','','[]','人說宦途好，元來是險途。',48,'全唐诗/poet.song.218000.json','["人說宦途好，元來是險途。", "不親真利害，難話細工夫。", "下考初書一，中心有愧無。", "官卑何展布，三載且糊塗。"]'),
('6095ad75-e42c-490e-a68c-71f2301536eb','劉直孺示拙逸詩編且命著語','朱南杰','宋','宋诗','song-poetry','','[]','拙自愚中來，逸與怠相比。',48,'全唐诗/poet.song.218000.json','["拙自愚中來，逸與怠相比。", "限界固分明，差忒亦容易。", "人心自有機，天下本無事。", "更參大學章，終始一誠意。"]'),
('8a737f13-2a73-4471-a6e5-c8fb0bda2c63','尹樓巖久留華亭','朱南杰','宋','宋诗','song-poetry','','[]','風雷昨夜揭窗紗，未信樓巖不憶家。',32,'全唐诗/poet.song.218000.json','["風雷昨夜揭窗紗，未信樓巖不憶家。", "和靖山頭春到了，莫因尋鶴負梅花。"]'),
('b45db635-0c9a-40cf-a20f-4db45c166abf','攝事華亭歸舟口占','朱南杰','宋','宋诗','song-poetry','','[]','挈來司市正花時，補陋支傾費品題。',32,'全唐诗/poet.song.218000.json','["挈來司市正花時，補陋支傾費品題。", "顧影自慚身是客，片帆又逐曉風西。"]'),
('c1310f00-c9d4-49e2-9d5c-f9d131ceac71','延陵道中即事三絕  其一','朱南杰','宋','宋诗','song-poetry','','[]','筍輿取道自吳干，東作村村喜一般。',32,'全唐诗/poet.song.218000.json','["筍輿取道自吳干，東作村村喜一般。", "已拜勸農田畯賜，舊租何似放令寬。"]'),
('9b1095b1-9171-4c8f-bfcb-9ccb1cafd3fc','延陵道中即事三絕  其二','朱南杰','宋','宋诗','song-poetry','','[]','人家密簇近溪旁，舊袂青裙競採桑。',32,'全唐诗/poet.song.218000.json','["人家密簇近溪旁，舊袂青裙競採桑。", "相喚相呼相歎息，繭絲歲歲爲官忙。"]'),
('2b802f80-6c6b-45df-b396-c7e63c5a01ad','延陵道中即事三絕  其三','朱南杰','宋','宋诗','song-poetry','','[]','小立青帘賣酒家，味雖薄薄勝空茶。',32,'全唐诗/poet.song.218000.json','["小立青帘賣酒家，味雖薄薄勝空茶。", "今年春滿疎籬外，數朶輕紅出杏花。"]'),
('d625b882-027b-4065-827a-ce0b249d983e','題吳梅庵和靖索句圖','朱南杰','宋','宋诗','song-poetry','','[]','童寒鶴冷雪霏霏，正是先生得句時。',32,'全唐诗/poet.song.218000.json','["童寒鶴冷雪霏霏，正是先生得句時。", "一段孤清圖不盡，梅花從此厭人詩。"]'),
('122f9864-00c8-4dd9-b11e-6bdc609357ef','入京','朱南杰','宋','宋诗','song-poetry','','[]','客懷醉殺也醒醒，昨夜思家夢幾驚。',32,'全唐诗/poet.song.218000.json','["客懷醉殺也醒醒，昨夜思家夢幾驚。", "道阻且長無信息，只將喜鵲驗安平。"]'),
('2b743fe0-33dc-4bde-916e-c0e562263436','橫林遇雨  其一','朱南杰','宋','宋诗','song-poetry','','[]','斷當篙師到錫山，片雲尼我竹林間。',32,'全唐诗/poet.song.218000.json','["斷當篙師到錫山，片雲尼我竹林間。", "短篷展轉渾無寐，祇聽郵鈴去復還。"]'),
('ca35c66d-52ba-450f-b085-0bbe729209a8','橫林遇雨  其二','朱南杰','宋','宋诗','song-poetry','','[]','雨濕桅竿風颭帆，不禁篷漏滴衣單。',32,'全唐诗/poet.song.218000.json','["雨濕桅竿風颭帆，不禁篷漏滴衣單。", "蒼頭更說無眠處，始信人生行路難。"]'),
('e438bd7d-0136-4c86-8f21-b6c31475790a','自庫入鎮十二里皆山徑邢侯以馬相招道間口占問梅','朱南杰','宋','宋诗','song-poetry','','[]','蹇馿突兀萬山間，欲雨還晴雪又慳。',32,'全唐诗/poet.song.218000.json','["蹇馿突兀萬山間，欲雨還晴雪又慳。", "一路梅花尋不見，多應開向小溪灣。"]'),
('1ddfb562-3a11-41f5-b374-6881494516c4','煙雨樓','朱南杰','宋','宋诗','song-poetry','','[]','錦繡囊開城角東，規模綿亙境相通。',64,'全唐诗/poet.song.218000.json','["錦繡囊開城角東，規模綿亙境相通。", "一亭舊占梅邊月，兩徑新添竹外風。", "山色有無煙變態，湖光濃淡雨收功。", "憑欄正好催歸去，橫笛數聲蘆葦中。"]'),
('e03d0858-d4df-4a4f-add7-38f4e774f3ea','秋意','蔣廷玉','宋','宋诗','song-poetry','','[]','秋意如詩淡，又如湘水清。',48,'全唐诗/poet.song.218000.json','["秋意如詩淡，又如湘水清。", "無家人易感，有筆畫難成。", "月冷砧千杵，江空鴈一聲。", "夢回蕉葉上，殘雨幾番鳴。"]'),
('5ff943df-19ea-47ef-8950-eeee9d046e84','浄剎','蔣廷玉','宋','宋诗','song-poetry','','[]','碑上文難讀，開山失所傳。',48,'全唐诗/poet.song.218000.json','["碑上文難讀，開山失所傳。", "巖松秋落子，石井夜添泉。", "地曠常多月，厨寒不起煙。", "昔年曾有虎，來到寺門前。"]'),
('41602945-7e69-4c23-b77c-e18fab6c38aa','絛','蔣廷玉','宋','宋诗','song-poetry','','[]','八百青銅買，歸來繫黑豹。',48,'全唐诗/poet.song.218000.json','["八百青銅買，歸來繫黑豹。", "松毛倒垂膝，椶綆曲圍腰。", "穩稱輕紗帽，宜懸小藥瓢。", "有時吟未就，頻在手中摇。"]'),
('f0e138bc-9b43-4190-af25-dd1565ca678d','補衣','蔣廷玉','宋','宋诗','song-poetry','','[]','百補未成片，何緣御得寒。',48,'全唐诗/poet.song.218000.json','["百補未成片，何緣御得寒。", "拆時如網裂，紉處著針難。", "色樣多無定，花紋鬭不完。", "分明類禪衲，其奈戴儒冠。"]'),
('3f36b132-8b54-4b1e-b112-2b5d62c833ca','贈陳宗之','蔣廷玉','宋','宋诗','song-poetry','','[]','經營一室面清波，不是儒衣不見過。',64,'全唐诗/poet.song.218000.json','["經營一室面清波，不是儒衣不見過。", "南渡好詩都刻盡，中朝名士與交多。", "分甘書史窩中老，興在江湖醉後歌。", "門外今年桐又長，不知堪繫我船麽。"]'),
('a1612cb3-5a2f-4958-96b4-4f436db441eb','葉夢麟往惟揚','蔣廷玉','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','一馬揚州路，桃開幾樹花。',48,'全唐诗/poet.song.218000.json','["一馬揚州路，桃開幾樹花。", "春光無揀擇，淮地亦繁華。", "日慘長江水，風昏古戰沙。", "爭雄舊時事，君去莫思家。"]'),
('0f175abd-ce47-4ee9-9012-fc2619252c8c','中秋無月二絕同韻  其一','趙崇檳','宋','宋诗','song-poetry','','[]','幾度開樽宴畫樓，月華孤負好中秋。',32,'全唐诗/poet.song.218000.json','["幾度開樽宴畫樓，月華孤負好中秋。", "姮娥也厭笙歌沸，雲幕重重不上鈎。"]'),
('b64d18ef-1f56-4dcc-afd5-8455c8a07dbd','中秋無月二絕同韻  其二','趙崇檳','宋','宋诗','song-poetry','','[]','何處人登庾亮樓，癡雲特地妬中秋。',32,'全唐诗/poet.song.218000.json','["何處人登庾亮樓，癡雲特地妬中秋。", "試憑絃管吹將散，江靜天空月滿鈎。"]'),
('76243e64-1828-445e-92b0-2ada6a748691','遊五雲觀','劉應龍','宋','宋诗','song-poetry','','[]','雨絕春風和，沉栖慕遐矚。',192,'全唐诗/poet.song.218000.json','["雨絕春風和，沉栖慕遐矚。", "野火開叢荆，遥岑路徑熟。", "極頂如掌平，羣峰四環矗。", "人言古觀基，突兀此有屋。", "半嶺汲餉勞，躋攀怨僮僕。", "一朝風霆怒，捲落置前麓。", "至今五雲宮，宛在平原曲。", "年代遠莫稽，兒童記樵牧。", "每聞風雨時，鐘聲隠巖谷。", "披尋杳無迹，靈境信非俗。", "苔花蝕碎瓦，字蹟不可讀。", "居人傳神奇，客子駭心目。", "振襟坐危磐，閬風想晞沐。", "轉石落懸巖，砰雷震山腹。", "徘徊不能去，登覽興未足。", "一笑下田家，題詩寄遊躅。"]'),
('f46ec623-d008-486a-82c5-e4d4e6615a99','挽忠烈劉侯','劉子實','宋','宋诗','song-poetry','','[]','樵水孤軍血戰時，英雄失援最堪悲。',64,'全唐诗/poet.song.218000.json','["樵水孤軍血戰時，英雄失援最堪悲。", "那知慣把鯨鯢戮，到底翻爲鳥鼠欺。", "堆壘誓當陰滅賊，崤陵休恨不全師。", "生封死廟男兒事，今有祠前墮淚碑。"]'),
('e83286d9-8a06-479a-83ef-6026d482b4fa','酬卧雲','劉木','宋','宋诗','song-poetry','','[]','美人隔雲水，廣永幾千里。',96,'全唐诗/poet.song.218000.json','["美人隔雲水，廣永幾千里。", "白日有沒時，相思無窮已。", "夜雨翳燈花，凉風折窗紙。", "披衣不能寐，詎待聞雞起。", "從來志士腸，高若雪山峙。", "豈不念摧折，藉此可憑恃。", "蔓草委地滋，孤松插天起。", "咸若知我深，贈言故及此。"]'),
('501dece8-602c-41bb-afec-d6587f76ef35','感懷','劉木','宋','宋诗','song-poetry','','[]','幾度言歸未得歸，歸心常切故山薇。',64,'全唐诗/poet.song.218000.json','["幾度言歸未得歸，歸心常切故山薇。", "人於愁處酒難著，春正好時花已稀。", "殘日明池蝌蚪集，綠陰滿院伯勞飛。", "浮生衮衮只如此，未必今朝悟昨非。"]'),
('6c27d9a6-b3e6-4bf4-b994-b8d3a5b8e93e','陳山謁吳越五王分祠','劉熺','宋','宋诗','song-poetry','','[]','海村崇祖祀，吳越舊王家。',48,'全唐诗/poet.song.218000.json','["海村崇祖祀，吳越舊王家。", "里老稱遺澤，文孫避俗譁。", "玉金榮带印，俎豆薦葵𦳏。", "欲補迎春曲，須歌陌上花。"]'),
('e636ace7-c417-4b29-a24e-5f8431dc8b36','挽錢心齋先生','劉熺','宋','宋诗','song-poetry','','[]','鳳躍南岡老隠淪，仙遊悲動感儒紳。',64,'全唐诗/poet.song.218000.json','["鳳躍南岡老隠淪，仙遊悲動感儒紳。", "海邊鷗鷺無知己，屋外溪山失主人。", "滿徑黄花閑白晝，一庭芳草自青春。", "他年化鶴歸來日，城郭依然跡已陳。"]'),
('f2e78c88-08ba-4931-9d76-2722face3510','海門','陳淳祖','宋','宋诗','song-poetry','','[]','微光動海門，色界一層新。',48,'全唐诗/poet.song.218000.json','["微光動海門，色界一層新。", "玄霧橫金闕，丹英吐玉津。", "長疑浴日處，上有飲霞人。", "頃刻晨烟合，紛紛亂野塵。"]'),
('9dd48bc6-073a-46cf-a212-9bef6e37b0b7','過鄭司業舊居','陳淳祖','宋','宋诗','song-poetry','','[]','司業閒居處，門前烟樹低。',48,'全唐诗/poet.song.218000.json','["司業閒居處，門前烟樹低。", "見山懷舊隠，撫壁試新題。", "燕語花初落，蜂衙日自西。", "一年春事畢，又見子規啼。"]'),
('a674c702-657b-469a-8f70-6f66ef8853f1','勸農二首奉呈同官諸丈  其一','陳淳祖','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','勸農事云畢，晴日足登山。',108,'全唐诗/poet.song.218000.json','["勸農事云畢，晴日足登山。", "山高翠微上，坐見人境閒。", "天目有修眉，洞庭無狂瀾。", "田疇井畫見，布穀行相關。", "村村自花柳，流水春風顔。", "周行撫泉石，碧匣開潺湲。", "尚想讀書聲，猶在松樹間。", "此事已難會，沂水何時還。", "朗吟蘇仙語，明月下前灣。"]'),
('8a356a9d-245e-470d-b4f7-afaa201b00de','勸農二首奉呈同官諸丈  其二','陳淳祖','宋','宋诗','song-poetry','','[]','迺一秋一冬，愁聽鴻飛鳴。',108,'全唐诗/poet.song.218000.json','["迺一秋一冬，愁聽鴻飛鳴。", "及茲問春半，土暖已足耕。", "殷勤勸父老，尊酒若爲情。", "我有一瓣香，爲爾祈西成。", "晴光動川原，桑麥日敷榮。", "天公幸見聽，一飽須可營。", "幾見隴畝事，得此白髮生。", "田父飲我酒，歸與兒孫評。", "孝弟力田者，家道終和平。"]'),
('5542faa8-686d-417e-87cd-ca8a92f9668e','看雲','陳淳祖','宋','宋诗','song-poetry','','[]','南山雲欲歸，北山雲欲出。',72,'全唐诗/poet.song.218000.json','["南山雲欲歸，北山雲欲出。", "北山已成雨，南山還有日。", "天風忽吹舉，南北山如一。", "白雲本無心，不知果何術。", "出者未云得，歸者未云失。", "茫茫古復今，世事却可說。"]'),
('0f45a393-0f5d-41fb-bfe4-c50282dc033f','重過惠泉','陳淳祖','宋','宋诗','song-poetry','','[]','何事笑癡兒，看山秋正宜。',48,'全唐诗/poet.song.218000.json','["何事笑癡兒，看山秋正宜。", "三年三到寺，一度一題詩。", "蝸篆避書壁，松釵落硯池。", "夜寒砧杵動，歸思鬢先知。"]'),
('91af99c1-772b-4a2a-8bb2-f13c38f21e72','征婦吟','陳淳祖','宋','宋诗','song-poetry','','[]','虜退沙場洗戰斑，誰家不上望夫山。',32,'全唐诗/poet.song.218000.json','["虜退沙場洗戰斑，誰家不上望夫山。", "江邊迤邐春無頼，楊柳枝垂人未還。"]'),
('b08ec65c-b312-4f8d-adc0-b9a1fd7e1e51','淳祐七年丁未十一月朔蔡久軒自江東提刑歸抵家時三館諸公以風霜隨氣節河漢下文章分韻賦詩送別得氣字','周梅叟','宋','宋诗','song-poetry','','[]','九峰洪範篇，雅是書之緯。',216,'全唐诗/poet.song.218000.json','["九峰洪範篇，雅是書之緯。", "頃嘗一讀之，懵然雲霧蔚。", "晚校中秘藏，講此愧猶未。", "喜逢尚書郎，家傳得之既。", "何以名內篇，一扣倘知味。", "無幾即語離，匆匆怪何謂。", "天子仁聖心，聞過未常諱。", "豈嫌有直疏，斥彼惡之彙。", "矧茲龍卷前，正欠王與魏。", "得見丹鳳鳴，士黨意乃慰。", "黯也不居中，物論幾鼎沸。", "雖然上所命，所重在民事。", "暨淑問臯陶，持平爾廷尉。", "突使江東人，德澤盡沾溉。", "惟公有古心，所守至弘毅。", "我不畏孔壬，汙吏必我畏。", "所願敷好生，物物皆吐氣。", "回思攬味甘，詔書登七貴。"]'),
('5d60846b-068c-4bcd-b9cd-94703fc15782','賀參政生日古風','翁合','宋','宋诗','song-poetry','','[]','國朝啟運星聚奎，太極夫子生濂溪。',288,'全唐诗/poet.song.218000.json','["國朝啟運星聚奎，太極夫子生濂溪。", "聖遠言湮開衆迷，接引伊洛爲航梯。", "乾精坤粹星端倪，紙上陳迹俱筌蹄。", "南來道統墜塗泥，我考亭翁重挈提。", "及肩諸子戶牖低，有山突兀宮牆西。", "道則高矣身顛擠，嘉禾瑞草來庭闈。", "種之美也無稗荑，公尤磽磽頭峙犀。", "筆下絕去翰墨畦，刪後既醉塗鳧鷖。", "三十年前塔上題，只今待漏聽朝鷄。", "排海摧嵩鱗屢批，肯美宮室奉妾妻。", "廣厦峨冠講若稽，我欲托國誰放麑。", "知公可仗爲築隄，保我子孫安烝黎。", "誰賢稚老空自賫，有德與位至公齊。", "言如車行得軏輗，尼山上有孤鳳棲。", "惟伋傳道如取携，鯉與白也難之隮。", "西山家學有根柢，眼中三世琮璋珪。", "言行一一無訶詆，此福如海難測蠡。", "番番黄髮齒且兒，倘可撰杖桃李蹊。"]'),
('72916be2-544f-4347-834a-04bc8458642a','壽參政','翁合','宋','宋诗','song-poetry','','[]','鳳凰巢定萬年枝，陶鑄蒼生儘未遲。',64,'全唐诗/poet.song.218000.json','["鳳凰巢定萬年枝，陶鑄蒼生儘未遲。", "六丈語言同輩服，二郎官職乃翁知。", "味回春茗甘方永，春到寒花淡更奇。", "十有三人共千歲，向羊終社更追隨。"]'),
('6ec2550b-bb27-4b77-acac-adf1368e6fdc','題方丈','翁合','宋','宋诗','song-poetry','','[]','武夷奇絕處，水碧更山丹。',48,'全唐诗/poet.song.218000.json','["武夷奇絕處，水碧更山丹。", "觀闢南唐址，祠仍西漢壇。", "山禽酣午夢，野菜健晨餐。", "道士江沖一，新詩有集刊。"]'),
('3112a91b-4b87-42cb-95c2-9292ebf2abc8','常庵','翁合','宋','宋诗','song-poetry','','[]','我是曾孫孫又孫，今朝始謁武夷君。',64,'全唐诗/poet.song.218000.json','["我是曾孫孫又孫，今朝始謁武夷君。", "三英秀峙千巖合，九曲平穿兩岸分。", "丹壑何年流絳水，幔亭整日鏁紅雲。", "一生湖海江三白，早向溪頭累石墳。"]'),
('29a1cec1-7439-463f-bc0a-1a037507282d','過周靜軒別墅','鄭藹','宋','宋诗','song-poetry','','[]','殘雪猶在屋，園林已半春。',48,'全唐诗/poet.song.218000.json','["殘雪猶在屋，園林已半春。", "客情盈一舫，幽事雜諸鄰。", "地有忘憂草，池無頳尾鱗。", "公榮殊自勝，樽酒肯同人。"]'),
('899c2feb-4236-4f68-8ed4-0509cc19a7e9','過桂氏湖莊','鄭蘭','宋','宋诗','song-poetry','','[]','堂上一天水，秋風叫白鷴。',48,'全唐诗/poet.song.218000.json','["堂上一天水，秋風叫白鷴。", "地偏遊客少，煙闊釣徒閒。", "懷古樓宜野，澆蔬月在山。", "駕言尋舊好，款款到蘆灣。"]'),
('61f6cbd8-45bb-4f76-b27c-b9cca6ee4e4b','鳳凰臺','劉次春','宋','宋诗','song-poetry','','[]','高臺寥寞晚雲深，故國山河萬里心。',32,'全唐诗/poet.song.218000.json','["高臺寥寞晚雲深，故國山河萬里心。", "若使當年真鳳見，不教春燕亦巢林。"]'),
('3c912137-a166-4189-8aaf-8f10d584ce1c','烏臺古柏','趙崇璠','宋','宋诗','song-poetry','','[]','豸冠鐵面氣昂藏，古柏亭亭降異香。',64,'全唐诗/poet.song.218000.json','["豸冠鐵面氣昂藏，古柏亭亭降異香。", "天挺孤姿培相業，風裁老幹肅臺綱。", "歲寒常捲珠簾雪，炎暑猶飛白簡霜。", "夜半群烏驚宿處，恍疑驄馬召歸忙。"]'),
('9c2281dc-75dc-4dde-a9dd-79369ad8cb48','題靜齋稿','沈平','宋','宋诗','song-poetry','','[]','斯道在人心，如蚌藏圓珠。',24,'全唐诗/poet.song.218000.json','["斯道在人心，如蚌藏圓珠。", "散作明月光，斂則止水虛。"]'),
('640eabc5-a2e8-463e-97f0-3a736c5cfc23','翠蛟峰','沈平','宋','宋诗','song-poetry','','[]','誰解青雲勒，在蛟舞不休。',48,'全唐诗/poet.song.218000.json','["誰解青雲勒，在蛟舞不休。", "飛來兩潭月，驚起九峰秋。", "松影晴猶暗，山光暖欲浮。", "因參玉局句，千古仰前修。"]'),
('987d6362-846b-4fb9-a560-b2d820e45738','句','沈平','宋','宋诗','song-poetry','','[]','還君此畫不忍覷，怕憶當年分手處。',16,'全唐诗/poet.song.218000.json','["還君此畫不忍覷，怕憶當年分手處。"]'),
('11640d54-37c1-4c2b-af53-0a246bc098fd','白石山','張志道','宋','宋诗','song-poetry','','[]','山似游龍勢欲奔，山中有路透天閽。',32,'全唐诗/poet.song.218000.json','["山似游龍勢欲奔，山中有路透天閽。", "峰巒常带烟霞色，洞穴渾無斧鑿痕。"]'),
('4ac808e9-1783-4992-a77f-003039c56a14','西湖懷古','張志道','宋','宋诗','song-poetry','','["\u897f\u6e56"]','荷花桂子不勝悲，江介繁華異昔時。',64,'全唐诗/poet.song.218000.json','["荷花桂子不勝悲，江介繁華異昔時。", "天目山來孤鳳歇，海門潮去六龍移。", "賈充誤國終無策，庾信哀時尚有詞。", "莫向中原誇絕景，西湖□恨是西施。"]'),
('eb30e08b-d34b-4cfa-9ebe-37093338babc','郢州堂唱和','李褒','宋','宋诗','song-poetry','','[]','不離雉堞似山家，消得詩翁著意誇。',64,'全唐诗/poet.song.218000.json','["不離雉堞似山家，消得詩翁著意誇。", "水界葱芊成畎澮，天將平遠入烟霞。", "沙禽暫落分明見，村徑相通取次斜。", "且莫向南舒望眼，塵埃闤闠事如麻。"]'),
('a0c78d7e-cc3d-47c6-b2c5-7421ae7cb867','次韻王魯齋大安古道','倪公武','宋','宋诗','song-poetry','','[]','著脚爭些子，公私只兩歧。',48,'全唐诗/poet.song.218000.json','["著脚爭些子，公私只兩歧。", "正途元自穩，捷徑不勝巇。", "見透行須透，心移境亦移。", "前人須指點，進步莫遲疑。"]'),
('edb4cb77-e915-4421-a1b6-89092b4b1ab0','浯溪','曹一龍','宋','宋诗','song-poetry','','[]','行樂乘陰好，誰能困墨朱。',48,'全唐诗/poet.song.218000.json','["行樂乘陰好，誰能困墨朱。", "重陽邀數客，盡日款三吾。", "煙慘江山古，風清竹木癯。", "漫郎如可作，分酒酹茱萸。"]'),
('49758cb0-e5d8-4105-8600-7f138edc2f13','入道詩十九首  其一','王慶升','宋','宋诗','song-poetry','','[]','浮世功名水一漚，數來誰得百年留。',32,'全唐诗/poet.song.218000.json','["浮世功名水一漚，數來誰得百年留。", "使能久履姬姜位，澤不加民時可羞。"]'),
('acebb214-9e0f-45f1-b80d-a07e2e657a6d','入道詩十九首  其二','王慶升','宋','宋诗','song-poetry','','[]','一貧徹骨且安貧，顔范雖貧姓字新。',32,'全唐诗/poet.song.218000.json','["一貧徹骨且安貧，顔范雖貧姓字新。", "任是富豪能敵國，不知身死屬何人。"]'),
('2902c822-80ec-4183-9113-8000f69b3fbb','入道詩十九首  其三','王慶升','宋','宋诗','song-poetry','','[]','蠅利蝸名是債緣，便須還了聽於天。',32,'全唐诗/poet.song.218000.json','["蠅利蝸名是債緣，便須還了聽於天。", "欠多欠少休貪債，必待豐高又不然。"]'),
('c0a19ebe-6b4c-4fef-9179-d9f4840389ff','入道詩十九首  其四','王慶升','宋','宋诗','song-poetry','','[]','若謀富貴說榮親，養志承顔有幾人。',32,'全唐诗/poet.song.218000.json','["若謀富貴說榮親，養志承顔有幾人。", "素位而行無怫逆，過於列鼎與羅珍。"]'),
('24c070e6-9f11-4ff4-a010-99b2dc991a4f','入道詩十九首  其五','王慶升','宋','宋诗','song-poetry','','[]','人期上塚要焚黄，名爵思爲厚夜光。',32,'全唐诗/poet.song.218000.json','["人期上塚要焚黄，名爵思爲厚夜光。", "九祖生天蒙帝渥，只緣一子入仙鄉。"]'),
('ca38f78a-6d4e-4e87-af14-b9eb520f6d6b','入道詩十九首  其六','王慶升','宋','宋诗','song-poetry','','[]','羲文孔子一先天，互把精微著易篇。',32,'全唐诗/poet.song.218000.json','["羲文孔子一先天，互把精微著易篇。", "不用陰陽真正理，旁蹊曲徑是徒然。"]'),
('e88d2369-6a8c-421d-a93a-4e62213197ce','入道詩十九首  其七','王慶升','宋','宋诗','song-poetry','','[]','乾坤大象一陰陽，離坎精華日月光。',32,'全唐诗/poet.song.218000.json','["乾坤大象一陰陽，離坎精華日月光。", "不取盈虛消息候，若非聾瞽必爲狂。"]'),
('de1d5688-a40c-44c8-ae59-ca93afd97ade','入道詩十九首  其八','王慶升','宋','宋诗','song-poetry','','[]','求道惟愁不遇真，得真翻惑是何人。',32,'全唐诗/poet.song.218000.json','["求道惟愁不遇真，得真翻惑是何人。", "但將德行爲梯磴，何必攀緣自苦辛。"]'),
('a4f83897-7f16-4ae3-b8ca-77140e55225d','入道詩十九首  其九','王慶升','宋','宋诗','song-poetry','','[]','時節因緣不偶然，既由人事亦關天。',32,'全唐诗/poet.song.218000.json','["時節因緣不偶然，既由人事亦關天。", "功深德厚天孚祐，玉籍標名骨自仙。"]'),
('2dcad305-b43f-4321-8c0f-678fdf9a6a65','入道詩十九首  其一○','王慶升','宋','宋诗','song-poetry','','[]','論兵莫待一陽生，習閲攻車要不驚。',32,'全唐诗/poet.song.218000.json','["論兵莫待一陽生，習閲攻車要不驚。", "或躍在淵能自試，不勞征戰屈人兵。"]'),
('b6e3674c-6104-4e2d-b19c-d55250248f2c','入道詩十九首  其一一','王慶升','宋','宋诗','song-poetry','','[]','好下工時便下工，百年光景一飛蓬。',32,'全唐诗/poet.song.218000.json','["好下工時便下工，百年光景一飛蓬。", "後生不值老來值，大藥難醫骨髓空。"]'),
('9f3b563f-a475-4508-ba7a-58ec766b15f6','入道詩十九首  其一二','王慶升','宋','宋诗','song-poetry','','[]','閏年爲厄要先推，陽忒陰差莫妄爲。',32,'全唐诗/poet.song.218000.json','["閏年爲厄要先推，陽忒陰差莫妄爲。", "守待一陽來復後，斗加東北月沈西。"]'),
('2d897276-e96f-4c0a-b4f7-98431004bbd0','入道詩十九首  其一三','王慶升','宋','宋诗','song-poetry','','[]','夜夜工夫總一般，坎男離女共同歡。',32,'全唐诗/poet.song.218000.json','["夜夜工夫總一般，坎男離女共同歡。", "專心直待陰陽足，却馬休兵國自安。"]'),
('b12edada-7a46-40fa-9007-3d243cbeca7a','入道詩十九首  其一四','王慶升','宋','宋诗','song-poetry','','[]','九轉金丹九月圓，木金胎旺好安禪。',32,'全唐诗/poet.song.218000.json','["九轉金丹九月圓，木金胎旺好安禪。", "純坤月裏純乾足，手把仙瓢酌醉仙。"]'),
('f2769133-2dc9-4cf5-b1da-0fabd5a29edd','入道詩十九首  其一五','王慶升','宋','宋诗','song-poetry','','[]','清高之士貴清虛，捕影追風釣火魚。',32,'全唐诗/poet.song.218000.json','["清高之士貴清虛，捕影追風釣火魚。", "闊論高談驚世俗，老君終是憚迴車。"]'),
('efc6878f-65e3-4223-ab05-569c0ef19377','入道詩十九首  其一六','王慶升','宋','宋诗','song-poetry','','[]','閭閻小子不明心，執著旁門學採陰。',32,'全唐诗/poet.song.218000.json','["閭閻小子不明心，執著旁門學採陰。", "坐卧三峰終作鬼，疇知仙遒有浮沉。"]'),
('8a3606e5-7ce8-4f36-a5be-274c05b097d8','入道詩十九首  其一七','王慶升','宋','宋诗','song-poetry','','[]','先天妙質罕人明，盡向虛無喚己名。',32,'全唐诗/poet.song.218000.json','["先天妙質罕人明，盡向虛無喚己名。", "太極重歸無極後，謂之皇極始長生。"]'),
('889ae82f-0eba-4207-8aa3-323378fba9b2','入道詩十九首  其一八','王慶升','宋','宋诗','song-poetry','','[]','萬卷丹書名一般，金砂玉石辯應難。',32,'全唐诗/poet.song.218000.json','["萬卷丹書名一般，金砂玉石辯應難。", "自非夙有神仙骨，未易教君洗眼看。"]'),
('34c967f2-36bb-4fe1-b82e-d1ad09757553','入道詩十九首  其一九','王慶升','宋','宋诗','song-poetry','','[]','金丹至藥匪尋常，幸藉西華泄此方。',32,'全唐诗/poet.song.218000.json','["金丹至藥匪尋常，幸藉西華泄此方。", "天上有之無計得，積功須及許旌陽。"]'),
('1bf3e101-33ba-47ba-ad89-07cba1536def','南峰寺藍光軒懷吳直翁','陳仁玉','宋','宋诗','song-poetry','','[]','懷佳人兮山扃，躡煙霏兮步輕。',77,'全唐诗/poet.song.218000.json','["懷佳人兮山扃，躡煙霏兮步輕。", "蹇獨立兮山上，空山無人兮寒松自聲。", "懷佳人兮何許，白雲封關兮猿鶴看戶。", "羌有懷兮曷愬，風虛徐兮簷鐸語。", "遲佳人兮未來，聊逍遥兮容與。"]'),
('a3ea6aad-ac8d-4318-a659-1d1660f9a0a2','游洞霄','陳仁玉','宋','宋诗','song-poetry','','[]','天柱峰頭疊紫煙，遥看萬玉聳相連。',64,'全唐诗/poet.song.218000.json','["天柱峰頭疊紫煙，遥看萬玉聳相連。", "雲深九鎖疑無路，翠豁一區俄有天。", "爽氣襲人森石樹，嗔雷飛雨響山泉。", "倏然不類人間世，今日自驚平地仙。"]'),
('2e49bf8c-ae96-463d-b0ac-1489a067d2af','題蘇端明書乳泉賦後','陳仁玉','宋','宋诗','song-poetry','','[]','坡翁謫海上，人傳已仙去。',48,'全唐诗/poet.song.218000.json','["坡翁謫海上，人傳已仙去。", "道逢章子厚，遄復返塵路。", "至言想世驚，猶閟乳泉賦。", "遥憐嵩山丘，千古不可駐。"]'),
('747d7bab-d7e0-47bc-a092-3eeeb0cd26c0','仙都山獨峰大雪歌','陳仁玉','宋','宋诗','song-poetry','','[]','仙居仙人游仙都，帝遣滕六爲先驅。',192,'全唐诗/poet.song.218000.json','["仙居仙人游仙都，帝遣滕六爲先驅。", "天花撩亂繽紛舞，秉圭植璧仙靈趨。", "削瓜青玉一萬仞，拔地挺挺撐元虛。", "人言黄帝此輕舉，上有蓮花開碧湖。", "我疑此是廣成子，守道特立萬萬古。", "我來有問輒不應，窈窈冥冥誰與語。", "丹邱赤城我所棲，任意逍遥了無伍。", "老君牧龍種芝田，草莽向人縈網罟。", "人間逼窄知奈何，桑田滄海無回波。", "吞腥啄腐競晷刻，角牙觸齧傷天和。", "從旁掀髯每大笑，仙都峰頭更觀妙。", "甚欲點鐵成黄金，却恐黄金誤後人。"]'),
('ab7bad7d-8a55-4997-86eb-3ed24f936eef','步虛歌','陳仁玉','宋','宋诗','song-poetry','','[]','仙之來兮駕五龍，霓旌絳節泠然風。',152,'全唐诗/poet.song.218000.json','["仙之來兮駕五龍，霓旌絳節泠然風。", "誰歟擘脯金盤供，垂要綠髮顔如童。", "五百餘載一瞬中，蓬萊水淺來何從。", "蔡翁得鞭與道通，雲間遺臼墮半空。", "九井丹液藏甘潼，赤明浩劫傳無窮。", "坐閲成壞此故宮，宮前山色知仙蹤。", "月明笙鶴歸長松，修身潔行儻可逢。", "屑然爲我達帝聰，流杯□□袪盲聾。", "卿雲甘露常歲豐，神仙豈必私此躬，八荒壽域仙之功。"]'),
('ecc7af37-7f88-413e-8173-20f50967fe44','中秋寄陳碧棲','萬哲','宋','宋诗','song-poetry','','[]','秋氣清如此，秋花香奈何。',48,'全唐诗/poet.song.218000.json','["秋氣清如此，秋花香奈何。", "人生還健在，月色況明多。", "有酒君當醉，無愁我欲歌。", "樓高俯松頂，誰共酌姮娥。"]'),
('0ffeb7be-25ed-4e60-b136-e3f00f983cad','絕句','萬哲','宋','宋诗','song-poetry','','[]','少日時時負百憂，從人絡馬與牽牛。',32,'全唐诗/poet.song.218000.json','["少日時時負百憂，從人絡馬與牽牛。", "中年置此身如竹，荏苒風前得自由。"]'),
('709a183e-928f-4975-8ccb-93d4851b5af9','理學','衛宗武','宋','宋诗','song-poetry','','[]','寥寥二千載，道統幾欲墜。',168,'全唐诗/poet.song.218000.json','["寥寥二千載，道統幾欲墜。", "濂洛暨關中，浚源接洙泗。", "乾淳諸大儒，流派何以異。", "無極而太極，性命發其秘。", "先天而後天，理數稽其至。", "四書共羣籍，精微窮奧義。", "五常與異端，辨析無遺旨。", "謂教以漸進，謂功可直遂。", "爲說雖殊科，其歸同一揆。", "踐修本誠敬，講貫非口耳。", "要在絕己私，渾然循天理。", "啟鑰以抽關，發蒙而警聵。", "後進有所宗，絕學得所繼。", "作者蔑以加，百世或可俟。"]'),
('10cde505-296d-4c4a-9074-fa47015717e7','君道','衛宗武','宋','宋诗','song-poetry','','[]','勳華相授受，謨典所具述。',144,'全唐诗/poet.song.218000.json','["勳華相授受，謨典所具述。", "其要在厥中，精一而允執。", "惟誠乃能精，惟誠乃能一。", "是以無黨偏，是以臻正直。", "三代所共守，百世不可易。", "伯者假仁義，戰國尚詐力。", "漢唐非無君，文爲事矯飾。", "其能粹而王，一指不可屈。", "所以無善治，循襲至今日。", "純誠而不雜，惟皇斯立極。", "斂敷錫庶民，懋建昭大德。", "治欲往古如，舍此他無術。"]'),
('1e5cfd12-a798-4f3a-bdda-8c3390417820','伊周','衛宗武','宋','宋诗','song-poetry','','[]','誓征黜夏命，武成有商邑。',96,'全唐诗/poet.song.218000.json','["誓征黜夏命，武成有商邑。", "惟王弗率祖，沖人初嗣歷。", "既放奉歸亳，已攝復明辟。", "前此所未聞，浮言曾罔恤。", "二公德動天，民亦歸其德。", "忠誠靡有他，上下素孚格。", "遂以直道行，觀聽自無惑。", "吁嗟人不古，後世幾新室。"]'),
('c04de4f2-327d-4abf-b7b8-5a1a2536e73e','漢文帝','衛宗武','宋','宋诗','song-poetry','','[]','愷悌而愛人，恭儉以持己。',120,'全唐诗/poet.song.218000.json','["愷悌而愛人，恭儉以持己。", "府庫有餘財，勿忍爲己費。", "田租奉公上，屢至爲民賜。", "不肯私嬖臣，以存大臣體。", "不敢私貴戚，以貽天下議。", "澹乎無嗜好，絕不尚功利。", "斷刑歲數百，煙火綿萬里。", "禮樂雖未遑，亦足爲善治。", "洪惟慶曆君，盛德槩相類。", "爰立俱名臣，後元則無是。"]'),
('ae88388b-4109-47c8-900c-24047d3cfc22','隋煬帝','衛宗武','宋','宋诗','song-poetry','','[]','方其爲儲貳，用智固已譎。',132,'全唐诗/poet.song.218000.json','["方其爲儲貳，用智固已譎。", "及夫據大器，爲謀抑何逆。", "龍舟及鳳譎，無歲不遊適。", "離宮與別殿，快意事淫佚。", "置酒燕要荒，會者三十國。", "紫舌與黄支，無所不臣服。", "親駕兩征遼，方且肆窮黷。", "羣盜遂蜂起，土地日以蹙。", "惛猶不知悟，愎諫輒誅戮。", "肘腋俄變生，兵刃交于目。", "不肖孰甚焉，身亡而國覆。"]'),
('73d180eb-dc8f-4f05-a4f3-281a0ff6dbd4','留侯','衛宗武','宋','宋诗','song-poetry','','[]','狙擊豈良圖，命幾危博浪。',108,'全唐诗/poet.song.218000.json','["狙擊豈良圖，命幾危博浪。", "既受黄石書，顛秦而蹶項。", "報韓志已酬，興漢畫仍贊。", "歷陳借箸計，潜消刻印患。", "定封謀遂寢，立嫡計莫尚。", "轉危以爲安，其易猶反掌。", "萬鍾誰不懷，裂土人所望。", "何勃身亦繫，韓彭國隨喪。", "駕言仙與遊，高風巢許上。"]'),
('37735e20-fd36-4c11-807c-93b839de1538','二疏','衛宗武','宋','宋诗','song-poetry','','[]','二君聳高致，今古知敬慕。',120,'全唐诗/poet.song.218000.json','["二君聳高致，今古知敬慕。", "勇退人所難，尤得所以去。", "貴戚舉愛弟，將使噲爲伍。", "天子尚衷疑，抗議非不許。", "儻或身久留，寧免與時忤。", "駕言盍知止，幡然解印組。", "歸來逸老壽，榮辱一無累。", "鬻金廣田宅，拒絕兒輩語。", "多財益其過，富爲衆怨府。", "賢哉乎斯言，奚止明出處。"]'),
('1c63cb21-ef06-4a01-9232-2fa317d88f98','孔明','衛宗武','宋','宋诗','song-poetry','','[]','龍卧而長吟，胸次抱奇偉。',132,'全唐诗/poet.song.218000.json','["龍卧而長吟，胸次抱奇偉。", "立心不北向，特爲三顧起。", "曹瞞下荆州，氣可吞權備。", "奮袂爲一出，遂成鼎足勢。", "忠誠以輔國，相業難擬議。", "刑政能服人，怨讎至感涕。", "出師陳悃款，訓誥相表裏。", "南攻孟獲平，北出張郃殪。", "司馬亦嚴憚，甘受巾幗恥。", "儻使先十年，營星未殞墜。", "興復其可期，中原安有魏。"]'),
('8833662c-8b75-4730-b738-9ec30d7ab13a','荀彧','衛宗武','宋','宋诗','song-poetry','','[]','曹公初見奇，直以子房許。',120,'全唐诗/poet.song.218000.json','["曹公初見奇，直以子房許。", "制勝算無遺，斃袁而誅呂。", "意見稍有乖，幾欲置鼎俎。", "朝端存正論，九錫胡不取。", "本初固難依，姦雄惡可輔。", "初年殲德祖，繼又族文舉。", "嗜殺其如斯，大夫可以去。", "見幾奚不早，一死昧所處。", "既不爲夷齊，又不爲伊呂。", "徒抱忠貞心，遺憾亙千古。"]'),
('41bea75b-c10f-4ccc-b7de-275861eda769','韓延之','衛宗武','宋','宋诗','song-poetry','','[]','劉公復晉祚，功成萌異志。',120,'全唐诗/poet.song.218000.json','["劉公復晉祚，功成萌異志。", "網羅欲用才，翦除不附己。", "荆州乃巨鎮，肯容司馬氏。", "家兒特小過，親駕勤問罪。", "延之乃其客，折柬謂可致。", "善乎爲辭令，伐君啖人利。", "誓與臧洪俱，身殞遊九地。", "啟緘示僚佐，事人固當爾。", "背主以從讎，自昔滔滔是。", "儻使閲此書，雖死有餘愧。"]'),
('35af20c2-ee47-4814-b0d8-8867e4188307','顔魯公','衛宗武','宋','宋诗','song-poetry','','[]','人之生也直，不直匪君子。',108,'全唐诗/poet.song.218000.json','["人之生也直，不直匪君子。", "一從平原歸，立朝更奇偉。", "挺挺盡孤忠，蹇蹇陳正義。", "初年忤元載，晚節遇盧杞。", "不爲時宰容，乃作天子使。", "正言明順逆，兇儔知敬畏。", "未幾變異生，卒墮奸邪計。", "羅浮寄遠音，流傳涉疑似。", "英烈天啟之，萬世凜生氣。"]'),
('b3020401-0c7d-4f24-8eb2-3bcd38d5e223','知足','衛宗武','宋','宋诗','song-poetry','','[]','束髮至皓首，雅意在林谷。',192,'全唐诗/poet.song.218000.json','["束髮至皓首，雅意在林谷。", "退閒十五年，一官如脫梏。", "抱關尋故步，謬語不可贖。", "投紱賦歸來，幸不至迷復。", "有田可餉饑，有園可寄目。", "有屋枵然大，其中無所蓄。", "代步跨款段，課耕驅觳觫。", "斗筲量易盈，菟裘計已足。", "嘅方際時艱，已幸免僇辱。", "年豐喜洊臻，我庾有新穀。", "床頭酒一壺，架上書數束。", "酒餘取書誦，豈不勝絲竹。", "水北與城南，蒼筠列萬玉。", "更須倣元亮，剩種松與菊。", "招邀文字侶，吟哦日相屬。", "自足了餘生，此外復何欲。"]'),
('8d992c48-0aa8-422f-9dcc-691c70be1502','春懷  其一','衛宗武','宋','宋诗','song-poetry','','[]','伊耆司化權，與物何落落。',96,'全唐诗/poet.song.218000.json','["伊耆司化權，與物何落落。", "不見陽和敷，但聞風雨惡。", "柔綠尚含滋，水紅慳破萼。", "動植久陵暴，至仁同橐籥。", "可使令行冬，寒威肆餘虐。", "便須轉機栝，曜靈俾灼爍。", "芬芳千萬林，薰爲紅紫幄。", "庶俾競春徒，薄有登臺樂。"]'),
('ade38108-3418-444f-931c-7e795b8fc66f','春懷  其二','衛宗武','宋','宋诗','song-poetry','','[]','乾坤日以闢，生意日以隘。',108,'全唐诗/poet.song.218000.json','["乾坤日以闢，生意日以隘。", "春風一披拂，萬族競蘇快。", "肖翹與蠕動，靡不忻坼解。", "慶澤流光華，垂榮到菅蒯。", "山木豈自寇，孰翦而孰拜。", "根幹儻有遺，滋萌乃復在。", "蒼籙溥至仁，何類不昭泰。", "人爲物之靈，元化忍獨外。", "氣運何日回，歲月易征邁。"]'),
('9527ad2c-2744-4d92-a40e-f19040ba9756','春懷  其三','衛宗武','宋','宋诗','song-poetry','','[]','時來桃李妍，春風乃知己。',108,'全唐诗/poet.song.218000.json','["時來桃李妍，春風乃知己。", "時去桃李萎，春華俱夢寐。", "芳菲氣不齊，一一理猶是。", "何如松與柏，無榮亦無悴。", "浮生寄旅亭，萬事若流水。", "富貴等空花，滅沒無足紀。", "身前苟遺臭，身後烏可洗。", "我願爲松柏，不願爲桃李。", "長保千歲姿，盤根澗阿底。"]'),
('320f0f49-d797-4c8f-ab3c-64c8f130b1da','春雨','衛宗武','宋','宋诗','song-poetry','','[]','青皇初布令，大塊已流濕。',192,'全唐诗/poet.song.218000.json','["青皇初布令，大塊已流濕。", "霏霏散沖融，一一成膏液。", "駸尋夜漏分，掀揚風箭疾。", "孤燈月明眼，漸覺簷花密。", "滴瀝聲既洪，淋浪勢方集。", "清響迸源泉，美澤徧原隰。", "甘腴滋田毛，浸灌融地脉。", "蓋將兆稌黍，豈但秀薺麥。", "溪山鱗甲長，卉木攢新碧。", "化工悅萬族，生意浩無極。", "苟惟本根在，孰不芽且坼。", "未春雨非土，見者自凄惻。", "既春雨非玉，聞者何悅懌。", "未能齊慘舒，吾亦爲物役。", "英英梅粉露，點點桃紅入。", "更喜釀芳菲，催花居第一。"]'),
('ade31164-8792-4415-9365-b43c0fab8359','立春出郊風急有作','衛宗武','宋','宋诗','song-poetry','','[]','意行出郊坰，迎春二之日。',96,'全唐诗/poet.song.218000.json','["意行出郊坰，迎春二之日。", "不聞條風鳴，但見朔風急。", "朔風何太嚴，厲物無洪纖。", "時方尚發育，豈汝當行權。", "試與東皇說，燠寒宜按節。", "一氣鼓至和，要令無夭閼。", "我老值途窮，荷鍤今爲農。", "但願五時若，鼓腹歌豳風。"]'),
('5fdd0bd2-2360-42e0-857e-35d73d6b2d56','次韻春  其一','衛宗武','宋','宋诗','song-poetry','','[]','水行苦嚴厲，萬彙喜得春。',96,'全唐诗/poet.song.218000.json','["水行苦嚴厲，萬彙喜得春。", "解雷久忽震，蟄戶奮者殷。", "根芽沐膏雨，暘暉復熹晨。", "淑氣盎原野，鼎鼎來芳辰。", "小車度花陰，遊芳浮麴塵。", "少年爭競春，外誘何紛紛。", "老矣蠲其華，寄賢而葆真。", "多吟以爲富，猶恐道益貧。"]'),
('e607da09-fbc6-45e2-b5b9-343c88ba49f2','次韻春  其二','衛宗武','宋','宋诗','song-poetry','','[]','熙陽薰蓋壤，麗景日以新。',72,'全唐诗/poet.song.218000.json','["熙陽薰蓋壤，麗景日以新。", "婭姹花媚晝，嚘嚶鳥鳴晨。", "紛華易消歇，非久淪沙塵。", "舉世競芳菲，湎若嗜飲醇。", "豈知有至味，澹然嚌道真。", "試問金谷夫，何如簞瓢人。"]'),
('d3af846c-4d18-4844-9f30-a3fc0e4b9874','次韻春  其三','衛宗武','宋','宋诗','song-poetry','','[]','物華來冉冉，天氣宜溫溫。',84,'全唐诗/poet.song.218000.json','["物華來冉冉，天氣宜溫溫。", "浪浪但鳴雨，浩浩常浮雲。", "誰知潤澤中，厥有豐美存。", "一朝日出杲，絢爛赬紫羣。", "川原徧塗抹，紛若粉黛陳。", "芳菲出枯槁，何異富易貧。", "難并惟樂事，昔人嘗有云。"]'),
('ad1d9212-e737-4bd7-b059-64f71d69d66b','次韻春  其四','衛宗武','宋','宋诗','song-poetry','','[]','方寸負奇偉，自足排外紛。',84,'全唐诗/poet.song.218000.json','["方寸負奇偉，自足排外紛。", "樂哉曾子履，翛然淵明巾。", "利欲伐其性，智識由是昏。", "盛麗悅其目，夢幻何足云。", "不如覷文字，日月從轉輪。", "飲芳而咀華，四時無非春。", "芸芸市朝客，孰識此味真。"]'),
('4c348a47-22c4-4f2b-8169-9dc479f6ca81','春山','衛宗武','宋','宋诗','song-poetry','','[]','青山四時好，春至尤盛麗。',180,'全唐诗/poet.song.218000.json','["青山四時好，春至尤盛麗。", "潤澤散沖融，華滋出枯悴。", "雲根鱗甲動，風柯羽旄曳。", "羣芳間點染，一碧互經緯。", "組繡列障陳，繢畫崇屏倚。", "嵬昂如帝尊，黼黻儼衣被。", "我老得餘暇，時來領勝事。", "穿雲度舟楫，披霧縱屐履。", "涓泉幽響生，鳴鳥繁聲脆。", "天然成妙奏，人籟惡可擬。", "息游返靖廬，紛華以靜對。", "獨坐勘古書，冥觀參物理。", "光景猶駒馳，色象亦蟬蛻。", "至人善觀山，夫豈悅浮靡。", "懿此靜秀姿，萬古挹清致。"]'),
('9690c6d9-9bb3-4265-b628-e67f6327dd55','塾樓春集次日和兒輩韻','衛宗武','宋','宋诗','song-poetry','','[]','伊耆噓至和，薰播彌大地。',288,'全唐诗/poet.song.218000.json','["伊耆噓至和，薰播彌大地。", "有聲沸候禽，有色衒名卉。", "麗景接川原，浩萬歷歲幾。", "于時不得樂，夫人自暴棄。", "卑官徒勞人，憶昔續賓戲。", "繼忝隸部曹，厠迹於朝市。", "未幾乘漢鄣，歸來從綺里。", "誓當守衡茅，不復問行李。", "方開陶徑荒，遽驚周室燬。", "時艱慨適逢，身存良自喜。", "築廬傍山棲，視家如客邸。", "雖存蓬蓽居，僅爲燕雀芘。", "茲辰薄遊衍，携友忘汝爾。", "書樓舒遠眺，林芳猶蛻委。", "麥隴連蔬畦，青黄錯成綺。", "野色入杯棬，山光浮屐底。", "陽春艷欲流，霽景浩無際。", "獻酬樂佳賓，續廣頼吾子。", "朝來補吟事，粗不忝詩禮。", "顧余八十叟，忘我忘忘世。", "醺餘扶杖歸，笑語喧童稚。", "斯遊固已適，未足窮樂意。", "九峰葦可杭，相望在尺咫。", "憂先天下憂，樂豈果在是。"]'),
('00a8adb7-8c70-4891-aa61-8b61705c8d6b','和野渡家園雜興  其一','衛宗武','宋','宋诗','song-poetry','','[]','幽人非嗜石，適意在嶙峋。',72,'全唐诗/poet.song.218000.json','["幽人非嗜石，適意在嶙峋。", "萬形何足多，一卷未爲貧。", "山奚必泰華，水奚必海濱。", "藏珠川乃媚，韞玉璞足珍。", "儻存丘壑意，可障世俗塵。", "烟霞從此生，自足怡性真。"]'),
('adca98a5-e320-414b-b052-c3efd76b5dbe','和野渡家園雜興  其二','衛宗武','宋','宋诗','song-poetry','','[]','雅士酷愛竹，無肉饑亦忍。',72,'全唐诗/poet.song.218000.json','["雅士酷愛竹，無肉饑亦忍。", "即之俗自祛，對此酌宜引。", "好尚契子猷，題詠邁元稹。", "二友獨與交，十客何敢竝。", "丈夫意氣豪，少年精爽緊。", "春至長子孫，班班森玉筍。"]'),
('552e2e17-fcaa-4ad3-8c6e-a42e3064506a','和野渡家園雜興  其三','衛宗武','宋','宋诗','song-poetry','','[]','誰謂野燒生，惡草不須薙。',72,'全唐诗/poet.song.218000.json','["誰謂野燒生，惡草不須薙。", "爲蕭易成叢，滋蔓或布地。", "不別小人儔，恐昧前賢意。", "舞茵含晴曛，經带摇輕吹。", "拂拂來野香，萋萋動幽思。", "坐對一庭芳，煮茶消午睡。"]'),
('f0bd2aa7-5b3b-40a4-8d1d-da876895e796','和野渡家園雜興  其四','衛宗武','宋','宋诗','song-poetry','','[]','綠稠紅欲盡，架竹引酴醾。',72,'全唐诗/poet.song.218000.json','["綠稠紅欲盡，架竹引酴醾。", "葳蕤晴雪艷，汗漫春風枝。", "燕鶑相見晚，蜂蝶正忙時。", "芳辰似歷塊，樂事猶殘棋。", "可憐香骨銷，但有綠鬢垂。", "春歸恨難挽，浮絮盈芳池。"]'),
('5ff2e28c-22ca-462e-ab0f-6876714664af','己卯雨後春興呈吟友','衛宗武','宋','宋诗','song-poetry','','[]','一氣散沖融，生意溢羣動。',228,'全唐诗/poet.song.218000.json','["一氣散沖融，生意溢羣動。", "膏澤溜涓涓，物華來總總。", "孤芳擅魁元，衆卉遂賓從。", "丹碧互鮮妍，低昂相錯綜。", "茵鋪五茸稠，旆接千林聳。", "爲媒想雉驕，求友悅鶑哢。", "絲繭富桑疇，餠餌馨麥隴。", "耕犁雨既肥，荷鍤雲成滃。", "花間車可乘，果下馬宜鞚。", "駸尋光景流，瀟洒日月送。", "悅情書一編，舒憂琴四弄。", "九仞功徒勞，三逕步莫縱。", "空羨蘭亭遊，惟存草池夢。", "郊原初駘蕩，風塵息澒洞。", "良辰悵易逾，雅志浩難控。", "春吟料滿囊，春釀香浮甕。", "春水玉交流，春山翠如涌。", "樂事勿復論，幽尋猶可共。", "王謝何人斯，吾將繼芳踵。"]'),
('9bee9710-b808-4b99-9828-a4215fbba210','竹外海棠','衛宗武','宋','宋诗','song-poetry','','[]','我有三徑園，今爲牛馬皂。',204,'全唐诗/poet.song.218000.json','["我有三徑園，今爲牛馬皂。", "傍家尋丈地，昔未長荼蓼。", "琅玕數十挺，新培歲可考。", "幻出一庭陰，咫尺成深窈。", "客來可款延，友至或徑造。", "于時正芳菲，所欠花繚繞。", "隔籬舊封植，一種媚而好。", "卷翠護春姿，嬌紅衒天巧。", "折來侑清尊，嫣然爲一笑。", "絕勝歌舞羣，聲容託幻眇。", "久欲構小亭，爲計恨不早。", "金屋延阿嬌，祇恐人易老。", "此花擅春妍，獨恨易榮槁。", "豈若對此君，四時森羽葆。", "不惟祛塵俗，端可助吟嘯。", "良辰集朋簪，杯柈慚草草。", "於焉小徜徉，即此是幽討。"]'),
('ba199aec-997c-4afd-b506-cab0c227883e','寓蕭塘皆春堂偶成','衛宗武','宋','宋诗','song-poetry','','[]','紅雲逐水流，春事隨飛揚。',192,'全唐诗/poet.song.218000.json','["紅雲逐水流，春事隨飛揚。", "昔嗟節序移，今苦歲月長。", "洊爲蕭水遊，物是人則亡。", "西園得逍遥，暫寄風雨床。", "欒欒荆棘中，尚餘頳紫粧。", "晚芳衒鮮妍，婉娩春滿堂。", "倚欄俯澄碧，浩蕩花藕塘。", "壽柏虬龍姿，古桂鴻鴈行。", "幽禽三五弄，髣髴疑宮商。", "林園豈不好，惆悵辰匪良。", "辰良其何時，世運安有常。", "我欲把犁鋤，老此桑麻鄉。", "却虞遠城市，物怪尤披猖。", "不如依墳壚，結茅千仞岡。", "寄玄而棲白，抗志於羲黄。", "清泉碧嶂間，歿則於斯藏。"]'),
('c9d13296-a206-481c-897c-ba0e9954b2c9','山行','衛宗武','宋','宋诗','song-poetry','','[]','携友行莫春，山南復山北。',108,'全唐诗/poet.song.218000.json','["携友行莫春，山南復山北。", "一川去縈紆，層林互倚伏。", "舍舟上孱顔，萬象咸在目。", "野花衒殘紅，柔條曳新綠。", "春巒潤如酥，春水流如玉。", "芳草浩無涯，好鳥鳴相續。", "老閲幾歲華，看山看不足。", "凡物各有時，時去時必復。", "顧我豈物如，此生何能穀。"]'),
('a42104f7-c900-41b1-9fae-78e405cfd8c7','將到霅隴','衛宗武','宋','宋诗','song-poetry','','[]','春巒如佳賓，應接何敢暇。',144,'全唐诗/poet.song.218000.json','["春巒如佳賓，應接何敢暇。", "我來日與對，不覺迫初夏。", "繁林湧翠霧，經綜密無罅。", "鳴鳥間啼鶑，鄭音忽奏雅。", "萋萋碧草間，曄曄赬紫亞。", "幽棲絕俗交，燕坐陪僧話。", "論事覈古今，談禪悟生化。", "新茗瀹雲濤，迥勝酒新醡。", "嘉蔬煮玉版，可鄙食肉者。", "時誦淵明詩，萬慮足陶寫。", "芳春背人去，歸舟行步駕。", "好山不可載，寫入無聲畫。"]'),
('ffd282ef-c128-42b6-b2a4-0112304f46d0','寄道友','衛宗武','宋','宋诗','song-poetry','','[]','憶昨君有行，飄飄氣欲僊。',96,'全唐诗/poet.song.218000.json','["憶昨君有行，飄飄氣欲僊。", "去作蘇門嘯，不覺晚歲年。", "雲采照高秋，盟言尚無愆。", "遠音傳征鴻，俄乃栖冷泉。", "北山有野鶴，長唳聲聞天。", "高人遊華胥，豈不驚晝眠。", "囊中寶苑書，香翰徒聯翩。", "安得九靈光，曄曄飛我前。"]'),
('a4a5bff6-c8bb-4eef-a72b-2e416632b97e','自茶塢歸禾中墳庵賦','衛宗武','宋','宋诗','song-poetry','','[]','既雨俄喜晴，既晴旋復雨。',132,'全唐诗/poet.song.218000.json','["既雨俄喜晴，既晴旋復雨。", "老年困肩輿，僕夫苦行路。", "霏霏霧氣收，冉冉陽明吐。", "乾端頓收豁，物象各呈露。", "晴巒含春暉，娟娟如靚女。", "枯槁變華滋，萬綠新織組。", "澗花度幽香，谷鳥試新語。", "勝槩未易窮，可挹不可取。", "我來事幽討，惟恐商羊舞。", "願天衍霽期，助我發吟趣。", "歸來日未晡，一聲聞杜宇。"]'),
('d995a264-744a-4cdd-8275-a8e7855bc3b6','錢竹深招泛西湖值雨即事','衛宗武','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖成久別，歲月不可記。',288,'全唐诗/poet.song.218000.json','["西湖成久別，歲月不可記。", "竹君秩豆籩，枌友集簪履。", "放船及中流，烟靄渺無際。", "宛類太極初，混沌但一氣。", "浩浩雲常浮，垂垂雨不止。", "樓觀列畫圖，黯淡微茫裏。", "素粧姿態妍，於此見西子。", "纔入西陵橋，林巒得近似。", "緩步香月堂，循山歷其址。", "逋僊去何之，千古儼清致。", "淋漓雨珠僊，一一浴未起。", "粲然間紅粧，臉霞淚如洗。", "餘芳襲壺觴，暗馥散襟袂。", "十里花柳堤，六橋風月地。", "暝色壓舩舷，遊屐不可至。", "昌翔度裏湖，兩山濃滴翠。", "中有白鳥閒，翩翩自遊戲。", "幾年阻行樂，謂有公閭第。", "棟宇半蒼苔，遺汙漬清泚。", "興亡成古今，感愾重歔欷。", "轉柁邇城隄，觥籌猶未既。", "風生語笑高，雲遏歌聲曳。", "斯遊屬晏陰，樂事亦足紀。", "何時可重來，風日待清美。"]'),
('b18b7897-21cf-4a63-8d3d-52abaf94e701','對竹衍坡詩意','衛宗武','宋','宋诗','song-poetry','','[]','爾來食無肉，所喜居有竹。',84,'全唐诗/poet.song.218000.json','["爾來食無肉，所喜居有竹。", "森森無千纛，挺挺立羣玉。", "嬋娟而鮮潤，偏悅隠者目。", "苟使清可娛，何妨飽不足。", "小人求屬厭，君子肯爲腹。", "餘生復何爲，一事無足錄。", "惟應對此君，細把坡詩讀。"]'),
('e7a20b66-1515-49cd-b9da-f7e71ba0f5ce','賦南墅竹','衛宗武','宋','宋诗','song-poetry','','[]','物得氣之清，鍾秀莫如竹。',288,'全唐诗/poet.song.218000.json','["物得氣之清，鍾秀莫如竹。", "是謂東南美，羣植可奴僕。", "虛心而獨立，勁節不囘曲。", "傍屋著數挺，能洗塵萬斛。", "截之作鳳鳴，雌雄相配六。", "殺以爲汗青，奚啻十年讀。", "有體兼有用，迥異凡草木。", "騷人互題品，國風嘗紀錄。", "子有步仞丘，殆類篔簹谷。", "老筠依雲根，錯出勝千陸。", "矯虔相長雄，高下森立玉。", "霏霏霧滴翠，灧灧浪翻綠。", "蟠根龍蛇走，密葉鸞鳳蹙。", "林飈振微響，環珮聲戛觸。", "瑣碎流金輝，霽曉弄清旭。", "熙陽發菁華，婀娜舞桂纛。", "滋萌長雲仍，一一錦䙀束。", "火輪行長空，炎歊暑方酷。", "枕簟入幽深，灑若寒露沃。", "秋月映嬋娟，清影夜相屬。", "歲寒交勝友，南枝花倚伏。", "四序景無涯，風月任追逐。", "人謂小渭川，我忝共淇澳。", "邀朋對此君，豈惜醉醽醁。"]'),
('45cee969-2274-4445-a5cb-ec9dbd23f841','賦西軒竹','衛宗武','宋','宋诗','song-poetry','','[]','種竹纔一畝，便有千畝勢。',204,'全唐诗/poet.song.218000.json','["種竹纔一畝，便有千畝勢。", "苟能會其趣，何拘尋丈地。", "其氣偉丈夫，其德象君子。", "瑩哉冰雪如，潤與珪璋比。", "中虛而有容，外直而不倚。", "迥非凡植儔，惟與喬松齒。", "攬以入吟篇，引以近書几。", "好之而樂之，雅致要相似。", "物清我亦清，相對乃無愧。", "翛然靜秀姿，舉世所同嗜。", "志趣有不侔，肝膽楚越異。", "將以洗凡俗，凡俗烏可洗。", "綠猗喻武公，金璧侈歸美。", "蕭瑟悅宣尼，食肉至忘味。", "有之而似之，氣類由默契。", "此君如有知，噲伍亦所恥。", "苟或冰炭然，雖多亦奚以。"]'),
('ad0f6f5f-e9a6-420f-918c-f0c695e97aae','爲僧賦竹泉詩','衛宗武','宋','宋诗','song-poetry','','[]','竹不可無水，有水必有竹。',72,'全唐诗/poet.song.218000.json','["竹不可無水，有水必有竹。", "彼美槃澗阿，碧鮮映澄綠。", "漱石戛鳴球，拂雲森立玉。", "苟得一以清，而况二吾足。", "上人要心契，毋但悅其目。", "物我趣不侔，亦恐難醫俗。"]'),
('68bd54bd-893c-4586-9859-9877025d1b54','初夏登北山  其一','衛宗武','宋','宋诗','song-poetry','','[]','春山如佳人，形色麗而秀。',264,'全唐诗/poet.song.218000.json','["春山如佳人，形色麗而秀。", "茲來悵非時，已入朱明候。", "片紅飛不留，萬綠新改舊。", "接茵芳草蔓，偃蓋古木茂。", "黛鬟臨水鏡，一色浄無垢。", "戛然鳴聲幽，雅弄出禽口。", "得閒此夷猶，不覺留滯久。", "一葉泛澄川，縈回歷農畝。", "决渠散青秧，耕夫類成偶。", "舍舟挾短筇，崎嶇度重阜。", "野芳氣如蘭，冉冉襲襟袖。", "逶迤窮山椒，寸懷納宇宙。", "川原浩無涯，萬象皆我有。", "滄溟杳渺間，雲夢吞八九。", "昌黎開衡雲，羊公登峴首。", "顧我凡陋資，視此亦培塿。", "雖然形氣殊，興趣無異否。", "獨嗟今昔殊，人事有遷貿。", "而我老無聞，將與草木朽。", "陟巘復降原，玄廬新結構。", "伊傅不可懷，松喬以爲友。", "不死非所求，姑以佚吾壽。"]'),
('f5e643d9-e875-48ed-b501-c2188c8e37b9','初夏登北山  其二','衛宗武','宋','宋诗','song-poetry','','[]','屢月不見山，胸次若逼窄。',120,'全唐诗/poet.song.218000.json','["屢月不見山，胸次若逼窄。", "舉棹遠相望，已漬雙眸碧。", "即之清入神，喜復遂良覿。", "非但塵思浣，頓覺餘疴失。", "玉流浸層巒，緣雲抱幽石。", "草木去浮誇，秋容浄如拭。", "我來誰與儔，一道兼一釋。", "精廬既窈深，靖宇尤邃密。", "吟哦對青嶂，瀟洒娛白日。", "奩香勘南華，孰爲寥天一。"]'),
('6d0093ff-7eab-4407-9b64-c804122d3742','初夏登北山  其三','衛宗武','宋','宋诗','song-poetry','','[]','出郭望遥岑，闒冗僅抔土。',168,'全唐诗/poet.song.218000.json','["出郭望遥岑，闒冗僅抔土。", "何異龍蜿蜒，或若鳳騰翥。", "兩岫更奇崛，不肯與噲伍。", "烟雲或凝散，日月遞吞吐。", "葱葱氣佳哉，景物此會府。", "五茸三泖區，南東淮海距。", "带接幾百川，盤亙千萬畝。", "於中不著山，勝槩將焉取。", "繇茲鍾神秀，人物亦翹楚。", "所以機雲輩，落筆有奇語。", "猶嫌氣節卑，未以勳業許。", "何當地闡靈，英賢更旁午。", "如眉有翁季，似岳生申甫。", "壯觀此九峰，佳名昭萬古。"]'),
('2c785dfc-01ac-4280-b943-4db4a40885e2','小園避暑','衛宗武','宋','宋诗','song-poetry','','[]','六月畏酷熱，簟枕依林塘。',228,'全唐诗/poet.song.218000.json','["六月畏酷熱，簟枕依林塘。", "古木同臭味，幽鳥含宮商。", "天孫雲錦機，丹碧交薦香。", "晴瀾泛清薰，襟袂生微凉。", "巉巉萬石間，修筠間新篁。", "羽葆列千挺，灧灧浮綠光。", "林飈一戛擊，環珮聲鏗鏘。", "披衣獨危坐，意氣超羲黄。", "豈惟熱惱除，冰雪置我腸。", "却愁林外人，久苦炎威張。", "天瓢忽傾倒，旱魃宜消亡。", "是月已火流，不日占金穰。", "時雖厭兵革，人或飽稻粱。", "此園僅如握，無徑不就荒。", "猶喜卉木存，弗爲斤斧戕。", "揚揚桂吐芬，粲粲菊有芳。", "清賞備四時，花辰復青陽。", "太平本無象，嗣歲或小康。", "於焉盍朋簪，一笑傳清觴。"]'),
('f85db9c8-8592-477c-b4a8-ae29419e02ed','久晴喜雨詩','衛宗武','宋','宋诗','song-poetry','','[]','日夕庚暑袢，無以袪熱惱。',132,'全唐诗/poet.song.218000.json','["日夕庚暑袢，無以袪熱惱。", "甘霔從何來，雷轟電光繞。", "勢如天潢翻，滂流浹清曉。", "六合開新宇，一氣蘇羣槁。", "凉颸散窗戶，炎熇泯如掃。", "從此協雨暘，免使虞旱澇。", "庶幾膴膴原，俱斂穰穰寶。", "大東與小東，民力差已耗。", "天公匪憒憒，善應固有道。", "未憂供百需，且欲資一飽。", "維魚行協占，焚尪頌有昊。"]'),
('1fcd0c15-bf07-4350-bc90-3406fed925b1','立秋喜雨','衛宗武','宋','宋诗','song-poetry','','[]','天心本至仁，生意豈有息。',120,'全唐诗/poet.song.218000.json','["天心本至仁，生意豈有息。", "粵從書夏五，甘霔絕點滴。", "涼風自西來，時送中夜濕。", "田腹泯龜文，屋角掛龍骨。", "我稷與我黍，實穎而實栗。", "屢豐固難望，一飽或可必。", "豈惟曾孫庾，如坻亦如櫛。", "滯穗不斂穧，可續窮民食。", "但虞耗鼠雀，尤恐資螟螣。", "願減漢民租，少裕東南力。"]'),
('bf4cf83f-a59a-46e9-ab84-17a02dc8f933','甲申過北山高祖大夫墳庵見盆芝','衛宗武','宋','宋诗','song-poetry','','[]','我祖藏北山，昔嘗産紫芝。',132,'全唐诗/poet.song.218000.json','["我祖藏北山，昔嘗産紫芝。", "庵以此得名，且將二百朞。", "耳聞非目接，至老心猶疑。", "一朝地闡靈，枯槁生神奇。", "曄曄根幹間，挺秀分三枝。", "採者不善護，猶惜其一遺。", "移置盆盎中，赬黄互相輝。", "豈殊子聞韶，不圖樂至斯。", "第嗟魯獲麟，所出非其時。", "吾年已如此，斯祥將奚爲。", "獨思避世士，商嶺其在茲。"]'),
('79ed3bfb-abe1-46ef-aa3a-cb98a557b63c','是歲之夏紫芝復生成叢大者徑七八寸','衛宗武','宋','宋诗','song-poetry','','[]','異物不易遇，其出由地靈。',240,'全唐诗/poet.song.218000.json','["異物不易遇，其出由地靈。", "伊耆闡坤珍，三秀既挺生。", "賦形雖恨小，殊喜見未曾。", "朱明復薦祥，僊種茂叢莖。", "小者既敷腴，大者尤輪囷。", "周遭徑盈尺，菌蠢疊成層。", "團團盤赤玉，艷艷盃紫金。", "霏烟氣葱鬰，映日光晶熒。", "神芝産冢阜，歲久迹已陳。", "不圖餘七袠，一再見斯今。", "有開必有先，休符不徒呈。", "老矣百無欲，弗願在其身。", "所積顧不厚，敢覬及子孫。", "惟冀福吾宗，以洎邦之人。", "皇穹其畀矜，茂毓賢與英。", "出際風雲會，爲世建太平。", "漢代歌芝房，其事不足云。", "致君堯舜上，朝野沸頌聲。", "復見祥蓂敷，豈但朱草榮。", "散爲天下瑞，郁郁而紛紛。"]'),
('c0397d17-f3e3-4835-b66c-7bc50e275ad4','秋懷  其一','衛宗武','宋','宋诗','song-poetry','','[]','秋空日澄霽，秋氣日蕭瑟。',72,'全唐诗/poet.song.218000.json','["秋空日澄霽，秋氣日蕭瑟。", "塞馬健嘶風，候蟲悲弔夕。", "卉木斂華滋，天地失顔色。", "來鴻謀稻粱，飛隼快搏擊。", "人境頓凄凉，物情亦悽惻。", "憂愁豈無端，感歎繼韓筆。"]'),
('ac987fa2-4c13-4196-8b34-b1f39ac73783','秋懷  其二','衛宗武','宋','宋诗','song-poetry','','[]','凉飈翦菑翳，萬山縮鱗甲。',72,'全唐诗/poet.song.218000.json','["凉飈翦菑翳，萬山縮鱗甲。", "水鏡滓不留，千尺見毛髮。", "凄風日以高，物華寖脧削。", "機杼軋晨霜，砧杵搗寒月。", "孤暌不成寐，耿耿至明發。", "何處一聲秋，停雲吹欲裂。"]'),
('5bf9eb9d-8bd1-4bba-aed6-fce08aae71e4','秋懷  其三','衛宗武','宋','宋诗','song-poetry','','[]','往事挽不回，新愁推不去。',72,'全唐诗/poet.song.218000.json','["往事挽不回，新愁推不去。", "秋葉既辭柯，滋榮春復吐。", "榆年逝如流，顔色寧反古。", "展書聖賢對，援琴兒女語。", "撫時耿予懷，聊以釋百慮。", "餘生欲何爲，將隨草木腐。"]'),
('ef9cb3a9-bc5f-4d45-b5c1-f12df702fc07','秋懷  其四','衛宗武','宋','宋诗','song-poetry','','[]','衰質蒲柳如，日夕就枯槁。',72,'全唐诗/poet.song.218000.json','["衰質蒲柳如，日夕就枯槁。", "往夢桃李春，其能幾日好。", "志業亦無成，飄零逐衰草。", "浮榮豈足懷，妄念猶風掃。", "陳言亦刊落，損學而促道。", "誓當與世違，山林以終老。"]'),
('76cfc83f-f469-476a-9769-1808a0899368','秋懷  其五','衛宗武','宋','宋诗','song-poetry','','[]','秋至山愈奇，獨不入凡目。',72,'全唐诗/poet.song.218000.json','["秋至山愈奇，獨不入凡目。", "翳薈既掃除，清峭如削玉。", "剝落千林空，中有歲寒木。", "雪霜自凝沍，柯葉不改綠。", "猶夫古君子，凜不可榮辱。", "貞心以自持，烏肯混流俗。"]'),
('f5addb78-6682-4768-a51b-a24825b8cb64','秋懷  其六','衛宗武','宋','宋诗','song-poetry','','[]','浩浩秋水生，江河若放溜。',72,'全唐诗/poet.song.218000.json','["浩浩秋水生，江河若放溜。", "翳滓一洗清，山川愈明秀。", "惟夫沮洳區，朝滿夕已垢。", "疏滌曾幾何，起穢復自臭。", "何異賤丈夫，逐利日貿貿。", "委志合羣污，氣類不改舊。"]'),
('a12e1532-1cc6-41c0-9bb9-46d1f22b5b3d','秋懷  其七','衛宗武','宋','宋诗','song-poetry','','[]','屋隅一握地，歲久寖蕪穢。',84,'全唐诗/poet.song.218000.json','["屋隅一握地，歲久寖蕪穢。", "茲晨命僕夫，疏剔浄無翳。", "洞目增秋明，彌襟挹凉氣。", "春葩已辭榮，柯葉猶蔽芾。", "晚芳粲黄金，新篁間幽桂。", "欲幻小池亭，西風幾凄厲。", "只今欠一死，肯作百年計。"]'),
('ae8fa41e-8f8b-4356-b94b-774534b51da6','秋山','衛宗武','宋','宋诗','song-poetry','','[]','秋山抱奇姿，不肯事嫵媚。',192,'全唐诗/poet.song.218000.json','["秋山抱奇姿，不肯事嫵媚。", "猶夫塵外士，飄然有仙氣。", "霜風肅宇宙，林壤去菑翳。", "皮毛剝落盡，玉骨乃挺異。", "獨存歲寒枝，虬髯倚天翠。", "我來一事無，兀兀惟坐對。", "挾策詠聖涯，援琴奏流水。", "方寸如太虛，物類無點綴。", "但欠淵明菊，得酒莫與醉。", "頼有坡仙竹，無肉可忘味。", "老懷藉陶寫，俗好非所嗜。", "平生愛山癖，每見如久契。", "勿云丘垤如，泰華所眇視。", "吾心與境融，小大無異致。", "行行陟其巔，天地特一指。", "忽動九辨悲，清愁飛海外。"]'),
('cc9b3884-991b-4a58-abb2-9fe4e734541f','山行鄉友遺五言','衛宗武','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','一雨如膏沐，秋山爲我容。',168,'全唐诗/poet.song.218000.json','["一雨如膏沐，秋山爲我容。", "誰云乏神秀，遐想猶岱宗。", "絕無喜僅有，疇列茲羣峰。", "繚繞若仙城，花但無芙蓉。", "幽香含桂菊，積翠浮杉松。", "生平嗜林谷，不厭來轍重。", "幾躡靈運屐，屢扶張騫筇。", "鷺朋與鷗侶，足爲談笑供。", "折簡不可招，欠致人中龍。", "毫端具造化，物象工陶鎔。", "吟思方淵渟，風撓鳴淙淙。", "佳章忽在前，撩動此興濃。", "君胡倦一出，嘲詠乃不傭。", "且勤遠致饋，與客叨飧饔。"]'),
('3dbfc767-4d5a-41c8-bfae-4aa6e0c18009','北山回櫂','衛宗武','宋','宋诗','song-poetry','','[]','高風掃羣翳，山色秀而靜。',48,'全唐诗/poet.song.218000.json','["高風掃羣翳，山色秀而靜。", "寒林隠虬龍，幽徑行蛇蚓。", "場登䆉稏實，水弄芙蓉影。", "明發汎歸舟，秋空更青迥。"]'),
('0b5c12c7-33b0-4a05-a112-40a1182ecca6','賞桂','衛宗武','宋','宋诗','song-poetry','','[]','駕言適東野，聊以慰離索。',156,'全唐诗/poet.song.218000.json','["駕言適東野，聊以慰離索。", "攝齊甫升堂，開尊隨命酌。", "芳鮮羅果羞，珍重如宿約。", "主客成五人，爽氣涵秋嶽。", "風生雄辯豪，舂容笑語狎。", "曲徑行委蛇，幽亭恣盤礴。", "團團駢翠樹，一一耀丹萼。", "葳蕤花四出，氤氳香徧達。", "方恨負清賞，不料此行樂。", "有女嬌婭姹，有子見頭角。", "舉醆競屬賞，此情尤不薄。", "英英晚節叢，芳意滿籬落。", "載酒儻重來，應無爽宿諾。"]'),
('492bd3e1-f862-4ac8-812a-b1b755e12353','約友秋賞','衛宗武','宋','宋诗','song-poetry','','[]','秋霖蕩殘暑，林飈鳴策策。',156,'全唐诗/poet.song.218000.json','["秋霖蕩殘暑，林飈鳴策策。", "乾坤灝氣浮，萬象互清發。", "望舒散天葩，拂拂餘芬落。", "霽景行澄鮮，三五圓素魄。", "有園那敢窺，有友那敢約。", "金吾不放夜，孤此月華白。", "鱸肥蟹可持，棗剝稻且穫。", "黄雞與白酒，樂事正參錯。", "胡爲抱空悲，常若遠行客。", "靖節存高風，黄花漸斑駁。", "吾儕于此時，何忍負杯酌。", "東郊稱行樂，鄰壤富林壑。", "邀朋踐前盟，須造子雲宅。"]'),
('a3542aa2-a3e3-4a48-b54b-e6f12148ea9e','星夕前露坐觀行雲有作','衛宗武','宋','宋诗','song-poetry','','[]','一氣有聚散，變化莫能測。',264,'全唐诗/poet.song.218000.json','["一氣有聚散，變化莫能測。", "氤氳彌太虛，膚寸繇觸石。", "翕如華蓋張，紛若纖纊擘。", "緝緝鯨布鱗，翩翩鳳展翼。", "祥或旗爲黄，祲或珥爲赤。", "友風而子雨，俄如翻墨汁。", "白衣與蒼狗，怪狀殊不一。", "露坐晚觀天，時近雙星夕。", "靄靄從何來，於粲絢金碧。", "突如怒濤湧，屹若奇峰立。", "黼黻盛彰施，文繡爛組織。", "良由天孫巧，匪自屏翳出。", "我不爲柳州，去拙有所乞。", "我不效汾陽，榮進占所得。", "但願煥有章，落筆成五色。", "毋使若貝錦，胥讒以作慝。", "傷哉杼軸空，民力敝東國。", "安得化爲繒，散漫浩萬匹。", "衣被此一方，羣黎徧爾德。", "仍須語河鼓，牽牛勤負軛。", "勉耕左角田，雨作蒸民粒。", "穰穰俱滿家，庶以給冗食。"]'),
('98aaae31-5e57-483c-80bf-63f00646fe0e','爲葉賓月賦','衛宗武','宋','宋诗','song-poetry','','[]','大乙涵中精，凝聚爲夜魄。',120,'全唐诗/poet.song.218000.json','["大乙涵中精，凝聚爲夜魄。", "皎皎行長空，高圓競明發。", "流輝大江湧，散影千林刻。", "騷人抱負奇，一氣清相若。", "有主此有賓，不勞折柬約。", "悠然來几席，玉色照肝膈。", "對之啟粲齒，嘲弄不爲虐。", "纍纍噴珠璣，華采互呈豁。", "銀闕或未完，要君施斧鑿。", "乘風到廣寒，一笑翻成客。"]'),
('c5e71a5c-2ee7-4ad8-949e-2cc52cb7e6ca','和人雜詠六首  其一','衛宗武','宋','宋诗','song-poetry','','[]','幾年抱渴襟，既見名副實。',60,'全唐诗/poet.song.218000.json','["幾年抱渴襟，既見名副實。", "擬爲嵇阮交，愧匪秦晉匹。", "風翮翔空冥，遠避弋與畢。", "汙世待澄清，其可事一室。", "駕言投吾簪，終爲清廟瑟。"]'),
('fb3b1375-8059-45a7-81ab-e96ae99c7344','和人雜詠六首  其二','衛宗武','宋','宋诗','song-poetry','','[]','窮秋菊薦香，小春梅破萼。',60,'全唐诗/poet.song.218000.json','["窮秋菊薦香，小春梅破萼。", "時卉互芳菲，榮悴異今昨。", "憶昔競芳妍，徵逐困吟酌。", "老去厭浮華，雅志在林壑。", "浩歌太沖章，願赴招隠約。"]'),
('961dc18d-1b0a-4230-9eda-59d37ee4bb3c','和人雜詠六首  其三','衛宗武','宋','宋诗','song-poetry','','[]','鐵研窮鑽研，知君用心苦。',60,'全唐诗/poet.song.218000.json','["鐵研窮鑽研，知君用心苦。", "撐腸書五車，何異羣玉府。", "粲然以成章，雲錦工織組。", "逸氣劘屈賈，餘子何足數。", "八詠俄頃成，落筆傾風雨。"]'),
('6c0988c5-3340-4de4-9ce4-1dffa3ac6312','和人雜詠六首  其四','衛宗武','宋','宋诗','song-poetry','','[]','世榮易消歇，猶歲多旱澇。',60,'全唐诗/poet.song.218000.json','["世榮易消歇，猶歲多旱澇。", "又如紅紫芳，焉得四時好。", "豈若潛窈深，考古而學道。", "葆真育其龢，英華發枯槁。", "出處明所宜，慎勿爲小草。"]'),
('7b685ae9-a30d-4ad0-ad9d-7c223f4539b5','和人雜詠六首  其五','衛宗武','宋','宋诗','song-poetry','','[]','矯矯鶴盤空，𡄸𡄸雁鳴旭。',60,'全唐诗/poet.song.218000.json','["矯矯鶴盤空，𡄸𡄸雁鳴旭。", "過雨沐遥岑，一日浣塵俗。", "久欲抱琴書，栖霞潄澄綠。", "劉安鷄犬仙，世豈無其術。", "一笑秋水橫，飛來雙白鵠。"]'),
('0092ef2d-bece-442b-b103-552879ada433','和人雜詠六首  其六','衛宗武','宋','宋诗','song-poetry','','[]','晴空擘絮雲，殘雨收綫溜。',60,'全唐诗/poet.song.218000.json','["晴空擘絮雲，殘雨收綫溜。", "晨興咀落英，風露入懷袖。", "遠水浮秋容，吟墨寫難就。", "碧山吾老友，扁舟擬訪舊。", "公肯從我游，茗飲烹乳竇。"]'),
('88773bab-901b-4230-a401-972c98dd6a7c','再和易後韻爲前韻六首  其一','衛宗武','宋','宋诗','song-poetry','','[]','多公苦嗜吟，殆類書癡竇。',60,'全唐诗/poet.song.218000.json','["多公苦嗜吟，殆類書癡竇。", "水火燥濕仝，一見懽如舊。", "七步未爲敏，百篇可立就。", "咀嚼牙頰香，氤氳滿襟袖。", "渾渾乎其來，勢若瓴建溜。"]'),
('f97acec5-e4ac-413c-baa4-d028e4bbde3a','再和易後韻爲前韻六首  其二','衛宗武','宋','宋诗','song-poetry','','[]','黑不待黔烏，白不待浴鵠。',60,'全唐诗/poet.song.218000.json','["黑不待黔烏，白不待浴鵠。", "天分既超卓，能消幾學術。", "飄飄霞外姿，瞳方而髮綠。", "滿腹貯古書，咳唾可袪俗。", "沖氣以爲和，陽春散晴旭。"]'),
('699a7d56-2e1c-477b-82a8-53c6734f2923','再和易後韻爲前韻六首  其三','衛宗武','宋','宋诗','song-poetry','','[]','妙語來翩翩，賡句慚草草。',60,'全唐诗/poet.song.218000.json','["妙語來翩翩，賡句慚草草。", "一鼓再則衰，氣痿腸亦槁。", "詩不造風雅，可觀徒小道。", "書能破萬卷，篇章自然好。", "淺學無根源，易涸如潢潦。"]'),
('d5a28b78-3db1-4816-acbb-a2a4af2f2269','再和易後韻爲前韻六首  其四','衛宗武','宋','宋诗','song-poetry','','[]','西風葉滿庭，欹枕聽鳴雨。',60,'全唐诗/poet.song.218000.json','["西風葉滿庭，欹枕聽鳴雨。", "悽然百感生，愁緒未易數。", "思昔詠干旌，良馬素絲組。", "今爲白屋夫，低頭拜官府。", "猶喜七十公，可免差科苦。"]'),
('81657651-b5bb-4d61-8988-0b639b485755','再和易後韻爲前韻六首  其五','衛宗武','宋','宋诗','song-poetry','','[]','懽猶程孔交，來匪張范約。',60,'全唐诗/poet.song.218000.json','["懽猶程孔交，來匪張范約。", "豈但授館粲，雅與同丘壑。", "我圃三徑荒，幾年負杯酌。", "秋葉與春花，今幸復還昨。", "園丁報新陽，早梅紅破萼。"]'),
('d276d3a9-b47a-4637-aba9-3b986b424ad8','再和易後韻爲前韻六首  其六','衛宗武','宋','宋诗','song-poetry','','[]','欲絕子期絃，肯鼓齊門瑟。',60,'全唐诗/poet.song.218000.json','["欲絕子期絃，肯鼓齊門瑟。", "諫官不足爲，孰可凂少室。", "然當展素藴，佐主爲召畢。", "志在澤斯民，思與鄒軻匹。", "難作遯世翁，江梅有佳實。"]'),
('874a0f18-71f0-493d-b3c9-ea328079f568','題張石山出行吟卷','衛宗武','宋','宋诗','song-poetry','','[]','峩峩章甫冠，飄飄凌雲氣。',204,'全唐诗/poet.song.218000.json','["峩峩章甫冠，飄飄凌雲氣。", "安肯鬰鬰居，乃試遠遊履。", "風雲負壯圖，川原窮雅志。", "槐竹憩幽深，草木仝臭味。", "滄溟浩八極，呼吸入胸次。", "物怪千萬狀，參錯入吟思。", "一篇復一篇，亹亹至百紙。", "芳菲迷目睫，璀璨照窗几。", "展玩三過讀，殆類噉蔗美。", "漸可造沖澹，豈特衒巧麗。", "章句亦何有，尚辭尤尚理。", "風行自成文，止於所宜止。", "熟之而精之，循能造極致。", "老我力已衰，不復競吟事。", "羨君年尚壯，進進殊未已。", "駸駸班前修，挺挺俯時輩。", "豈但薊北傳，可使雞林至。"]'),
('16afc96a-74b3-4d0d-a803-348a60a9ebc3','雪晴','衛宗武','宋','宋诗','song-poetry','','[]','歲窮候嚴沍，木石凍欲折。',144,'全唐诗/poet.song.218000.json','["歲窮候嚴沍，木石凍欲折。", "寒雲盡四垂，乾坤清氣發。", "僊人唾珠玉，瑣碎自天落。", "神功忽收斂，聲光隨息絕。", "暮夜風怒號，飄泛動几格。", "老夫卷書坐，燈焰耿明滅。", "爐存火已微，缾罄酒莫索。", "擁衾作龜縮，毛骨冷於鐵。", "皓色倏浮窗，疑雪復疑月。", "推枕晨啟扉，金烏已赫赫。", "桃符即換歲，椒盤行送臈。", "誰其呼滕六，爲我作三白。"]');
